// ---------------------------------------------------------------------------
// Hot-swappable inference runtime (#569)
// ---------------------------------------------------------------------------

/// Inference backends that can be swapped at runtime via config API.
///
/// Wrapped in `Arc<std::sync::RwLock<...>>` inside AppState so that the
/// config endpoint can rebuild and replace backends without a server restart.
/// Read lock is acquired briefly (just clone the Arc), so contention is minimal.
pub struct InferenceRuntime {
    pub generation_backend: Option<Arc<dyn GenerationBackend>>,
    pub provider_registry: Arc<matric_inference::ProviderRegistry>,
}

/// Background task that periodically probes the generation backend for
/// reachability and updates `inference_available` (#630).
///
/// Without this, a one-shot startup probe would latch Fortemi's
/// `capabilities.chat.available` and `capabilities.inference.available` to
/// `false` if the provider (e.g. Ollama) was still starting when Fortemi came
/// up — leaving every client stuck in "offline mode"
/// until Fortemi was manually restarted.
///
/// Interval is `INFERENCE_PROBE_INTERVAL_SECS` (default 30s). A transition in
/// reachability is logged at INFO level so operators can correlate with
/// provider availability.
async fn inference_reachability_probe(
    runtime: Arc<std::sync::RwLock<InferenceRuntime>>,
    flag: Arc<AtomicBool>,
    event_bus: Arc<EventBus>,
    interval_secs: u64,
) {
    let mut interval = tokio::time::interval(std::time::Duration::from_secs(interval_secs));
    // First tick fires immediately — skip it since startup already probed.
    interval.tick().await;

    loop {
        interval.tick().await;

        let backend = {
            let rt = runtime.read().unwrap();
            rt.generation_backend.clone()
        };

        let reachable = match backend {
            Some(b) => b.health_check().await.unwrap_or(false),
            None => false,
        };

        let previous = flag.swap(reachable, Ordering::Relaxed);
        if previous != reachable {
            if reachable {
                info!("Inference provider became reachable — chat endpoint enabled");
            } else {
                warn!("Inference provider became unreachable — chat endpoint disabled");
            }
            // Emit SSE event so clients clear/raise offline banners without polling `/health`.
            event_bus.emit(ServerEvent::InferenceAvailabilityChanged {
                available: reachable,
            });
        }
    }
}

// =============================================================================
// REQUEST ID (UUIDv7)
// =============================================================================

/// Generates time-ordered UUIDv7 request correlation IDs.
///
/// UUIDv7 embeds a Unix timestamp, so IDs sort chronologically — useful for
/// log correlation, distributed tracing, and debugging production incidents.
#[derive(Clone, Default)]
struct MakeRequestUuidV7;

impl MakeRequestId for MakeRequestUuidV7 {
    fn make_request_id<B>(&mut self, _request: &axum::http::Request<B>) -> Option<RequestId> {
        let id = Uuid::now_v7().to_string().parse().ok()?;
        Some(RequestId::new(id))
    }
}

// =============================================================================
// NLP PIPELINE HELPER
// =============================================================================

/// Queue the full NLP pipeline for a note.
///
/// This function queues all necessary processing jobs for a note in the correct order:
/// 1. AI Revision (priority 8) - Enhance content with context
/// 2. Embedding (priority 5) - Generate vector embeddings for semantic search
/// 3. Title Generation (priority 2) - Generate descriptive title
/// 4. Linking (priority 3) - Create semantic links to related notes
///
/// The `revision_mode` parameter controls AI revision behavior:
/// - `Full`: Aggressive expansion with context from related notes (default)
/// - `Light`: Structure and formatting only, no invented details
/// - `None`: Skip AI revision entirely, store original as-is
///
/// The `schema` parameter specifies which PostgreSQL schema to use for job execution:
/// - `None` (default): Use the public schema (backward compatible)
/// - `Some("archive_name")`: Use the specified archive schema for parallel memory isolation
///
/// Queue an extraction job for a newly uploaded attachment.
///
/// This should be called after storing the attachment and committing the transaction.
/// The extraction handler will fetch the file data from storage using the attachment_id.
#[allow(clippy::too_many_arguments)]
async fn queue_extraction_job(
    db: &Database,
    note_id: Uuid,
    attachment_id: Uuid,
    strategy: ExtractionStrategy,
    filename: &str,
    content_type: &str,
    event_bus: &EventBus,
    schema: Option<&str>,
    vision_mode: Option<&str>,
) {
    let payload = extraction_job_payload(
        attachment_id,
        strategy,
        filename,
        content_type,
        schema,
        vision_mode,
    );

    queue_extraction_job_payload(
        db,
        note_id,
        attachment_id,
        strategy,
        filename,
        payload,
        event_bus,
    )
    .await;
}

fn extraction_job_payload(
    attachment_id: Uuid,
    strategy: ExtractionStrategy,
    filename: &str,
    content_type: &str,
    schema: Option<&str>,
    vision_mode: Option<&str>,
) -> serde_json::Value {
    let mut payload = serde_json::json!({
        "strategy": strategy.to_string(),
        "attachment_id": attachment_id.to_string(),
        "filename_len": telemetry_text_len(filename),
        "mime_type_len": telemetry_text_len(content_type),
    });
    if let Some(s) = schema {
        payload["schema"] = serde_json::json!(s);
    }
    // Build config object for extraction handler (#550)
    let mut config = serde_json::Map::new();
    if let Some(vm) = vision_mode {
        if vm == "full" || vm == "standard" {
            config.insert("vision_mode".into(), serde_json::json!(vm));
        }
    }
    if !config.is_empty() {
        payload["config"] = serde_json::Value::Object(config);
    }
    payload
}

async fn queue_extraction_job_payload(
    db: &Database,
    note_id: Uuid,
    attachment_id: Uuid,
    strategy: ExtractionStrategy,
    filename: &str,
    payload: serde_json::Value,
    event_bus: &EventBus,
) {
    // Determine cost tier based on extraction strategy.
    // 3D model extraction uses Open3D renderer (GPU EGL), separated from
    // vision tier to avoid renderer↔Ollama GPU contention.
    // Vision extraction uses Ollama vision model directly.
    let cost_tier = match strategy {
        ExtractionStrategy::Glb3DModel => Some(matric_core::cost_tier::RENDER_GPU),
        ExtractionStrategy::Vision => Some(matric_core::cost_tier::VISION_GPU),
        _ => None,
    };

    // Use non-deduplicating queue: each attachment needs its own extraction job.
    // queue_deduplicated uses (note_id, job_type) as the dedup key, which would
    // silently drop extraction jobs when multiple attachments are uploaded to the
    // same note in quick succession.
    match db
        .jobs
        .queue(
            Some(note_id),
            JobType::Extraction,
            JobType::Extraction.default_priority(),
            Some(payload),
            cost_tier,
        )
        .await
    {
        Ok(job_id) => {
            let note_id_telemetry = event_text_telemetry(&note_id.to_string());
            let attachment_id_telemetry = event_text_telemetry(&attachment_id.to_string());
            let job_id_telemetry = event_text_telemetry(&job_id.to_string());
            info!(
                note_id_present = note_id_telemetry.present,
                note_id_len = note_id_telemetry.len,
                attachment_id_present = attachment_id_telemetry.present,
                attachment_id_len = attachment_id_telemetry.len,
                job_id_present = job_id_telemetry.present,
                job_id_len = job_id_telemetry.len,
                strategy_len = telemetry_text_len(&strategy.to_string()),
                filename_len = telemetry_text_len(filename),
                "Extraction job queued for attachment"
            );
            event_bus.emit(ServerEvent::JobQueued {
                job_id,
                job_type: format!("{:?}", JobType::Extraction),
                note_id: Some(note_id),
            });
        }
        Err(e) => {
            error!(
                error_len = telemetry_text_len(&e.to_string()),
                detail = API_JOB_QUEUE_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "queue_attachment_extraction",
                strategy_len = telemetry_text_len(&strategy.to_string()),
                filename_len = telemetry_text_len(filename),
                "Failed to queue extraction job"
            );
        }
    }
}

/// Queue an EXIF extraction job for image attachments.
///
/// This should be called after storing image attachments. The handler extracts
/// EXIF metadata (camera info, GPS coordinates, datetime) and creates provenance
/// records (location, device, file).
async fn queue_exif_extraction_job(
    db: &Database,
    note_id: Uuid,
    attachment_id: Uuid,
    content_type: &str,
    event_bus: &EventBus,
    schema: Option<&str>,
) {
    // Only queue for image content types
    if !content_type.starts_with("image/") {
        return;
    }

    let mut payload = serde_json::json!({
        "attachment_id": attachment_id.to_string(),
    });
    if let Some(s) = schema {
        payload["schema"] = serde_json::json!(s);
    }

    // Use non-deduplicating queue: each image attachment needs its own EXIF job.
    // Same rationale as extraction jobs — dedup by (note_id, job_type) drops jobs
    // when multiple images are attached to the same note.
    match db
        .jobs
        .queue(
            Some(note_id),
            JobType::ExifExtraction,
            JobType::ExifExtraction.default_priority(),
            Some(payload),
            None,
        )
        .await
    {
        Ok(job_id) => {
            event_bus.emit(ServerEvent::JobQueued {
                job_id,
                job_type: format!("{:?}", JobType::ExifExtraction),
                note_id: Some(note_id),
            });
        }
        Err(e) => {
            error!(
                error_len = telemetry_text_len(&e.to_string()),
                detail = API_JOB_QUEUE_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "queue_exif_extraction",
                content_type_len = telemetry_text_len(content_type),
                "Failed to queue EXIF extraction job"
            );
        }
    }
}

/// Queue a media optimization job for audio/video attachments (#506).
///
/// Creates web-optimized variants (faststart MP4, remuxed container, preview clips).
/// Only queues if the content type is audio or video.
async fn queue_media_optimize_job(
    db: &Database,
    note_id: Uuid,
    attachment_id: Uuid,
    content_type: &str,
    event_bus: &EventBus,
    schema: Option<&str>,
) {
    // Only queue for audio/video content types
    if !content_type.starts_with("audio/") && !content_type.starts_with("video/") {
        return;
    }

    let mut payload = media_optimize_job_payload(attachment_id, content_type);
    if let Some(s) = schema {
        payload["schema"] = serde_json::json!(s);
    }

    match db
        .jobs
        .queue(
            Some(note_id),
            JobType::MediaOptimize,
            JobType::MediaOptimize.default_priority(),
            Some(payload),
            None,
        )
        .await
    {
        Ok(job_id) => {
            event_bus.emit(ServerEvent::JobQueued {
                job_id,
                job_type: format!("{:?}", JobType::MediaOptimize),
                note_id: Some(note_id),
            });
        }
        Err(e) => {
            error!(
                error_len = telemetry_text_len(&e.to_string()),
                detail = API_JOB_QUEUE_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "queue_media_optimize",
                content_type_len = telemetry_text_len(content_type),
                "Failed to queue media optimize job"
            );
        }
    }
}

fn media_optimize_job_payload(attachment_id: Uuid, content_type: &str) -> serde_json::Value {
    serde_json::json!({
        "attachment_id": attachment_id.to_string(),
        "content_type_len": telemetry_text_len(content_type),
    })
}

fn scan_downstream_job(job_type: JobType, payload: serde_json::Value) -> serde_json::Value {
    serde_json::json!({
        "job_type": match job_type {
            JobType::Extraction => "extraction",
            JobType::ExifExtraction => "exif_extraction",
            JobType::MediaOptimize => "media_optimize",
            JobType::AudioTranscription => "audio_transcription",
            _ => unreachable!("scan downstream job type must be allowlisted"),
        },
        "payload": payload,
    })
}

#[allow(clippy::too_many_arguments)]
fn attachment_scan_downstream_jobs(
    attachment_id: Uuid,
    strategy: ExtractionStrategy,
    filename: &str,
    content_type: &str,
    schema: Option<&str>,
    vision_mode: Option<&str>,
    media_optimize: bool,
) -> Vec<serde_json::Value> {
    let mut jobs = vec![scan_downstream_job(
        JobType::Extraction,
        extraction_job_payload(
            attachment_id,
            strategy,
            filename,
            content_type,
            schema,
            vision_mode,
        ),
    )];
    if content_type.starts_with("image/") {
        let mut payload = serde_json::json!({
            "attachment_id": attachment_id.to_string(),
        });
        if let Some(schema) = schema {
            payload["schema"] = serde_json::json!(schema);
        }
        jobs.push(scan_downstream_job(JobType::ExifExtraction, payload));
    }
    if media_optimize && (content_type.starts_with("audio/") || content_type.starts_with("video/"))
    {
        let mut payload = media_optimize_job_payload(attachment_id, content_type);
        if let Some(schema) = schema {
            payload["schema"] = serde_json::json!(schema);
        }
        jobs.push(scan_downstream_job(JobType::MediaOptimize, payload));
    }
    jobs
}

async fn queue_attachment_scan_job(
    state: &AppState,
    note_id: Uuid,
    attachment_id: Uuid,
    schema: Option<&str>,
    downstream_jobs: Vec<serde_json::Value>,
) -> Result<Uuid, ApiError> {
    let mut payload = serde_json::json!({
        "attachment_id": attachment_id.to_string(),
        "downstream_jobs": downstream_jobs,
    });
    if let Some(schema) = schema {
        payload["schema"] = serde_json::json!(schema);
    }
    let job_id = state
        .db
        .jobs
        .queue(
            Some(note_id),
            JobType::AttachmentVirusScan,
            JobType::AttachmentVirusScan.default_priority(),
            Some(payload),
            JobType::AttachmentVirusScan.default_cost_tier(),
        )
        .await?;
    state.event_bus.emit(ServerEvent::JobQueued {
        job_id,
        job_type: format!("{:?}", JobType::AttachmentVirusScan),
        note_id: Some(note_id),
    });
    Ok(job_id)
}

async fn apply_attachment_scan_policy_tx(
    state: &AppState,
    tx: &mut sqlx::Transaction<'_, sqlx::Postgres>,
    attachment: &mut matric_core::Attachment,
    data: &[u8],
) -> Result<(), ApiError> {
    if state.attachment_scan_mode == AttachmentScanMode::Disabled {
        let content_hash = matric_db::compute_content_hash(data);
        state
            .db
            .file_storage
            .as_ref()
            .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?
            .set_scan_verdict_tx(
                tx,
                attachment.id,
                AttachmentScanStatus::Bypassed,
                Some("fortemi-policy"),
                None,
                None,
                Some("explicit_local_bypass"),
                Some(&content_hash),
            )
            .await?;
        attachment.virus_scan_status = AttachmentScanStatus::Bypassed;
        attachment.virus_scan_at = Some(Utc::now());
        attachment.virus_scan_backend = Some("fortemi-policy".to_string());
        attachment.virus_scan_reason_code = Some("explicit_local_bypass".to_string());
        attachment.virus_scan_blob_hash = Some(content_hash);
        state.attachment_scan_metrics.record_bypass();
    }
    Ok(())
}

/// Parse and validate a `revision_mode` string, returning 400 for invalid values.
///
/// Accepts both new modes (`standard`, `contextual`, `contextual_filtered`) and
/// legacy values (`full` maps to `Contextual` for backward compatibility).
fn parse_revision_mode(mode: Option<&str>) -> Result<RevisionMode, ApiError> {
    match mode {
        Some("full") => Ok(RevisionMode::Full),
        Some("light") => Ok(RevisionMode::Light),
        Some("standard") => Ok(RevisionMode::Standard),
        Some("contextual") => Ok(RevisionMode::Contextual),
        Some("contextual_filtered") => Ok(RevisionMode::ContextualFiltered),
        Some("none") => Ok(RevisionMode::None),
        None => Ok(RevisionMode::Standard),
        Some(_) => Err(invalid_revision_mode(None, REVISION_MODE_ALLOWED_FULL)),
    }
}

const REVISION_MODE_ALLOWED_FULL: &str =
    "standard, light, full, contextual, contextual_filtered, none";
const REVISION_MODE_ALLOWED_BULK: &str = "full, light, none";
const BULK_CHUNKING_VALIDATION_MESSAGE: &str =
    "Invalid note chunking parameters. Check chunk_max_chars and chunk_overlap.";

fn invalid_revision_mode(index: Option<usize>, allowed: &str) -> ApiError {
    let detail = match index {
        Some(i) => format!("Note at index {i}: invalid revision_mode. Must be one of: {allowed}"),
        None => format!("Invalid revision_mode. Must be one of: {allowed}"),
    };
    ApiError::BadRequest(detail)
}

fn unknown_document_type(index: Option<usize>) -> ApiError {
    let detail = match index {
        Some(i) => format!(
            "Note at index {i}: unknown document_type. Use GET /api/v1/document-types to list available types"
        ),
        None => {
            "Unknown document_type. Use GET /api/v1/document-types to list available types"
                .to_string()
        }
    };
    ApiError::BadRequest(detail)
}

/// Validate optional chunking parameters for revision. (#572)
/// Returns an error message string if validation fails.
fn validate_chunking_params(
    chunk_max_chars: Option<usize>,
    chunk_overlap: Option<usize>,
) -> Result<(), String> {
    if let Some(max) = chunk_max_chars {
        // 0 is valid (means disable chunking / single-pass)
        if max > 0 && max < 2000 {
            return Err("chunk_max_chars must be 0 or at least 2000.".to_string());
        }
    }
    if let Some(overlap) = chunk_overlap {
        if let Some(max) = chunk_max_chars {
            if max > 0 && overlap >= max / 2 {
                return Err("chunk_overlap must be less than half of chunk_max_chars.".to_string());
            }
        }
    }
    Ok(())
}

fn invalid_bulk_chunking_params() -> ApiError {
    ApiError::BadRequest(BULK_CHUNKING_VALIDATION_MESSAGE.to_string())
}

