/// This should be called after:
/// - Creating a new note
/// - Updating note content
/// - Any operation that modifies content requiring re-indexing
///
/// Uses deduplicated queuing to prevent duplicate jobs for the same note/type.
async fn queue_nlp_pipeline(
    db: &Database,
    note_id: Uuid,
    revision_mode: RevisionMode,
    event_bus: &EventBus,
    schema: Option<&str>,
    model: Option<&str>,
) {
    queue_nlp_pipeline_inner(
        db,
        note_id,
        revision_mode,
        event_bus,
        schema,
        model,
        false,
        None,
        None,
        None,
    )
    .await;
}

/// Inner pipeline with title generation control and optional feature filtering.
/// When `skip_title_gen` is true, TitleGeneration is omitted from Phase 1 jobs.
/// Used by document types like agent-reflection that are machine-generated. (#563)
///
/// When `pipeline` is `Some`, only listed features are queued. Empty = no processing.
/// When `pipeline` is `None`, full default pipeline runs. (#628)
#[allow(clippy::too_many_arguments)]
async fn queue_nlp_pipeline_inner(
    db: &Database,
    note_id: Uuid,
    revision_mode: RevisionMode,
    event_bus: &EventBus,
    schema: Option<&str>,
    model: Option<&str>,
    skip_title_gen: bool,
    chunk_max_chars: Option<usize>,
    chunk_overlap: Option<usize>,
    pipeline: Option<&[String]>,
) {
    // If pipeline is explicitly set to empty, skip all AI processing (store only).
    // Callers opt-in to specific pipeline features via the `pipeline` field (#628).
    if let Some(features) = pipeline {
        if features.is_empty() {
            return;
        }
    }

    // Helper: check if a feature is enabled (None = all enabled, Some = only listed)
    let feature_enabled = |name: &str| -> bool {
        match pipeline {
            None => true,
            Some(features) => features.iter().any(|f| f == name),
        }
    };

    // Queue AI revision with mode and schema in payload (unless mode is None)
    if revision_mode != RevisionMode::None && feature_enabled("revision") {
        let mut payload = serde_json::json!({
            "revision_mode": revision_mode
        });
        if let Some(s) = schema {
            payload["schema"] = serde_json::json!(s);
        }
        if let Some(m) = model {
            payload["model"] = serde_json::json!(m);
        }
        if let Some(c) = chunk_max_chars {
            payload["chunk_max_chars"] = serde_json::json!(c);
        }
        if let Some(o) = chunk_overlap {
            payload["chunk_overlap"] = serde_json::json!(o);
        }
        match db
            .jobs
            .queue_deduplicated(
                Some(note_id),
                JobType::AiRevision,
                JobType::AiRevision.default_priority(),
                Some(payload),
                JobType::AiRevision.default_cost_tier(),
            )
            .await
        {
            Ok(Some(job_id)) => {
                event_bus.emit(ServerEvent::JobQueued {
                    job_id,
                    job_type: format!("{:?}", JobType::AiRevision),
                    note_id: Some(note_id),
                });
            }
            Ok(None) => {} // Deduplicated
            Err(e) => {
                error!(
                    error_len = telemetry_text_len(&e.to_string()),
                    detail = API_JOB_PIPELINE_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "queue_ai_revision",
                    "Failed to queue AI revision job"
                );
            }
        }
    }

    // Queue Phase 1 pipeline jobs with cost tiers from JobType::default_cost_tier().
    // ConceptTagging is NOT in this list — it chains from AiRevision on completion
    // so it operates on the enriched AI-revised content instead of the raw original.
    // Pipeline: AiRevision → ConceptTagging → RelatedConceptInference → Embedding → Linking (#420, #424, #435, #538).
    let phase1_jobs: Vec<JobType> = [
        JobType::TitleGeneration,
        JobType::ReferenceExtraction,
        JobType::MetadataExtraction,
        JobType::DocumentTypeInference,
    ]
    .into_iter()
    .filter(|jt| !(skip_title_gen && *jt == JobType::TitleGeneration))
    .filter(|jt| {
        feature_enabled(match jt {
            JobType::TitleGeneration => "title_generation",
            JobType::ReferenceExtraction => "reference_extraction",
            JobType::MetadataExtraction => "metadata_extraction",
            JobType::DocumentTypeInference => "document_type_inference",
            _ => "unknown",
        })
    })
    .collect();
    for job_type in phase1_jobs {
        // Create payload with schema and optional model override
        let mut payload = serde_json::Map::new();
        if let Some(s) = schema {
            payload.insert("schema".to_string(), serde_json::json!(s));
        }
        if let Some(m) = model {
            payload.insert("model".to_string(), serde_json::json!(m));
        }
        let payload = if payload.is_empty() {
            None
        } else {
            Some(serde_json::Value::Object(payload))
        };

        match db
            .jobs
            .queue_deduplicated(
                Some(note_id),
                job_type,
                job_type.default_priority(),
                payload,
                job_type.default_cost_tier(),
            )
            .await
        {
            Ok(Some(job_id)) => {
                event_bus.emit(ServerEvent::JobQueued {
                    job_id,
                    job_type: format!("{:?}", job_type),
                    note_id: Some(note_id),
                });
            }
            Ok(None) => {} // Deduplicated
            Err(e) => {
                error!(
                    error_len = telemetry_text_len(&e.to_string()),
                    detail = API_JOB_PIPELINE_DIAGNOSTIC_FAILURE_DETAIL,
                    job_type_len = telemetry_text_len(&format!("{job_type:?}")),
                    operation = "queue_nlp_pipeline_job",
                    "Failed to queue NLP pipeline job"
                );
            }
        }
    }

    // When revision is disabled (or not requested via pipeline filter), queue
    // ConceptTagging directly since there's no AiRevision to chain from.
    // Otherwise AiRevision chains it on completion.
    if (revision_mode == RevisionMode::None || !feature_enabled("revision"))
        && feature_enabled("concept_tagging")
    {
        let mut payload = serde_json::Map::new();
        if let Some(s) = schema {
            payload.insert("schema".to_string(), serde_json::json!(s));
        }
        if let Some(m) = model {
            payload.insert("model".to_string(), serde_json::json!(m));
        }
        let payload = if payload.is_empty() {
            None
        } else {
            Some(serde_json::Value::Object(payload))
        };
        match db
            .jobs
            .queue_deduplicated(
                Some(note_id),
                JobType::ConceptTagging,
                JobType::ConceptTagging.default_priority(),
                payload,
                JobType::ConceptTagging.default_cost_tier(),
            )
            .await
        {
            Ok(Some(job_id)) => {
                event_bus.emit(ServerEvent::JobQueued {
                    job_id,
                    job_type: format!("{:?}", JobType::ConceptTagging),
                    note_id: Some(note_id),
                });
            }
            Ok(None) => {} // Deduplicated
            Err(e) => {
                error!(
                    error_len = telemetry_text_len(&e.to_string()),
                    detail = API_JOB_PIPELINE_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "queue_concept_tagging_no_revision",
                    "Failed to queue ConceptTagging (no-revision path)"
                );
            }
        }
    }
}
