/// Global rate limiter type (direct quota, no keyed bucketing for personal server).
type GlobalRateLimiter = RateLimiter<
    governor::state::NotKeyed,
    governor::state::InMemoryState,
    governor::clock::DefaultClock,
>;

static RTP_AUDIO_FRAMES_TOTAL: AtomicUsize = AtomicUsize::new(0);
static RTP_CODEC_DECODE_FAILURES_TOTAL: AtomicUsize = AtomicUsize::new(0);
static RTP_OUTBOX_WRITE_FAILURES_TOTAL: AtomicUsize = AtomicUsize::new(0);

#[derive(Clone, Default)]
struct LifecycleState {
    ready: Arc<AtomicBool>,
    draining: Arc<AtomicBool>,
}

impl LifecycleState {
    fn mark_ready(&self) {
        self.draining.store(false, Ordering::Release);
        self.ready.store(true, Ordering::Release);
    }

    fn begin_draining(&self) {
        self.ready.store(false, Ordering::Release);
        self.draining.store(true, Ordering::Release);
    }

    fn is_ready(&self) -> bool {
        self.ready.load(Ordering::Acquire) && !self.is_draining()
    }

    fn is_draining(&self) -> bool {
        self.draining.load(Ordering::Acquire)
    }
}

/// Application state shared across handlers.
#[derive(Clone)]
struct AppState {
    db: Database,
    search: Arc<HybridSearchEngine>,
    /// OAuth2 issuer URL (base URL of the server).
    issuer: String,
    /// Global rate limiter (None if rate limiting is disabled).
    rate_limiter: Option<Arc<GlobalRateLimiter>>,
    /// Tag resolver for strict filter resolution.
    tag_resolver: TagResolver,
    /// Redis search cache (reduces latency for repeated queries).
    search_cache: matric_api::services::SearchCache,
    /// Redis-backed buffer for SSE chat-stream resumption (#815).
    chat_stream_store: matric_api::services::ChatStreamStore,
    /// Redis-backed cursor store for `/ingest/stream` resumption (#828).
    ingest_cursor_store: matric_api::services::IngestCursorStore,
    /// Redis-backed stream-scoped bearer tokens for `/ingest/stream` (#829).
    ingest_token_store: matric_api::services::IngestTokenStore,
    /// Redis-backed `Idempotency-Key` dedupe for incoming webhooks (#822).
    idempotency_store: matric_api::services::IdempotencyStore,
    /// Event bus for real-time notifications (WebSocket, SSE, webhooks, telemetry).
    event_bus: Arc<EventBus>,
    /// Active WebSocket connection count (Issue #42).
    ws_connections: Arc<AtomicUsize>,
    /// Cached default archive for routing middleware (Issue #107).
    default_archive_cache: Arc<RwLock<DefaultArchiveCache>>,
    /// Require authentication for protected routes (Issue #114).
    require_auth: bool,
    /// Require explicit confirmation before call-recording session creation.
    call_recording_require_confirmation: bool,
    /// Authorization policy decision point (#710). Starts with AllowAllPolicy to
    /// preserve current CE/personal-server behavior while middleware wiring lands.
    authorization_policy: Arc<dyn AuthorizationPolicy>,
    /// Runtime-selected recorder. CE defaults to `NoOpMeter`; durable mode is startup-required.
    usage_meter: Arc<dyn UsageMeter>,
    /// OAuth access token lifetime (standard clients).
    oauth_token_lifetime: chrono::Duration,
    /// OAuth access token lifetime (MCP clients).
    oauth_mcp_token_lifetime: chrono::Duration,
    /// Maximum number of memories (archives) allowed.
    max_memories: i64,
    /// Maximum file upload size in bytes (for attachment validation).
    max_upload_size: usize,
    /// Managed attachment scan policy for processing and download decisions.
    attachment_scan_mode: AttachmentScanMode,
    /// Bounded-cardinality managed attachment scan counters.
    attachment_scan_metrics: Arc<AttachmentScanMetrics>,
    /// Vision backend for ad-hoc image description (None if OLLAMA_VISION_MODEL not set).
    vision_backend: Option<Arc<dyn VisionBackend>>,
    /// Transcription backend for ad-hoc audio transcription (None if WHISPER_BASE_URL not set).
    transcription_backend: Option<Arc<dyn TranscriptionBackend>>,
    /// Realtime Deepgram ASR metrics snapshot source, if configured.
    realtime_deepgram_metrics: Option<Arc<matric_api::realtime::asr::deepgram::DeepgramMetrics>>,
    /// Realtime ASR backend used by provider media streams.
    realtime_asr_backend: Option<Arc<dyn matric_api::realtime::asr::StreamingASRBackend>>,
    /// NER backend for named entity recognition (None if GLINER_BASE_URL not set).
    ner_backend: Option<Arc<dyn matric_inference::NerBackend>>,
    /// Diarization backend for speaker identification (None if DIARIZATION_BASE_URL not set).
    diarization_backend: Option<Arc<dyn DiarizationBackend>>,
    /// Git commit SHA at build time.
    git_sha: String,
    /// Build date (ISO 8601).
    build_date: String,
    /// Extraction strategies that are actually registered and available.
    extraction_strategies: Vec<String>,
    /// Hot-swappable inference runtime for generation backend + provider registry (#569).
    /// Use accessor methods `generation_backend()` and `provider_registry()` for reads.
    inference_runtime: Arc<std::sync::RwLock<InferenceRuntime>>,
    /// Cached per-schema search engines for non-default archives.
    schema_engines:
        Arc<tokio::sync::RwLock<std::collections::HashMap<String, Arc<HybridSearchEngine>>>>,
    /// Database URL for creating per-schema connection pools.
    database_url: String,
    /// Pause state for global and per-archive job processing control (Issue #466).
    pause_state: Option<PauseState>,
    /// Staging directory for tus resumable uploads (Issue #528).
    tus_staging_path: String,
    /// Semaphore limiting concurrent chat requests to avoid VRAM contention (#549).
    /// None if Ollama generation is not configured.
    chat_semaphore: Option<Arc<tokio::sync::Semaphore>>,
    /// Live reachability flag for the inference provider (#630).
    ///
    /// Updated by a background probe task (see `inference_reachability_probe`).
    /// Consumers (chat handler, `/health`) read this rather than relying on the
    /// one-shot startup probe, so availability recovers automatically when a
    /// provider (e.g. Ollama) starts after Fortemi.
    inference_available: Arc<AtomicBool>,
    /// Counters for the streaming chat endpoint, surfaced on `/health/streaming` (#814).
    chat_stream_metrics: Arc<ChatStreamMetrics>,
    /// Backpressure gauges/counters for `/ingest/stream`, surfaced on `/health/streaming` (#827).
    ingest_stream_metrics: Arc<crate::handlers::ingest_stream::IngestStreamMetrics>,
    /// Per-connector counters for inbound event sources, surfaced on `/health/streaming` (#833).
    inbound_metrics: Arc<matric_jobs::inbound::InboundMetrics>,
    /// Process readiness and drain state for orchestrator probes.
    lifecycle: LifecycleState,
    /// Immediate-peer allowlist for security-sensitive forwarded metadata.
    trusted_proxy_config: TrustedProxyConfig,
}

impl AppState {
    /// Get the current generation backend (clones the Arc, drops lock immediately).
    fn generation_backend(&self) -> Option<Arc<dyn GenerationBackend>> {
        self.inference_runtime
            .read()
            .unwrap()
            .generation_backend
            .clone()
    }

    /// Get the current provider registry (clones the Arc, drops lock immediately).
    fn provider_registry(&self) -> Arc<matric_inference::ProviderRegistry> {
        self.inference_runtime
            .read()
            .unwrap()
            .provider_registry
            .clone()
    }
}

