#[cfg(test)]
fn health_dependency_error_code(kind: &str) -> &'static str {
    match kind {
        "database_query" => "database_query_failed",
        "dependency_timeout" => "dependency_timeout",
        "cache_unavailable" => "cache_unavailable",
        "provider_unreachable" => "provider_unreachable",
        "provider_check" => "provider_check_failed",
        "provider_unhealthy" => "provider_unhealthy",
        "backend_not_initialized" => "backend_not_initialized",
        _ => "dependency_check_failed",
    }
}

#[cfg(test)]
fn set_health_service_reason_code(
    services: &mut serde_json::Value,
    service_name: &str,
    reason_code: &str,
) {
    services[service_name]["reason_code"] = serde_json::Value::String(reason_code.to_string());
}

fn provider_url_configured(url: &str) -> bool {
    !url.trim().is_empty()
}

#[utoipa::path(
    get,
    path = "/health",
    tag = "System",
    responses(
        (status = 200, description = "Success"),
    )
)]
async fn health_check(State(state): State<AppState>) -> impl IntoResponse {
    let job_processing = if let Some(ref ps) = state.pause_state {
        if ps.is_globally_paused() {
            "paused"
        } else {
            "running"
        }
    } else {
        "running"
    };
    let attachment_scan_queue_depth = state
        .db
        .jobs
        .pending_count_for_type(JobType::AttachmentVirusScan)
        .await
        .unwrap_or_default();

    // Build inference status for health response (#568, #630).
    // `configured` reflects static env/db config; `available` reflects the latest
    // periodic reachability probe (#630) so transient provider outages don't latch
    // chat to "offline" for the Fortemi process lifetime.
    let gen_backend = state.generation_backend();
    let provider_registry = state.provider_registry();
    let inference_reachable = state.inference_available.load(Ordering::Relaxed);
    let inference_info = match &gen_backend {
        Some(backend) => {
            let provider_url = provider_registry
                .get_provider(provider_registry.default_provider())
                .map(|provider| provider.base_url.as_str())
                .unwrap_or_default();
            serde_json::json!({
                "configured": true,
                "available": inference_reachable,
                "provider_url_configured": provider_url_configured(provider_url),
                "gen_model": backend.model_name(),
                "embed_model": std::env::var("OLLAMA_EMBED_MODEL")
                    .unwrap_or_else(|_| matric_core::defaults::EMBED_MODEL.to_string()),
            })
        }
        None => serde_json::json!({
            "configured": false,
            "available": false,
        }),
    };

    Json(serde_json::json!({
        "status": "healthy",
        "version": env!("CARGO_PKG_VERSION"),
        "git_sha": state.git_sha,
        "build_date": state.build_date,
        "capabilities": {
            "inference": inference_info,
            "vision": state.vision_backend.is_some(),
            "audio_transcription": state.transcription_backend.is_some(),
            "speaker_diarization": state.diarization_backend.is_some(),
            "ner": state.ner_backend.is_some(),
            "auth_required": state.require_auth,
            "attachment_scanning": {
                "mode": state.attachment_scan_mode.as_str(),
                "configured": state.attachment_scan_mode == AttachmentScanMode::Required,
                "queue_depth": attachment_scan_queue_depth,
                "metrics": state.attachment_scan_metrics.snapshot(),
            },
            "extraction_strategies": state.extraction_strategies,
            "chat": {
                "available": gen_backend.is_some() && inference_reachable,
                "configured": gen_backend.is_some(),
                "max_concurrent": matric_core::defaults::chat_max_concurrent(),
            },
        },
        "job_processing": job_processing,
        "lifecycle": {
            "ready": state.lifecycle.is_ready(),
            "draining": state.lifecycle.is_draining(),
        },
        "sse": state.event_bus.metrics.snapshot(),
    }))
}

#[derive(Debug, Serialize)]
struct CompatibilityResponse {
    schema_version: u8,
    contract_revision: &'static str,
    api: CompatibilityApi,
    deployment: CompatibilityDeployment,
    auth: CompatibilityAuth,
    capabilities: serde_json::Value,
    backoffice: BackofficeCompatibility,
    links: CompatibilityLinks,
}

#[derive(Debug, Serialize)]
struct CompatibilityApi {
    name: &'static str,
    version: &'static str,
    minimum_hotm_enterprise_client: &'static str,
    git_sha_present: bool,
    build_date_present: bool,
}

#[derive(Debug, Serialize)]
struct CompatibilityDeployment {
    mode: &'static str,
    edition: &'static str,
    hosted_multi_tenant_ready: bool,
}

#[derive(Debug, Serialize)]
struct CompatibilityAuth {
    required: bool,
    mode: &'static str,
    oauth_issuer_configured: bool,
    tenant_context_available: bool,
}

#[derive(Debug, Serialize)]
struct CompatibilityLinks {
    openapi: &'static str,
    asyncapi: &'static str,
    health: &'static str,
    streaming_health: &'static str,
}

#[derive(Debug, Serialize)]
struct BackofficeCompatibility {
    contract_revision: &'static str,
    production_enabled: bool,
    preview_responses_enabled: bool,
    preview_gate: &'static str,
    surfaces: Vec<BackofficeSurface>,
}

#[derive(Debug, Serialize)]
struct BackofficeSurface {
    key: &'static str,
    state: &'static str,
    reason_code: &'static str,
    endpoint: &'static str,
    required_scopes: &'static [&'static str],
    actions: &'static [&'static str],
    audit_events: &'static [&'static str],
    response_contract: &'static str,
}

#[derive(Debug, Clone, Copy)]
struct CompatibilityInputs<'a> {
    require_auth: bool,
    git_sha: &'a str,
    build_date: &'a str,
}

fn capability_state(state: &'static str) -> serde_json::Value {
    serde_json::json!({ "state": state })
}

fn capability_state_with_reason(
    state: &'static str,
    reason_code: &'static str,
) -> serde_json::Value {
    serde_json::json!({
        "state": state,
        "reason_code": reason_code,
    })
}

fn compatibility_auth_mode(require_auth: bool) -> &'static str {
    if require_auth {
        "oauth"
    } else {
        "anonymous_local"
    }
}

fn compatibility_deployment_mode(require_auth: bool) -> &'static str {
    if require_auth {
        "single_tenant_server"
    } else {
        "local_sidecar"
    }
}

fn build_backoffice_compatibility() -> BackofficeCompatibility {
    BackofficeCompatibility {
        contract_revision: "2026-07-10",
        production_enabled: false,
        preview_responses_enabled: false,
        preview_gate: "FORTEMI_BACKOFFICE_PREVIEW=true",
        surfaces: vec![
            BackofficeSurface {
                key: "tenant_health",
                state: "unavailable",
                reason_code: "backoffice_contract_preview_disabled",
                endpoint: "/api/v1/admin/tenant/health",
                required_scopes: &["admin:tenant:read"],
                actions: &["tenant.health.read"],
                audit_events: &["backoffice.tenant_health.read"],
                response_contract: "health_state, degraded_reasons, checked_at",
            },
            BackofficeSurface {
                key: "audit_posture",
                state: "preview",
                reason_code: "hosted_audit_gate_open",
                endpoint: "/api/v1/admin/audit/posture",
                required_scopes: &["admin:audit:read"],
                actions: &["audit.posture.read"],
                audit_events: &["backoffice.audit_posture.read"],
                response_contract: "coverage_state, sink_state, retention_state, missing_events",
            },
            BackofficeSurface {
                key: "quota_status",
                state: "unavailable",
                reason_code: "quota_policy_not_implemented",
                endpoint: "/api/v1/admin/quota/status",
                required_scopes: &["admin:quota:read"],
                actions: &["quota.status.read"],
                audit_events: &["backoffice.quota_status.read"],
                response_contract: "metering_state, period, limits, usage, reset_at",
            },
            BackofficeSurface {
                key: "kms_status",
                state: "unavailable",
                reason_code: "key_provider_not_implemented",
                endpoint: "/api/v1/admin/kms/status",
                required_scopes: &["admin:kms:read"],
                actions: &["kms.status.read"],
                audit_events: &["backoffice.kms_status.read"],
                response_contract:
                    "provider_state, keyring_state, rotation_state, degraded_reasons",
            },
            BackofficeSurface {
                key: "premium_components",
                state: "preview",
                reason_code: "capability_catalog_preview_only",
                endpoint: "/api/v1/admin/premium/components",
                required_scopes: &["admin:components:read"],
                actions: &["premium.components.read"],
                audit_events: &["backoffice.premium_components.read"],
                response_contract: "component_key, state, reason_code, required_entitlements",
            },
            BackofficeSurface {
                key: "support_diagnostics",
                state: "unavailable",
                reason_code: "support_diagnostics_not_implemented",
                endpoint: "/api/v1/admin/support/diagnostics",
                required_scopes: &["admin:support:read"],
                actions: &["support.diagnostics.read"],
                audit_events: &["backoffice.support_diagnostics.read"],
                response_contract: "diagnostic_key, state, redacted_summary, collected_at",
            },
        ],
    }
}

fn build_compatibility_response_from_inputs(
    inputs: CompatibilityInputs<'_>,
) -> CompatibilityResponse {
    CompatibilityResponse {
        schema_version: 1,
        contract_revision: "2026-07-06",
        api: CompatibilityApi {
            name: "fortemi",
            version: env!("CARGO_PKG_VERSION"),
            minimum_hotm_enterprise_client: "0.0.0-checkpoint",
            git_sha_present: !inputs.git_sha.trim().is_empty() && inputs.git_sha != "unknown",
            build_date_present: !inputs.build_date.trim().is_empty()
                && inputs.build_date != "unknown",
        },
        deployment: CompatibilityDeployment {
            mode: compatibility_deployment_mode(inputs.require_auth),
            edition: "community",
            hosted_multi_tenant_ready: false,
        },
        auth: CompatibilityAuth {
            required: inputs.require_auth,
            mode: compatibility_auth_mode(inputs.require_auth),
            oauth_issuer_configured: inputs.require_auth,
            tenant_context_available: false,
        },
        capabilities: serde_json::json!({
            "core_notes": capability_state("available"),
            "search": capability_state("available"),
            "jobs": capability_state("available"),
            "realtime_activity": capability_state("available"),
            "hosted_auth": capability_state_with_reason(
                "unavailable",
                if inputs.require_auth {
                    "rls_gate_open"
                } else {
                    "hosted_auth_not_configured"
                },
            ),
            "premium_components": capability_state_with_reason(
                "preview",
                "capability_catalog_preview_only",
            ),
            "backoffice_api": capability_state_with_reason(
                "unavailable",
                "contract_not_implemented",
            ),
            "audit_posture": capability_state_with_reason(
                "preview",
                "hosted_audit_gate_open",
            ),
            "quota_status": capability_state_with_reason(
                "unavailable",
                "quota_policy_not_implemented",
            ),
            "kms_status": capability_state_with_reason(
                "unavailable",
                "key_provider_not_implemented",
            ),
            "mcp_scope_gate": capability_state_with_reason(
                "preview",
                "enterprise_gate_not_implemented",
            ),
        }),
        backoffice: build_backoffice_compatibility(),
        links: CompatibilityLinks {
            openapi: route_policy::OPERATOR_OPENAPI_PATH,
            asyncapi: route_policy::OPERATOR_ASYNCAPI_PATH,
            health: "/health",
            streaming_health: "/api/v1/health/streaming",
        },
    }
}

fn build_compatibility_response(state: &AppState) -> CompatibilityResponse {
    build_compatibility_response_from_inputs(CompatibilityInputs {
        require_auth: state.require_auth,
        git_sha: &state.git_sha,
        build_date: &state.build_date,
    })
}

#[utoipa::path(
    get,
    path = "/api/v1/system/compatibility",
    tag = "System",
    responses((status = 200, description = "Public-safe API compatibility and coarse capability metadata"))
)]
async fn system_compatibility(State(state): State<AppState>) -> impl IntoResponse {
    let mut headers = HeaderMap::new();
    headers.insert(header::CACHE_CONTROL, HeaderValue::from_static("no-store"));
    (headers, Json(build_compatibility_response(&state)))
}

#[utoipa::path(
    get,
    path = "/api/v1/health/streaming",
    tag = "System",
    responses((status = 200, description = "Streaming subsystem health and realtime metrics"))
)]
async fn streaming_health_check(
    State(state): State<AppState>,
) -> Result<impl IntoResponse, ApiError> {
    let call_metrics = state.db.call_sessions.realtime_metrics().await?;
    let deepgram_rate = realtime_asr_deepgram_cost_per_minute();
    let deepgram_metrics = state
        .realtime_deepgram_metrics
        .as_ref()
        .map(|metrics| metrics.snapshot());

    Ok(Json(serde_json::json!({
        "status": "healthy",
        "sse": state.event_bus.metrics.snapshot(),
        "rtp": build_rtp_metrics(call_metrics, deepgram_rate, deepgram_metrics),
        "chat": state.chat_stream_metrics.snapshot(),
        "ingest": state.ingest_stream_metrics.snapshot(),
        "inbound": state.inbound_metrics.public_snapshot(),
    })))
}

fn realtime_asr_backend_from_env() -> (
    Option<Arc<dyn matric_api::realtime::asr::StreamingASRBackend>>,
    Option<Arc<matric_api::realtime::asr::deepgram::DeepgramMetrics>>,
) {
    match std::env::var("REALTIME_ASR_BACKEND")
        .unwrap_or_else(|_| "deepgram".to_string())
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "mock" => (
            Some(Arc::new(
                matric_api::realtime::asr::MockAsrBackend::default(),
            )),
            None,
        ),
        "" | "disabled" | "none" => (None, None),
        "deepgram" => match matric_api::realtime::asr::deepgram::DeepgramBackend::from_env() {
            Ok(backend) => {
                let metrics = backend.metrics();
                (Some(Arc::new(backend)), Some(metrics))
            }
            Err(error) => {
                tracing::info!(
                    error_len = telemetry_text_len(&error.to_string()),
                    detail = API_PROVIDER_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "realtime_asr_backend_from_env",
                    "Realtime Deepgram ASR backend disabled"
                );
                (None, None)
            }
        },
        other => {
            tracing::warn!(
                backend_len = telemetry_text_len(other),
                detail = API_PROVIDER_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "realtime_asr_backend_selection",
                "Unsupported REALTIME_ASR_BACKEND; realtime ASR disabled"
            );
            (None, None)
        }
    }
}

fn realtime_asr_deepgram_cost_per_minute() -> f64 {
    std::env::var("REALTIME_ASR_COST_DEEPGRAM_DOLLARS_PER_MINUTE")
        .ok()
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value >= 0.0)
        .unwrap_or(0.0036)
}

fn build_rtp_metrics(
    metrics: matric_db::call_sessions::RealtimeCallMetrics,
    deepgram_rate: f64,
    deepgram_metrics: Option<matric_api::realtime::asr::deepgram::DeepgramMetricsSnapshot>,
) -> serde_json::Value {
    let backend_seconds_by_label = metrics
        .duration_seconds_by_backend
        .as_object()
        .cloned()
        .unwrap_or_default();
    let deepgram_seconds = backend_seconds_by_label
        .get("deepgram")
        .and_then(|value| value.as_f64())
        .unwrap_or(0.0);
    let backend_total_seconds: f64 = backend_seconds_by_label
        .values()
        .filter_map(|value| value.as_f64())
        .sum();
    let backend_count = backend_seconds_by_label.len();
    let estimated_cost = (deepgram_seconds / 60.0) * deepgram_rate;
    let deepgram_metrics = deepgram_metrics.unwrap_or(
        matric_api::realtime::asr::deepgram::DeepgramMetricsSnapshot {
            partial_events: 0,
            final_events: 0,
            failover_total: 0,
            partial_latency_sum_ms: 0,
            partial_latency_buckets:
                matric_api::realtime::asr::deepgram::DeepgramPartialLatencyBuckets {
                    le_100: 0,
                    le_250: 0,
                    le_500: 0,
                    le_1000: 0,
                    le_2500: 0,
                    le_inf: 0,
                },
            last_partial_latency_ms: 0,
        },
    );

    serde_json::json!({
        "rtp_call_active_count": {
            "type": "gauge",
            "value": metrics.active_sessions,
            "labels": {}
        },
        "rtp_audio_frame_latency_ms": {
            "type": "histogram",
            "unit": "milliseconds",
            "buckets": [
                {"le": 10, "count": 0},
                {"le": 25, "count": 0},
                {"le": 50, "count": 0},
                {"le": 100, "count": 0},
                {"le": 250, "count": 0},
                {"le": "+Inf", "count": 0}
            ],
            "count": RTP_AUDIO_FRAMES_TOTAL.load(Ordering::Relaxed),
            "sum": 0
        },
        "rtp_codec_decode_failures_total": {
            "type": "counter",
            "value": RTP_CODEC_DECODE_FAILURES_TOTAL.load(Ordering::Relaxed),
            "labels": {"provider": "twilio"}
        },
        "rtp_asr_partial_latency_ms": {
            "type": "histogram",
            "unit": "milliseconds",
            "buckets": [
                {"le": 100, "count": deepgram_metrics.partial_latency_buckets.le_100},
                {"le": 250, "count": deepgram_metrics.partial_latency_buckets.le_250},
                {"le": 500, "count": deepgram_metrics.partial_latency_buckets.le_500},
                {"le": 1000, "count": deepgram_metrics.partial_latency_buckets.le_1000},
                {"le": 2500, "count": deepgram_metrics.partial_latency_buckets.le_2500},
                {"le": "+Inf", "count": deepgram_metrics.partial_latency_buckets.le_inf}
            ],
            "count": deepgram_metrics.partial_events,
            "sum": deepgram_metrics.partial_latency_sum_ms,
            "latest": deepgram_metrics.last_partial_latency_ms
        },
        "rtp_asr_failover_total": {
            "type": "counter",
            "value": deepgram_metrics.failover_total,
            "labels": {"backend": "deepgram"}
        },
        "rtp_outbox_write_failures_total": {
            "type": "counter",
            "value": RTP_OUTBOX_WRITE_FAILURES_TOTAL.load(Ordering::Relaxed)
        },
        "rtp_session_duration_seconds": {
            "type": "histogram",
            "unit": "seconds",
            "buckets": [
                {"le": 30, "count": metrics.duration_buckets.le_30},
                {"le": 60, "count": metrics.duration_buckets.le_60},
                {"le": 300, "count": metrics.duration_buckets.le_300},
                {"le": 900, "count": metrics.duration_buckets.le_900},
                {"le": 1800, "count": metrics.duration_buckets.le_1800},
                {"le": 3600, "count": metrics.duration_buckets.le_3600},
                {"le": "+Inf", "count": metrics.duration_buckets.le_inf}
            ],
            "count": metrics.completed_sessions,
            "sum": metrics.completed_duration_sum_seconds
        },
        "rtp_estimated_asr_cost_dollars_total": {
            "type": "counter",
            "value": estimated_cost,
            "rates_per_minute": {"deepgram": deepgram_rate},
            "duration_seconds_by_backend": {
                "backend_count": backend_count,
                "total_seconds": backend_total_seconds,
                "deepgram_seconds": deepgram_seconds
            }
        },
        "session_totals": {
            "total": metrics.total_sessions,
            "active": metrics.active_sessions,
            "completed": metrics.completed_sessions
        }
    })
}

fn live_probe_response() -> (StatusCode, Json<serde_json::Value>) {
    (
        StatusCode::OK,
        Json(serde_json::json!({ "status": "live" })),
    )
}

#[utoipa::path(
    get,
    path = "/livez",
    tag = "System",
    responses((status = 200, description = "Process is live"))
)]
async fn liveness_probe() -> impl IntoResponse {
    live_probe_response()
}

/// Compatibility alias for the canonical `/livez` process liveness probe.
#[utoipa::path(
    get,
    path = "/health/live",
    tag = "System",
    responses((status = 200, description = "Process is live"))
)]
async fn health_check_live() -> impl IntoResponse {
    live_probe_response()
}

#[utoipa::path(
    get,
    path = "/readyz",
    tag = "System",
    responses(
        (status = 200, description = "Process is ready to serve traffic"),
        (status = 503, description = "Process is draining or a required dependency is unavailable"),
    )
)]
async fn readiness_probe(State(state): State<AppState>) -> impl IntoResponse {
    if !state.lifecycle.is_ready() {
        return (
            StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({
                "status": "not_ready",
                "reason_code": if state.lifecycle.is_draining() {
                    "draining"
                } else {
                    "initializing"
                },
            })),
        );
    }

    if dependencies_ready(&state).await {
        (
            StatusCode::OK,
            Json(serde_json::json!({ "status": "ready" })),
        )
    } else {
        (
            StatusCode::SERVICE_UNAVAILABLE,
            Json(serde_json::json!({
                "status": "not_ready",
                "reason_code": "required_dependency_unavailable",
            })),
        )
    }
}

/// Check required dependencies without coupling readiness to optional backends.
async fn dependencies_ready(state: &AppState) -> bool {
    matches!(
        tokio::time::timeout(
            std::time::Duration::from_secs(5),
            sqlx::query_scalar::<_, i32>("SELECT 1").fetch_one(&state.db.pool),
        )
        .await,
        Ok(Ok(_))
    )
}

// =============================================================================
// NOTE HANDLERS
// =============================================================================

/// Parse relative time string (e.g., "7d", "1w", "2h") into a DateTime.
fn parse_relative_time(s: &str) -> Option<chrono::DateTime<chrono::Utc>> {
    let s = s.trim().to_lowercase();
    if s.is_empty() {
        return None;
    }

    // Parse the number and unit
    let mut num_str = String::new();
    let mut unit = String::new();
    for c in s.chars() {
        if c.is_ascii_digit() {
            num_str.push(c);
        } else {
            unit.push(c);
        }
    }

    let num: i64 = num_str.parse().ok()?;
    let duration = match unit.as_str() {
        "h" | "hr" | "hrs" | "hour" | "hours" => chrono::Duration::hours(num),
        "d" | "day" | "days" => chrono::Duration::days(num),
        "w" | "wk" | "week" | "weeks" => chrono::Duration::weeks(num),
        "m" | "mo" | "month" | "months" => chrono::Duration::days(num * 30),
        "min" | "mins" | "minute" | "minutes" => chrono::Duration::minutes(num),
        _ => return None,
    };

    Some(chrono::Utc::now() - duration)
}

