#[derive(Deserialize, utoipa::ToSchema)]
struct SetTagsBody {
    tags: Vec<String>,
}

impl fmt::Debug for SetTagsBody {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("SetTagsBody")
            .field("tags_count", &self.tags.len())
            .field(
                "tag_lens",
                &self
                    .tags
                    .iter()
                    .map(|tag| telemetry_text_len(tag))
                    .collect::<Vec<_>>(),
            )
            .finish()
    }
}

#[utoipa::path(put, path = "/api/v1/notes/{id}/tags", tag = "Tags",
    params(("id" = Uuid, Path, description = "Note ID")),
    request_body = SetTagsBody,
    responses((status = 204, description = "Success"))
)]
async fn set_note_tags(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Json(body): Json<SetTagsBody>,
) -> Result<impl IntoResponse, ApiError> {
    // Validate tag depth and length (fixes #193, #189)
    for tag in &body.tags {
        if tag.len() > matric_core::defaults::TAG_NAME_MAX_LENGTH {
            return Err(tag_length_validation_error(None));
        }
        let depth = tag
            .split('/')
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
            .count();
        if depth > matric_core::tags::MAX_TAG_PATH_DEPTH {
            return Err(tag_depth_validation_error(None));
        }
    }
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let tags_clone = body.tags.clone();
    ctx.execute(move |tx| {
        Box::pin(async move { repo.set_for_note_tx(tx, id, body.tags, "api").await })
    })
    .await?;

    // Emit NoteTagsUpdated event (Issue #463)
    state.event_bus.emit_with_context(
        ServerEvent::NoteTagsUpdated {
            note_id: id,
            tags: tags_clone,
        },
        event_context_for(&archive_ctx),
    );

    // Invalidate search cache so tag changes are reflected in filtered searches (#341)
    state.search_cache.invalidate_all().await;

    Ok(StatusCode::NO_CONTENT)
}

#[utoipa::path(get, path = "/api/v1/tags", tag = "Tags",
    responses((status = 200, description = "Success"))
)]
