#[utoipa::path(patch, path = "/api/v1/concepts/{id}", tag = "SKOS",
    params(("id" = Uuid, Path,)),
    request_body = matric_core::UpdateConceptRequest,
    responses((status = 200, description = "Success")))]
async fn update_concept(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Json(body): Json<matric_core::UpdateConceptRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let event_attrs = taxonomy_concept_update_attrs(&body);
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let skos = matric_db::PgSkosRepository::new(state.db.pool.clone());
    // Return updated concept for better REST semantics (issue #142)
    let concept = ctx
        .execute(move |tx| {
            Box::pin(async move {
                skos.update_concept_tx(tx, id, body).await?;
                skos.get_concept_with_label_tx(tx, id)
                    .await?
                    .ok_or_else(|| concept_not_found_after_update_error(id))
            })
        })
        .await?;

    state.event_bus.emit_with_context(
        ServerEvent::ConceptUpdated { concept_id: id },
        event_context_for(&archive_ctx),
    );
    emit_taxonomy_audit_event(taxonomy_audit_event(
        "concept_update",
        AuditOutcome::Success,
        "taxonomy_concept",
        id,
        event_attrs,
        Some(&archive_ctx.schema),
    ))
    .await;

    Ok(Json(concept))
}

fn concept_not_found_after_update_error(_id: Uuid) -> matric_core::Error {
    matric_core::Error::NotFound(
        "Concept not found after update; concept_id_present=true".to_string(),
    )
}

