impl std::fmt::Debug for RelatedNote {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("RelatedNote")
            .field("note_id_set", &true)
            .field("score", &self.score)
            .field(
                "snippet_len",
                &self.snippet.as_ref().map(|value| value.len()),
            )
            .field("title_len", &self.title.as_ref().map(|value| value.len()))
            .field("tags_count", &self.tags.len())
            .field("source_len", &self.source.len())
            .finish()
    }
}

/// Query parameters for the related-notes endpoint.
#[derive(Deserialize)]
struct RelatedNotesQuery {
    /// Maximum related notes to return (default: 10, max: 50).
    limit: Option<i64>,
    /// Minimum similarity score threshold (default: 0.3).
    min_score: Option<f32>,
    /// Include an LLM-generated context summary (default: false).
    /// Requires an inference backend to be available.
    context_summary: Option<bool>,
}

impl fmt::Debug for RelatedNotesQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("RelatedNotesQuery")
            .field("limit", &self.limit)
            .field("min_score", &self.min_score)
            .field("context_summary", &self.context_summary)
            .finish()
    }
}

/// Response from the related-notes endpoint.
#[derive(Serialize)]
struct RelatedNotesResponse {
    note_id: Uuid,
    related: Vec<RelatedNote>,
    /// LLM-generated explanation of why these notes are related.
    /// Only present when `context_summary=true` and inference is available.
    #[serde(skip_serializing_if = "Option::is_none")]
    context_summary: Option<String>,
}

impl std::fmt::Debug for RelatedNotesResponse {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("RelatedNotesResponse")
            .field("note_id_set", &true)
            .field("related_count", &self.related.len())
            .field(
                "context_summary_len",
                &self.context_summary.as_ref().map(|value| value.len()),
            )
            .finish()
    }
}

/// Get related notes via semantic similarity and graph links.
///
/// Combines vector-similarity search (if the note has embeddings) with
/// direct graph links to produce a unified list of related notes,
/// optionally enriched with an LLM-generated context summary.
#[utoipa::path(get, path = "/api/v1/notes/{id}/related", tag = "Graph",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("limit" = Option<i64>, Query, description = "Max results (default 10, max 50)"),
        ("min_score" = Option<f32>, Query, description = "Minimum score threshold (default 0.3)"),
        ("context_summary" = Option<bool>, Query, description = "Include LLM context summary"),
    ),
    responses((status = 200, description = "Related notes")))]
async fn get_related_notes(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(query): Query<RelatedNotesQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let pool = state.db.pool.clone();
    let note_id = id;

    let limit = query.limit.unwrap_or(10).clamp(1, 50);
    let min_score = query.min_score.unwrap_or(0.3);
    let want_summary = query.context_summary.unwrap_or(false);

    // 1. Verify note exists
    let notes = matric_db::PgNoteRepository::new(pool.clone());
    let note_exists = ctx
        .query(move |tx| Box::pin(async move { notes.exists_tx(tx, note_id).await }))
        .await?;
    if !note_exists {
        return Err(note_not_found());
    }

    // 2. Get note title for the LLM prompt
    let source_title = {
        let notes = matric_db::PgNoteRepository::new(pool.clone());
        ctx.query(move |tx| {
            Box::pin(async move {
                let full = notes.fetch_tx(tx, note_id).await?;
                Ok(full.note.title.unwrap_or_default())
            })
        })
        .await
        .unwrap_or_default()
    };

    // 3. Find semantically similar notes via embedding vector
    let semantic_hits: Vec<RelatedNote> = {
        let embeds = matric_db::PgEmbeddingRepository::new(pool.clone());
        let embeds2 = matric_db::PgEmbeddingRepository::new(pool.clone());
        // Fetch the note's embedding vector, then find similar
        let hits = ctx
            .query(move |tx| {
                Box::pin(async move {
                    let vec_opt = embeds.get_note_vector_tx(tx, note_id).await?;
                    match vec_opt {
                        Some(vec) => {
                            // Request extra to account for self-exclusion and merging
                            embeds2.find_similar_tx(tx, &vec, limit + 5, true).await
                        }
                        None => Ok(Vec::new()),
                    }
                })
            })
            .await?;

        hits.into_iter()
            .filter(|h| h.note_id != note_id && h.score >= min_score)
            .map(|h| RelatedNote {
                note_id: h.note_id,
                score: h.score,
                snippet: h.snippet,
                title: h.title,
                tags: h.tags,
                source: "semantic".to_string(),
            })
            .collect()
    };

    // 4. Get graph links (outgoing + incoming)
    let link_notes: Vec<RelatedNote> = {
        let links_out = matric_db::PgLinkRepository::new(pool.clone());
        let links_in = matric_db::PgLinkRepository::new(pool.clone());

        let (outgoing, incoming) = ctx
            .query(move |tx| {
                Box::pin(async move {
                    let out = links_out.get_outgoing_tx(tx, note_id).await?;
                    let inc = links_in.get_incoming_tx(tx, note_id).await?;
                    Ok((out, inc))
                })
            })
            .await?;

        let mut link_results: Vec<RelatedNote> = Vec::new();
        for link in outgoing {
            if let Some(to_id) = link.to_note_id {
                if to_id != note_id {
                    link_results.push(RelatedNote {
                        note_id: to_id,
                        score: link.score,
                        snippet: link.snippet,
                        title: None,
                        tags: Vec::new(),
                        source: "link_outgoing".to_string(),
                    });
                }
            }
        }
        for link in incoming {
            if link.from_note_id != note_id {
                link_results.push(RelatedNote {
                    note_id: link.from_note_id,
                    score: link.score,
                    snippet: link.snippet,
                    title: None,
                    tags: Vec::new(),
                    source: "link_incoming".to_string(),
                });
            }
        }
        link_results
    };

    // 5. Merge and deduplicate (prefer semantic over link, keep highest score)
    let mut seen = std::collections::HashMap::<Uuid, usize>::new();
    let mut merged: Vec<RelatedNote> = Vec::new();

    // Add semantic hits first (higher quality — have title, tags, longer snippets)
    for note in semantic_hits {
        seen.insert(note.note_id, merged.len());
        merged.push(note);
    }
    // Add link hits, merging score if already present
    for note in link_notes {
        if let Some(&idx) = seen.get(&note.note_id) {
            // Keep the higher score
            if note.score > merged[idx].score {
                merged[idx].score = note.score;
            }
        } else {
            seen.insert(note.note_id, merged.len());
            merged.push(note);
        }
    }

    // Sort by score descending and truncate to limit
    merged.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    merged.truncate(limit as usize);

    // 6. Optionally generate LLM context summary
    let context_summary = if want_summary && !merged.is_empty() {
        let backend = OllamaBackend::from_env();

        // Build a concise prompt from the related notes
        let mut note_list = String::new();
        for (i, rn) in merged.iter().take(5).enumerate() {
            let title = rn.title.as_deref().unwrap_or("Untitled");
            let snippet = rn
                .snippet
                .as_deref()
                .unwrap_or("")
                .chars()
                .take(120)
                .collect::<String>();
            note_list.push_str(&format!(
                "{}. \"{}\" (score: {:.2}): {}\n",
                i + 1,
                title,
                rn.score,
                snippet
            ));
        }

        let system = "You are a knowledge assistant. Given a source note and its related notes, \
            write a brief 1-2 sentence summary explaining the thematic connection between them. \
            Be specific about the shared topics or concepts. Do not use filler phrases.";
        let prompt = format!(
            "Source note: \"{}\"\n\nRelated notes:\n{}\n\nContext summary:",
            source_title, note_list
        );

        match GenerationBackend::generate_with_system(&backend, system, &prompt).await {
            Ok(summary) => Some(summary.trim().to_string()),
            Err(e) => {
                tracing::warn!(
                    error_len = telemetry_text_len(&e.to_string()),
                    detail = API_RELATED_NOTES_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "generate_related_notes_context_summary",
                    "Failed to generate context summary for related notes"
                );
                None
            }
        }
    } else {
        None
    };

    Ok(Json(RelatedNotesResponse {
        note_id,
        related: merged,
        context_summary,
    }))
}

// =============================================================================
// PROVENANCE HANDLERS (W3C PROV)
// =============================================================================

/// Get W3C PROV provenance chain for a note's AI revisions.
///
/// Returns the full provenance graph including:
/// - Activities (AI processing operations)
/// - Edges (derivation relationships to source notes)
#[utoipa::path(get, path = "/api/v1/notes/{id}/provenance", tag = "Provenance",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn get_note_provenance(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let pool = state.db.pool.clone();
    let note_id = id;

    let chain = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| Box::pin(async move { prov.get_chain_tx(tx, note_id).await }))
            .await?
    };

    let activities = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| {
            Box::pin(async move { prov.get_activities_for_note_tx(tx, note_id).await })
        })
        .await?
    };

    let edges = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| Box::pin(async move { prov.get_edges_for_note_tx(tx, note_id).await }))
            .await?
    };

    let derived = {
        let prov = matric_db::PgProvenanceRepository::new(pool.clone());
        ctx.query(move |tx| Box::pin(async move { prov.get_derived_notes_tx(tx, note_id).await }))
            .await?
    };

    Ok(Json(serde_json::json!({
        "note_id": id,
        "current_chain": chain,
        "all_activities": activities,
        "all_edges": edges,
        "derived_notes": derived,
        "derived_count": derived.len()
    })))
}

// =============================================================================
// MEMORY SEARCH HANDLERS (Spatial/Temporal Provenance)
// =============================================================================

#[derive(Deserialize)]
struct MemorySearchQuery {
    /// Latitude in decimal degrees (-90 to 90)
    lat: Option<f64>,
    /// Longitude in decimal degrees (-180 to 180)
    lon: Option<f64>,
    /// Search radius in meters (default: 1000)
    radius: Option<f64>,
    /// Start of time range (ISO 8601)
    start: Option<crate::query_types::FlexibleDateTime>,
    /// End of time range (ISO 8601)
    end: Option<crate::query_types::FlexibleDateTime>,
}

impl fmt::Debug for MemorySearchQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("MemorySearchQuery")
            .field("lat_set", &self.lat.is_some())
            .field("lon_set", &self.lon.is_some())
            .field("radius_set", &self.radius.is_some())
            .field("start_set", &self.start.is_some())
            .field("end_set", &self.end.is_some())
            .finish()
    }
}

/// Search memories by location, time, or both.
///
/// Query parameter combinations:
/// - `lat` + `lon` + `radius` → spatial search (nearest memories)
/// - `start` + `end` → temporal search (memories in time range)
/// - All five → combined spatial + temporal search
#[utoipa::path(get, path = "/api/v1/memories/search", tag = "Search",
    responses((status = 200, description = "Success")))]
async fn search_memories(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<MemorySearchQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let has_location = query.lat.is_some() && query.lon.is_some();
    let has_time = query.start.is_some() && query.end.is_some();

    if !has_location && !has_time {
        return Err(ApiError::BadRequest(
            "At least one search dimension required. Provide lat+lon for spatial search, \
             start+end for temporal search, or all for combined search."
                .to_string(),
        ));
    }

    // Validate coordinate bounds (issue #148)
    if let Some(lat) = query.lat {
        if !(-90.0..=90.0).contains(&lat) {
            return Err(invalid_memory_search_latitude());
        }
    }
    if let Some(lon) = query.lon {
        if !(-180.0..=180.0).contains(&lon) {
            return Err(invalid_memory_search_longitude());
        }
    }
    if let Some(radius) = query.radius {
        if radius <= 0.0 {
            return Err(invalid_memory_search_radius());
        }
    }
    // Return empty results for inverted time ranges (issue #296)
    if has_time {
        let start_dt = query.start.as_ref().unwrap().0;
        let end_dt = query.end.as_ref().unwrap().0;
        if end_dt < start_dt {
            let mode = if has_location { "combined" } else { "time" };
            return Ok(Json(serde_json::json!({
                "mode": mode,
                "results": [],
                "count": 0
            })));
        }
    }

    if has_location && has_time {
        // Combined spatial + temporal search
        let lat = query.lat.unwrap();
        let lon = query.lon.unwrap();
        let radius = query.radius.unwrap_or(1000.0);
        let start = query.start.unwrap().into_inner();
        let end = query.end.unwrap().into_inner();

        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
        let results = ctx
            .query(move |tx| {
                Box::pin(async move {
                    memory_search
                        .search_by_location_and_time_tx(tx, lat, lon, radius, start, end)
                        .await
                })
            })
            .await?;

        Ok(Json(serde_json::json!({
            "mode": "combined",
            "results": results,
            "count": results.len()
        })))
    } else if has_location {
        // Spatial-only search
        let lat = query.lat.unwrap();
        let lon = query.lon.unwrap();
        let radius = query.radius.unwrap_or(1000.0);

        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
        let results = ctx
            .query(move |tx| {
                Box::pin(async move {
                    memory_search
                        .search_by_location_tx(tx, lat, lon, radius)
                        .await
                })
            })
            .await?;

        Ok(Json(serde_json::json!({
            "mode": "location",
            "results": results,
            "count": results.len()
        })))
    } else {
        // Temporal-only search
        let start = query.start.unwrap().into_inner();
        let end = query.end.unwrap().into_inner();

        let ctx = state.db.for_schema(&archive_ctx.schema)?;
        let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
        let results = ctx
            .query(move |tx| {
                Box::pin(async move { memory_search.search_by_timerange_tx(tx, start, end).await })
            })
            .await?;

        Ok(Json(serde_json::json!({
            "mode": "time",
            "results": results,
            "count": results.len()
        })))
    }
}

/// Get the complete file provenance chain for a note's attachments.
///
/// Returns temporal-spatial provenance including location, device, and
/// capture time information for all file attachments.
#[utoipa::path(get, path = "/api/v1/notes/{id}/memory-provenance", tag = "Provenance",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn get_memory_provenance_handler(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let memory_search = matric_db::PgMemorySearchRepository::new(state.db.pool.clone());
    let provenance = ctx
        .query(move |tx| {
            Box::pin(async move { memory_search.get_memory_provenance_tx(tx, id).await })
        })
        .await?;

    match provenance {
        Some(prov) => Ok(Json(serde_json::json!(prov))),
        None => Ok(Json(serde_json::json!({
            "note_id": id,
            "files": []
        }))),
    }
}

// =============================================================================
// EXPORT HANDLERS
// =============================================================================

#[derive(Deserialize)]
struct ExportQuery {
    /// Include YAML frontmatter with metadata (default: true)
    #[serde(default = "default_true")]
    include_frontmatter: bool,
    /// Content version: "revised" (default) or "original"
    #[serde(default)]
    content: Option<String>,
}

impl fmt::Debug for ExportQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ExportQuery")
            .field("include_frontmatter", &self.include_frontmatter)
            .field(
                "content_len",
                &self.content.as_deref().map(telemetry_text_len),
            )
            .finish()
    }
}

fn default_true() -> bool {
    true
}

#[utoipa::path(get, path = "/api/v1/notes/{id}/export", tag = "Notes",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn export_note(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(query): Query<ExportQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let tag_repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let (note_full, tags) = ctx
        .query(move |tx| {
            Box::pin(async move {
                let note = notes.fetch_tx(tx, id).await?;
                let tags = tag_repo.get_for_note_tx(tx, id).await?;
                Ok((note, tags))
            })
        })
        .await?;

    let mut output = String::new();

    // Add YAML frontmatter if requested
    if query.include_frontmatter {
        output.push_str("---\n");
        output.push_str(&format!("id: {}\n", note_full.note.id));
        if let Some(ref title) = note_full.note.title {
            // Escape title for YAML
            let escaped_title = title.replace('\"', "\\\"");
            output.push_str(&format!("title: \"{}\"\n", escaped_title));
        }
        output.push_str(&format!(
            "created: {}\n",
            note_full.note.created_at_utc.to_rfc3339()
        ));
        output.push_str(&format!(
            "updated: {}\n",
            note_full.note.updated_at_utc.to_rfc3339()
        ));
        if note_full.note.starred {
            output.push_str("starred: true\n");
        }
        if note_full.note.archived {
            output.push_str("archived: true\n");
        }
        if !tags.is_empty() {
            output.push_str("tags:\n");
            for tag in &tags {
                output.push_str(&format!("  - {}\n", tag));
            }
        }
        if let Some(collection_id) = note_full.note.collection_id {
            output.push_str(&format!("collection_id: {}\n", collection_id));
        }
        output.push_str("---\n\n");
    }

    // Add content (revised by default, original if requested)
    let use_original = query.content.as_deref() == Some("original");
    let content = if use_original || note_full.revised.content.is_empty() {
        &note_full.original.content
    } else {
        &note_full.revised.content
    };
    output.push_str(content);

    // Return as markdown with appropriate headers
    let filename = note_export_download_filename(note_full.note.title.as_deref(), id);

    let mut headers = HeaderMap::new();
    headers.insert(
        header::CONTENT_TYPE,
        "text/markdown; charset=utf-8".parse().unwrap(),
    );
    headers.insert(
        header::CONTENT_DISPOSITION,
        format!("attachment; filename=\"{}.md\"", filename)
            .parse()
            .unwrap(),
    );

    Ok((StatusCode::OK, headers, output))
}

fn note_export_download_filename(title: Option<&str>, note_id: Uuid) -> String {
    match title {
        Some(title) => format!(
            "note_title_len_{}_{}.md",
            telemetry_text_len(title),
            note_id
        ),
        None => format!("note_{}.md", note_id),
    }
}

// =============================================================================
// DOCUMENT RECONSTRUCTION HANDLER (#111)
// =============================================================================

/// Get the full reconstructed document for a note (works with both chunked and regular notes).
///
/// For chunked documents, this endpoint:
/// - Identifies all chunks in the document chain
/// - Stitches them back together in order
/// - Removes overlaps between chunks
/// - Returns the full content with metadata about chunks
///
/// For regular notes, it simply returns the note content as-is.
#[utoipa::path(get, path = "/api/v1/notes/{id}/full", tag = "Notes",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn get_full_document(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    if archive_ctx.schema != "public" {
        return Err(ApiError::BadRequest(
            "Document reconstruction not yet supported for non-default archives".to_string(),
        ));
    }
    use matric_api::services::ReconstructionService;

    let reconstruction_service = ReconstructionService::new(state.db.clone());
    let full_document = reconstruction_service.get_full_document(id).await?;

    Ok(Json(full_document))
}

// =============================================================================
// NOTE VERSIONING HANDLERS (#104)
// =============================================================================

/// List all versions for a note (both original and revision tracks).
#[utoipa::path(get, path = "/api/v1/notes/{id}/versions", tag = "Notes",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn list_note_versions(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let notes = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let versioning = matric_db::VersioningRepository::new(state.db.pool.clone());
    let versions = ctx
        .query(move |tx| {
            Box::pin(async move {
                let _ = notes.fetch_tx(tx, id).await?;
                versioning.list_versions_tx(tx, id).await
            })
        })
        .await?;

    Ok(Json(serde_json::json!({
        "note_id": versions.note_id,
        "current_original_version": versions.current_original_version,
        "current_revision_number": versions.current_revision_number,
        "original_versions": versions.original_versions.iter().map(|v| serde_json::json!({
            "version_number": v.version_number,
            "created_at_utc": v.created_at_utc.to_rfc3339(),
            "created_by": v.created_by,
            "is_current": v.is_current
        })).collect::<Vec<_>>(),
        "revised_versions": versions.revised_versions.iter().map(|v| serde_json::json!({
            "id": v.id,
            "revision_number": v.revision_number,
            "created_at_utc": v.created_at_utc.to_rfc3339(),
            "model": v.model,
            "is_user_edited": v.is_user_edited
        })).collect::<Vec<_>>()
    })))
}

#[derive(Deserialize)]
struct GetVersionQuery {
    /// Track to get version from: "original" or "revision" (default: "original")
    track: Option<String>,
}

impl fmt::Debug for GetVersionQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("GetVersionQuery")
            .field("track_len", &self.track.as_deref().map(telemetry_text_len))
            .finish()
    }
}

/// Get a specific version of a note.
#[utoipa::path(get, path = "/api/v1/notes/{id}/versions/{version}", tag = "Notes",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("version" = i32, Path, description = "Version number")
    ),
    responses((status = 200, description = "Success")))]
async fn get_note_version(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((id, version)): Path<(Uuid, i32)>,
    Query(query): Query<GetVersionQuery>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let track = query.track.as_deref().unwrap_or("original");
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let repo = matric_db::VersioningRepository::new(state.db.pool.clone());

    match track {
        "original" => {
            let version_data = ctx
                .query(move |tx| {
                    Box::pin(async move { repo.get_original_version_tx(tx, id, version).await })
                })
                .await?
                .ok_or_else(note_version_not_found)?;

            Ok(Json(serde_json::json!({
                "track": "original",
                "id": version_data.id,
                "note_id": version_data.note_id,
                "version_number": version_data.version_number,
                "content": version_data.content,
                "hash": version_data.hash,
                "created_at_utc": version_data.created_at_utc.to_rfc3339(),
                "created_by": version_data.created_by
            })))
        }
        "revision" => {
            let revision = ctx
                .query(move |tx| {
                    Box::pin(async move { repo.get_revision_version_tx(tx, id, version).await })
                })
                .await?
                .ok_or_else(note_revision_not_found)?;

            Ok(Json(serde_json::json!({
                "track": "revision",
                "id": revision.id,
                "note_id": revision.note_id,
                "revision_number": revision.revision_number,
                "content": revision.content,
                "type": revision.revision_type,
                "summary": revision.summary,
                "rationale": revision.rationale,
                "created_at_utc": revision.created_at_utc.to_rfc3339(),
                "model": revision.model,
                "is_user_edited": revision.is_user_edited
            })))
        }
        _ => Err(ApiError::BadRequest(
            "Invalid track. Use 'original' or 'revision'".to_string(),
        )),
    }
}

#[derive(Default, Deserialize, utoipa::ToSchema)]
struct RestoreVersionRequest {
    /// Whether to restore tags from the version snapshot (default: false)
    #[serde(default)]
    restore_tags: bool,
}

impl fmt::Debug for RestoreVersionRequest {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("RestoreVersionRequest")
            .field("restore_tags", &self.restore_tags)
            .finish()
    }
}

/// Restore a previous version of a note.
#[utoipa::path(post, path = "/api/v1/notes/{id}/versions/{version}/restore", tag = "Notes",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("version" = i32, Path, description = "Version number")
    ),
    responses((status = 200, description = "Success")))]
async fn restore_note_version(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((id, version)): Path<(Uuid, i32)>,
    body: Option<Json<RestoreVersionRequest>>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let request = body.map(|j| j.0).unwrap_or_default();
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let repo = matric_db::VersioningRepository::new(state.db.pool.clone());
    let restore_tags = request.restore_tags;
    let new_version = ctx
        .execute(move |tx| {
            Box::pin(async move {
                repo.restore_original_version_tx(tx, id, version, restore_tags)
                    .await
            })
        })
        .await?;

    Ok(Json(serde_json::json!({
        "success": true,
        "restored_from_version": version,
        "new_version": new_version,
        "restore_tags": request.restore_tags
    })))
}

/// Delete a specific version from history.
#[utoipa::path(delete, path = "/api/v1/notes/{id}/versions/{version}", tag = "Notes",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("version" = i32, Path, description = "Version number")
    ),
    responses((status = 200, description = "Success")))]
async fn delete_note_version(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((id, version)): Path<(Uuid, i32)>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let repo = matric_db::VersioningRepository::new(state.db.pool.clone());
    let deleted = ctx
        .execute(move |tx| Box::pin(async move { repo.delete_version_tx(tx, id, version).await }))
        .await?;

    if deleted {
        Ok(Json(serde_json::json!({
            "success": true,
            "deleted_version": version
        })))
    } else {
        Err(note_version_not_found())
    }
}

#[derive(Deserialize)]
struct DiffVersionsQuery {
    /// Version to diff from
    #[serde(alias = "from_version")]
    from: i32,
    /// Version to diff to
    #[serde(alias = "to_version")]
    to: i32,
}

impl fmt::Debug for DiffVersionsQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("DiffVersionsQuery")
            .field("from", &self.from)
            .field("to", &self.to)
            .finish()
    }
}

/// Generate a diff between two versions.
#[utoipa::path(get, path = "/api/v1/notes/{id}/versions/diff", tag = "Notes",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn diff_note_versions(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(query): Query<DiffVersionsQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let repo = matric_db::VersioningRepository::new(state.db.pool.clone());
    let from = query.from;
    let to = query.to;
    let diff = ctx
        .query(move |tx| Box::pin(async move { repo.diff_versions_tx(tx, id, from, to).await }))
        .await?;

    // Return as plain text (unified diff format)
    let mut headers = HeaderMap::new();
    headers.insert(
        header::CONTENT_TYPE,
        "text/plain; charset=utf-8".parse().unwrap(),
    );

    Ok((StatusCode::OK, headers, diff))
}

