const INVALID_JOB_TYPE_MESSAGE: &str =
    "Invalid job_type. Use a supported job type from the API contract.";

#[derive(Deserialize, utoipa::ToSchema)]
struct CreateJobBody {
    note_id: Option<Uuid>,
    job_type: String,
    priority: Option<i32>,
    payload: Option<serde_json::Value>,
    /// When true, skip if a pending job with the same note_id+job_type already exists.
    #[serde(default)]
    deduplicate: bool,
}

impl fmt::Debug for CreateJobBody {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("CreateJobBody")
            .field("note_id_set", &self.note_id.is_some())
            .field("job_type_len", &telemetry_text_len(&self.job_type))
            .field("priority", &self.priority)
            .field(
                "payload_class",
                &self.payload.as_ref().map(webhook_delivery_json_class),
            )
            .field(
                "payload_len",
                &self
                    .payload
                    .as_ref()
                    .map(|payload| telemetry_text_len(&payload.to_string())),
            )
            .field(
                "payload_secret_candidate",
                &self
                    .payload
                    .as_ref()
                    .is_some_and(webhook_delivery_json_has_secret_candidate),
            )
            .field("deduplicate", &self.deduplicate)
            .finish()
    }
}

#[derive(Serialize)]
struct JobResponse {
    id: Uuid,
    note_id: Option<Uuid>,
    job_type: JobType,
    status: JobStatus,
    priority: i32,
    payload: Option<serde_json::Value>,
    result: Option<serde_json::Value>,
    error_message: Option<String>,
    progress_percent: i32,
    progress_message: Option<String>,
    retry_count: i32,
    max_retries: i32,
    created_at: DateTime<Utc>,
    started_at: Option<DateTime<Utc>>,
    completed_at: Option<DateTime<Utc>>,
    cost_tier: Option<i16>,
}

impl fmt::Debug for JobResponse {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("JobResponse")
            .field("id_present", &true)
            .field("note_id_present", &self.note_id.is_some())
            .field("job_type", &self.job_type)
            .field("status", &self.status)
            .field("priority", &self.priority)
            .field(
                "payload_class",
                &self.payload.as_ref().map(webhook_delivery_json_class),
            )
            .field(
                "payload_len",
                &self
                    .payload
                    .as_ref()
                    .map(|payload| telemetry_text_len(&payload.to_string())),
            )
            .field(
                "result_class",
                &self.result.as_ref().map(webhook_delivery_json_class),
            )
            .field(
                "result_len",
                &self
                    .result
                    .as_ref()
                    .map(|result| telemetry_text_len(&result.to_string())),
            )
            .field(
                "error_message_len",
                &self.error_message.as_deref().map(telemetry_text_len),
            )
            .field("progress_percent", &self.progress_percent)
            .field(
                "progress_message_len",
                &self.progress_message.as_deref().map(telemetry_text_len),
            )
            .field("retry_count", &self.retry_count)
            .field("max_retries", &self.max_retries)
            .field("created_at", &self.created_at)
            .field("started_at_present", &self.started_at.is_some())
            .field("completed_at_present", &self.completed_at.is_some())
            .field("cost_tier", &self.cost_tier)
            .finish()
    }
}

impl From<Job> for JobResponse {
    fn from(job: Job) -> Self {
        let error_message = job
            .error_message
            .map(|_| "Job failed. Check server logs for diagnostics.".to_string());

        Self {
            id: job.id,
            note_id: job.note_id,
            job_type: job.job_type,
            status: job.status,
            priority: job.priority,
            payload: job.payload.as_ref().map(sanitize_job_value),
            result: job.result.as_ref().map(sanitize_job_value),
            error_message,
            progress_percent: job.progress_percent,
            progress_message: job.progress_message,
            retry_count: job.retry_count,
            max_retries: job.max_retries,
            created_at: job.created_at,
            started_at: job.started_at,
            completed_at: job.completed_at,
            cost_tier: job.cost_tier,
        }
    }
}

fn sanitize_job_value(value: &serde_json::Value) -> serde_json::Value {
    match value {
        serde_json::Value::Object(map) => serde_json::Value::Object(
            map.iter()
                .map(|(key, value)| {
                    let sanitized = if is_sensitive_job_key(key) {
                        serde_json::Value::String("[redacted]".to_string())
                    } else {
                        sanitize_job_value(value)
                    };
                    (key.clone(), sanitized)
                })
                .collect(),
        ),
        serde_json::Value::Array(values) => {
            serde_json::Value::Array(values.iter().map(sanitize_job_value).collect())
        }
        serde_json::Value::String(value) if looks_sensitive_job_string(value) => {
            serde_json::Value::String("[redacted]".to_string())
        }
        _ => value.clone(),
    }
}

fn is_sensitive_job_key(key: &str) -> bool {
    let key = key.to_ascii_lowercase();
    [
        "api_key",
        "authorization",
        "bearer",
        "content",
        "dsn",
        "error",
        "exception",
        "file",
        "filename",
        "input",
        "message",
        "password",
        "path",
        "prompt",
        "raw",
        "stderr",
        "stdout",
        "secret",
        "text",
        "token",
        "transcript",
        "uri",
        "url",
    ]
    .iter()
    .any(|needle| key == *needle || key.ends_with(&format!("_{needle}")))
}

fn looks_sensitive_job_string(value: &str) -> bool {
    let lower = value.to_ascii_lowercase();
    lower.contains("://")
        || lower.contains("postgres")
        || lower.contains("sql")
        || lower.contains("bearer ")
        || lower.contains("api_key")
        || lower.contains("token")
        || lower.contains("secret")
        || lower.contains("generation failed:")
        || lower.contains("ai generation failed:")
        || value.starts_with("/srv/")
        || value.starts_with("/home/")
        || value.starts_with("/var/")
        || value.starts_with("/tmp/")
}

#[utoipa::path(post, path = "/api/v1/jobs", tag = "Jobs",
    responses((status = 201, description = "Success")))]
async fn create_job(
    State(state): State<AppState>,
    Json(body): Json<CreateJobBody>,
) -> Result<impl IntoResponse, ApiError> {
    let job_type = match body.job_type.as_str() {
        "ai_revision" => JobType::AiRevision,
        "embedding" => JobType::Embedding,
        "linking" => JobType::Linking,
        "context_update" => JobType::ContextUpdate,
        "title_generation" => JobType::TitleGeneration,
        "concept_tagging" => JobType::ConceptTagging,
        "reference_extraction" => JobType::ReferenceExtraction,
        "related_concept_inference" => JobType::RelatedConceptInference,
        "re_embed_all" => JobType::ReEmbedAll,
        "extraction" => JobType::Extraction,
        "exif_extraction" => JobType::ExifExtraction,
        "graph_maintenance" => JobType::GraphMaintenance,
        "speaker_diarization" => JobType::SpeakerDiarization,
        "speaker_relabel" => JobType::SpeakerRelabel,
        "media_optimize" => JobType::MediaOptimize,
        "audio_transcription" => JobType::AudioTranscription,
        "audio_chunk_transcription" => JobType::AudioChunkTranscription,
        "keyframe_vision" => JobType::KeyframeVision,
        "keyframe_assembly" => JobType::KeyframeAssembly,
        "view_vision" => JobType::ViewVision,
        "view_assembly" => JobType::ViewAssembly,
        "thumbnail_sprite" => JobType::ThumbnailSprite,
        _ => return Err(ApiError::BadRequest(INVALID_JOB_TYPE_MESSAGE.to_string())),
    };

    // Validate note exists before queuing (avoids raw FK constraint error)
    if let Some(note_id) = body.note_id {
        state
            .db
            .notes
            .fetch(note_id)
            .await
            .map_err(|_| note_not_found())?;
    }

    let priority = body.priority.unwrap_or_else(|| job_type.default_priority());

    if body.deduplicate {
        // Deduplicated queuing: skip if same note_id+job_type already pending
        let maybe_id = state
            .db
            .jobs
            .queue_deduplicated(body.note_id, job_type, priority, body.payload, None)
            .await?;

        match maybe_id {
            Some(job_id) => {
                state.event_bus.emit(ServerEvent::JobQueued {
                    job_id,
                    job_type: format!("{:?}", job_type),
                    note_id: body.note_id,
                });
                Ok((
                    StatusCode::CREATED,
                    Json(serde_json::json!({
                        "id": job_id,
                        "status": "queued"
                    })),
                ))
            }
            None => Ok((
                StatusCode::OK,
                Json(serde_json::json!({
                    "id": null,
                    "status": "already_pending"
                })),
            )),
        }
    } else {
        let job_id = state
            .db
            .jobs
            .queue(body.note_id, job_type, priority, body.payload, None)
            .await?;

        state.event_bus.emit(ServerEvent::JobQueued {
            job_id,
            job_type: format!("{:?}", job_type),
            note_id: body.note_id,
        });

        Ok((
            StatusCode::CREATED,
            Json(serde_json::json!({
                "id": job_id,
                "status": "queued",
                "message": format!("{:?} job queued", job_type),
            })),
        ))
    }
}

