// =============================================================================
// OAUTH2 HANDLERS
// =============================================================================

async fn emit_oauth_lifecycle_audit_event(event: AuditEvent) {
    if let Err(err) = TracingSink.emit(event).await {
        warn!(
            error_len = telemetry_text_len(&err.to_string()),
            detail = API_AUDIT_EMIT_DIAGNOSTIC_FAILURE_DETAIL,
            operation = "emit_oauth_lifecycle_audit_event",
            "failed to emit OAuth lifecycle audit event"
        );
    }
}

fn oauth_principal_audit_id(client_id: &str, user_id: Option<&str>) -> String {
    if user_id.is_some() {
        "oauth_user".to_string()
    } else {
        format!("oauth_client_len:{}", client_id.chars().count())
    }
}

fn oauth_grant_type_class(grant_type: &str) -> &'static str {
    match grant_type {
        "authorization_code" => "authorization_code",
        "client_credentials" => "client_credentials",
        "refresh_token" => "refresh_token",
        _ => "unknown",
    }
}

fn oauth_token_hint_class(token_type_hint: Option<&str>) -> &'static str {
    match token_type_hint {
        Some("access_token") => "access_token",
        Some("refresh_token") => "refresh_token",
        Some("") | None => "none",
        Some(_) => "unknown",
    }
}

fn oauth_scope_count(scope: &str) -> i64 {
    scope
        .split_whitespace()
        .filter(|part| !part.is_empty())
        .count() as i64
}

fn oauth_invalid_grant_type_detail(grant_type: &str) -> String {
    format!(
        "Invalid grant_type: grant_type_len={}, allowed_count={}",
        telemetry_text_len(grant_type),
        ALLOWED_GRANT_TYPES.len()
    )
}

fn oauth_invalid_scope_detail(scope: &str) -> String {
    format!(
        "Invalid scope: scope_len={}, allowed_count={}",
        telemetry_text_len(scope),
        active_oauth_capabilities().scopes.len()
    )
}

fn oauth_unsupported_grant_type_detail(grant_type: &str) -> String {
    format!(
        "Unsupported grant type: grant_type_len={}, allowed_count={}",
        telemetry_text_len(grant_type),
        ALLOWED_GRANT_TYPES.len()
    )
}

fn oauth_token_issue_audit_event(
    client_id: &str,
    grant_type: &str,
    token: &matric_core::OAuthToken,
    refresh_token_issued: bool,
    expires_in: i64,
) -> AuditEvent {
    let mut event = AuditEvent::new("oauth", "token_issue", AuditOutcome::Success)
        .with_principal(oauth_principal_audit_id(
            client_id,
            token.user_id.as_deref(),
        ))
        .with_resource("oauth_token", token.id.to_string())
        .with_attr("client_id_len", client_id.chars().count() as i64)
        .with_attr("grant_type", oauth_grant_type_class(grant_type))
        .with_attr("scope_count", oauth_scope_count(&token.scope))
        .with_attr("scope_len", token.scope.chars().count() as i64)
        .with_attr("refresh_credential_issued", refresh_token_issued)
        .with_attr("expires_in_secs", expires_in)
        .with_attr("user_id_present", token.user_id.is_some());

    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.severity = AuditSeverity::Info;
    event.sanitized()
}

fn oauth_introspection_audit_event(
    client_id: &str,
    request: &IntrospectRequest,
    response: &TokenIntrospectionResponse,
) -> AuditEvent {
    let mut event = AuditEvent::new("oauth", "token_introspect", AuditOutcome::Success)
        .with_principal(oauth_principal_audit_id(client_id, None))
        .with_attr("client_id_len", client_id.chars().count() as i64)
        .with_attr("credential_present", !request.token.is_empty())
        .with_attr("credential_len", request.token.chars().count() as i64)
        .with_attr(
            "credential_type_hint",
            oauth_token_hint_class(request.token_type_hint.as_deref()),
        )
        .with_attr("active", response.active)
        .with_attr("response_client_id_present", response.client_id.is_some())
        .with_attr(
            "response_user_id_present",
            response.username.is_some() || response.sub.is_some(),
        )
        .with_attr(
            "response_scope_count",
            response
                .scope
                .as_deref()
                .map(oauth_scope_count)
                .unwrap_or(0),
        )
        .with_attr(
            "response_credential_type",
            oauth_token_hint_class(response.token_type.as_deref()),
        );

    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.severity = AuditSeverity::Info;
    event.sanitized()
}

fn oauth_revocation_audit_event(
    client_id: &str,
    request: &RevokeRequest,
    revoked: bool,
) -> AuditEvent {
    let mut event = AuditEvent::new("oauth", "token_revoke", AuditOutcome::Success)
        .with_principal(oauth_principal_audit_id(client_id, None))
        .with_attr("client_id_len", client_id.chars().count() as i64)
        .with_attr("credential_present", !request.token.is_empty())
        .with_attr("credential_len", request.token.chars().count() as i64)
        .with_attr(
            "credential_type_hint",
            oauth_token_hint_class(request.token_type_hint.as_deref()),
        )
        .with_attr("revoked", revoked);

    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.severity = AuditSeverity::Info;
    event.sanitized()
}

/// OAuth2 authorization server metadata (RFC 8414).
fn oauth_authorization_server_metadata(issuer: &str) -> AuthorizationServerMetadata {
    let capabilities = active_oauth_capabilities();
    AuthorizationServerMetadata {
        issuer: issuer.to_string(),
        authorization_endpoint: format!("{issuer}/oauth/authorize"),
        token_endpoint: format!("{issuer}/oauth/token"),
        registration_endpoint: capabilities
            .advertise_registration_endpoint
            .then(|| format!("{issuer}/oauth/register")),
        introspection_endpoint: Some(format!("{issuer}/oauth/introspect")),
        revocation_endpoint: Some(format!("{issuer}/oauth/revoke")),
        response_types_supported: vec!["code".to_string()],
        grant_types_supported: vec![
            "authorization_code".to_string(),
            "client_credentials".to_string(),
            "refresh_token".to_string(),
        ],
        token_endpoint_auth_methods_supported: capabilities.token_endpoint_auth_methods.clone(),
        scopes_supported: capabilities.scopes.clone(),
        code_challenge_methods_supported: Some(capabilities.pkce_methods.clone()),
    }
}

#[utoipa::path(get, path = "/.well-known/oauth-authorization-server", tag = "OAuth",
    responses((status = 200, description = "Success")))]
async fn oauth_discovery(State(state): State<AppState>) -> impl IntoResponse {
    Json(oauth_authorization_server_metadata(&state.issuer))
}

/// OAuth Protected Resource Metadata (RFC 9728).
/// Required by MCP OAuth clients to discover authorization server.
fn oauth_protected_resource_metadata(issuer: &str) -> serde_json::Value {
    let capabilities = active_oauth_capabilities();
    serde_json::json!({
        "resource": issuer,
        "authorization_servers": [issuer],
        "bearer_methods_supported": ["header"],
        "scopes_supported": capabilities.scopes,
    })
}

#[utoipa::path(get, path = "/.well-known/oauth-protected-resource", tag = "OAuth",
    responses((status = 200, description = "Success")))]
async fn oauth_protected_resource(State(state): State<AppState>) -> impl IntoResponse {
    Json(oauth_protected_resource_metadata(&state.issuer))
}

/// OAuth2 Dynamic Client Registration (RFC 7591).
/// Allowed OAuth2 grant types for client registration.
const ALLOWED_GRANT_TYPES: &[&str] = &["authorization_code", "client_credentials", "refresh_token"];

#[utoipa::path(post, path = "/oauth/register", tag = "OAuth",
    request_body = ClientRegistrationRequest,
    responses((status = 201, description = "Created")))]
async fn oauth_register(
    State(state): State<AppState>,
    Json(req): Json<ClientRegistrationRequest>,
) -> Result<impl IntoResponse, OAuthApiError> {
    // Validate grant types (Issue #115 — AUTH-004)
    for gt in &req.grant_types {
        if !ALLOWED_GRANT_TYPES.contains(&gt.as_str()) {
            let msg = oauth_invalid_grant_type_detail(gt);
            return Err(OAuthApiError::OAuth(OAuthError::invalid_request(&msg)));
        }
    }

    // Validate scope if provided
    if let Some(ref scope) = req.scope {
        for s in scope.split_whitespace() {
            if !is_allowed_oauth_scope(s) {
                let msg = oauth_invalid_scope_detail(s);
                return Err(OAuthApiError::OAuth(OAuthError::invalid_request(&msg)));
            }
        }
    }

    let mut response = state.db.oauth.register_client(req).await?;

    // Set the registration_client_uri based on our issuer
    response.registration_client_uri = Some(format!(
        "{}/oauth/register/{}",
        state.issuer, response.client_id
    ));

    Ok((StatusCode::CREATED, Json(response)))
}

/// Parse client credentials from Authorization header or body.
fn parse_client_credentials(
    headers: &HeaderMap,
    client_id: Option<&str>,
    client_secret: Option<&str>,
) -> Option<(String, String)> {
    // Try Authorization header first (client_secret_basic)
    if let Some(auth_header) = headers.get(header::AUTHORIZATION) {
        if let Ok(auth_str) = auth_header.to_str() {
            if let Some(basic_auth) = auth_str.strip_prefix("Basic ") {
                if let Ok(decoded) = base64_decode(basic_auth) {
                    if let Ok(decoded_str) = String::from_utf8(decoded) {
                        if let Some((id, secret)) = decoded_str.split_once(':') {
                            return Some((id.to_string(), secret.to_string()));
                        }
                    }
                }
            }
        }
    }

    // Fall back to body parameters (client_secret_post)
    if let (Some(id), Some(secret)) = (client_id, client_secret) {
        return Some((id.to_string(), secret.to_string()));
    }

    None
}

/// Base64 decode helper.
fn base64_decode(input: &str) -> Result<Vec<u8>, base64::DecodeError> {
    use base64::{engine::general_purpose::STANDARD, Engine};
    STANDARD.decode(input)
}

impl AppState {
    /// Determine token lifetime based on scope.
    ///
    /// MCP clients (scope contains "mcp") get longer tokens to support interactive sessions.
    /// Lifetimes are configurable via `OAUTH_TOKEN_LIFETIME_SECS` and `OAUTH_MCP_TOKEN_LIFETIME_SECS`.
    fn token_lifetime_for_scope(&self, scope: &str) -> chrono::Duration {
        if scope.contains("mcp") {
            self.oauth_mcp_token_lifetime
        } else {
            self.oauth_token_lifetime
        }
    }
}

/// OAuth2 token endpoint.
#[utoipa::path(post, path = "/oauth/token", tag = "OAuth",
    responses((status = 200, description = "Success")))]
async fn oauth_token(
    State(state): State<AppState>,
    headers: HeaderMap,
    Form(req): Form<TokenRequest>,
) -> Result<impl IntoResponse, OAuthApiError> {
    // Parse client credentials
    let (client_id, client_secret) = parse_client_credentials(
        &headers,
        req.client_id.as_deref(),
        req.client_secret.as_deref(),
    )
    .ok_or_else(|| {
        OAuthApiError::OAuth(OAuthError::invalid_client("Missing client credentials"))
    })?;

    // Validate client credentials
    let valid = state
        .db
        .oauth
        .validate_client(&client_id, &client_secret)
        .await?;
    if !valid {
        return Err(OAuthApiError::OAuth(OAuthError::invalid_client(
            "Invalid client credentials",
        )));
    }

    match req.grant_type.as_str() {
        "client_credentials" => {
            // Check if client supports this grant type
            if !state
                .db
                .oauth
                .client_supports_grant(&client_id, "client_credentials")
                .await?
            {
                return Err(OAuthApiError::OAuth(OAuthError::unauthorized_client(
                    "Client not authorized for client_credentials grant",
                )));
            }

            // Get client to determine scope
            let client = state
                .db
                .oauth
                .get_client(&client_id)
                .await?
                .ok_or_else(|| {
                    OAuthApiError::OAuth(OAuthError::invalid_client("Client not found"))
                })?;

            let scope = req.scope.unwrap_or(client.scope);
            let lifetime = state.token_lifetime_for_scope(&scope);
            let (access_token, _, token) = state
                .db
                .oauth
                .create_token_with_lifetime(&client_id, &scope, None, false, lifetime)
                .await?;
            emit_oauth_lifecycle_audit_event(oauth_token_issue_audit_event(
                &client_id,
                "client_credentials",
                &token,
                false,
                lifetime.num_seconds(),
            ))
            .await;

            let response = matric_core::TokenResponse {
                access_token,
                token_type: "Bearer".to_string(),
                expires_in: lifetime.num_seconds(),
                refresh_token: None,
                scope: Some(token.scope),
            };
            Ok(Json(response))
        }

        "authorization_code" => {
            let code = req
                .code
                .as_deref()
                .ok_or_else(|| OAuthApiError::OAuth(OAuthError::invalid_request("Missing code")))?;
            let redirect_uri = req.redirect_uri.as_deref().ok_or_else(|| {
                OAuthApiError::OAuth(OAuthError::invalid_request("Missing redirect_uri"))
            })?;

            // Consume the authorization code
            let auth_code = state
                .db
                .oauth
                .consume_authorization_code(
                    code,
                    &client_id,
                    redirect_uri,
                    req.code_verifier.as_deref(),
                )
                .await
                .map_err(|_| {
                    OAuthApiError::OAuth(OAuthError::invalid_grant(
                        "Invalid or expired authorization code",
                    ))
                })?;

            // Create tokens
            let lifetime = state.token_lifetime_for_scope(&auth_code.scope);
            let (access_token, refresh_token, token) = state
                .db
                .oauth
                .create_token_with_lifetime(
                    &client_id,
                    &auth_code.scope,
                    auth_code.user_id.as_deref(),
                    true,
                    lifetime,
                )
                .await?;
            emit_oauth_lifecycle_audit_event(oauth_token_issue_audit_event(
                &client_id,
                "authorization_code",
                &token,
                refresh_token.is_some(),
                lifetime.num_seconds(),
            ))
            .await;

            let response = matric_core::TokenResponse {
                access_token,
                token_type: "Bearer".to_string(),
                expires_in: lifetime.num_seconds(),
                refresh_token,
                scope: Some(token.scope),
            };
            Ok(Json(response))
        }

        "refresh_token" => {
            let refresh_token = req.refresh_token.as_deref().ok_or_else(|| {
                OAuthApiError::OAuth(OAuthError::invalid_request("Missing refresh_token"))
            })?;

            let (access_token, new_refresh_token, token) = state
                .db
                .oauth
                .refresh_access_token(refresh_token, &client_id)
                .await
                .map_err(|_| {
                    OAuthApiError::OAuth(OAuthError::invalid_grant("Invalid refresh token"))
                })?;

            let lifetime = state.token_lifetime_for_scope(&token.scope);
            emit_oauth_lifecycle_audit_event(oauth_token_issue_audit_event(
                &client_id,
                "refresh_token",
                &token,
                new_refresh_token.is_some(),
                lifetime.num_seconds(),
            ))
            .await;
            let response = matric_core::TokenResponse {
                access_token,
                token_type: "Bearer".to_string(),
                expires_in: lifetime.num_seconds(),
                refresh_token: new_refresh_token,
                scope: Some(token.scope),
            };
            Ok(Json(response))
        }

        _ => Err(OAuthApiError::OAuth(OAuthError::unsupported_grant_type(
            &oauth_unsupported_grant_type_detail(&req.grant_type),
        ))),
    }
}

/// Token introspection request.
#[derive(Deserialize, utoipa::ToSchema)]
struct IntrospectRequest {
    token: String,
    #[serde(default)]
    #[allow(dead_code)]
    token_type_hint: Option<String>,
}

impl std::fmt::Debug for IntrospectRequest {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("IntrospectRequest")
            .field("token_set", &!self.token.is_empty())
            .field("token_len", &telemetry_text_len(&self.token))
            .field(
                "token_type_hint_class",
                &oauth_token_hint_class(self.token_type_hint.as_deref()),
            )
            .finish()
    }
}

/// OAuth2 token introspection (RFC 7662).
#[utoipa::path(post, path = "/oauth/introspect", tag = "OAuth",
    responses((status = 200, description = "Success")))]
async fn oauth_introspect(
    State(state): State<AppState>,
    headers: HeaderMap,
    Form(req): Form<IntrospectRequest>,
) -> Result<impl IntoResponse, OAuthApiError> {
    // Introspection requires client authentication
    let (client_id, client_secret) =
        parse_client_credentials(&headers, None, None).ok_or_else(|| {
            OAuthApiError::OAuth(OAuthError::invalid_client("Missing client credentials"))
        })?;

    let valid = state
        .db
        .oauth
        .validate_client(&client_id, &client_secret)
        .await?;
    if !valid {
        return Err(OAuthApiError::OAuth(OAuthError::invalid_client(
            "Invalid client credentials",
        )));
    }

    let mut response = state.db.oauth.introspect_token(&req.token).await?;
    response.iss = Some(state.issuer.clone());
    emit_oauth_lifecycle_audit_event(oauth_introspection_audit_event(&client_id, &req, &response))
        .await;

    Ok(Json(response))
}

/// Token revocation request.
#[derive(Deserialize, utoipa::ToSchema)]
struct RevokeRequest {
    token: String,
    #[serde(default)]
    token_type_hint: Option<String>,
}

impl std::fmt::Debug for RevokeRequest {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("RevokeRequest")
            .field("token_set", &!self.token.is_empty())
            .field("token_len", &telemetry_text_len(&self.token))
            .field(
                "token_type_hint_class",
                &oauth_token_hint_class(self.token_type_hint.as_deref()),
            )
            .finish()
    }
}

/// OAuth2 token revocation (RFC 7009).
#[utoipa::path(post, path = "/oauth/revoke", tag = "OAuth",
    responses((status = 200, description = "Success")))]
async fn oauth_revoke(
    State(state): State<AppState>,
    headers: HeaderMap,
    Form(req): Form<RevokeRequest>,
) -> Result<impl IntoResponse, OAuthApiError> {
    // Revocation requires client authentication
    let (client_id, client_secret) =
        parse_client_credentials(&headers, None, None).ok_or_else(|| {
            OAuthApiError::OAuth(OAuthError::invalid_client("Missing client credentials"))
        })?;

    let valid = state
        .db
        .oauth
        .validate_client(&client_id, &client_secret)
        .await?;
    if !valid {
        return Err(OAuthApiError::OAuth(OAuthError::invalid_client(
            "Invalid client credentials",
        )));
    }

    // Revoke the token (always returns 200 per RFC 7009)
    let revoked = state
        .db
        .oauth
        .revoke_token(&req.token, req.token_type_hint.as_deref())
        .await
        .unwrap_or(false);
    emit_oauth_lifecycle_audit_event(oauth_revocation_audit_event(&client_id, &req, revoked)).await;

    Ok(StatusCode::OK)
}

