#[derive(Serialize)]
struct ApiKeyResponse {
    id: Uuid,
    key_prefix_len: usize,
    name_len: usize,
    description_len: Option<usize>,
    scope_len: usize,
    rate_limit_per_minute: Option<i32>,
    rate_limit_per_hour: Option<i32>,
    last_used_at: Option<chrono::DateTime<chrono::Utc>>,
    use_count: i64,
    is_active: bool,
    expires_at: Option<chrono::DateTime<chrono::Utc>>,
    created_at: chrono::DateTime<chrono::Utc>,
}

impl From<matric_core::ApiKey> for ApiKeyResponse {
    fn from(api_key: matric_core::ApiKey) -> Self {
        Self {
            id: api_key.id,
            key_prefix_len: telemetry_text_len(&api_key.key_prefix),
            name_len: telemetry_text_len(&api_key.name),
            description_len: api_key.description.as_deref().map(telemetry_text_len),
            scope_len: telemetry_text_len(&api_key.scope),
            rate_limit_per_minute: api_key.rate_limit_per_minute,
            rate_limit_per_hour: api_key.rate_limit_per_hour,
            last_used_at: api_key.last_used_at,
            use_count: api_key.use_count,
            is_active: api_key.is_active,
            expires_at: api_key.expires_at,
            created_at: api_key.created_at,
        }
    }
}

/// List all API keys (requires admin scope).
#[utoipa::path(get, path = "/api/v1/api-keys", tag = "OAuth",
    responses((status = 200, description = "Success")))]
async fn list_api_keys(State(state): State<AppState>) -> Result<impl IntoResponse, ApiError> {
    let keys = state.db.oauth.list_api_keys().await?;
    let keys: Vec<ApiKeyResponse> = keys.into_iter().map(ApiKeyResponse::from).collect();
    Ok(Json(serde_json::json!({ "api_keys": keys })))
}

/// Create a new API key.
#[utoipa::path(post, path = "/api/v1/api-keys", tag = "OAuth",
    request_body = CreateApiKeyRequest,
    responses((status = 201, description = "Created")))]
async fn create_api_key(
    State(state): State<AppState>,
    Json(req): Json<CreateApiKeyRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let response = state.db.oauth.create_api_key(req).await?;
    Ok((StatusCode::CREATED, Json(response)))
}

/// Revoke an API key.
#[utoipa::path(delete, path = "/api/v1/api-keys/{id}", tag = "OAuth",
    params(("id" = Uuid, Path, description = "API key ID")),
    responses(
        (status = 204, description = "Success"),
        (status = 404, description = "Not found"),
    )
)]
async fn revoke_api_key(
    State(state): State<AppState>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let revoked = state.db.oauth.revoke_api_key(id).await?;
    if revoked {
        Ok(StatusCode::NO_CONTENT)
    } else {
        Err(ApiError::NotFound("API key not found".to_string()))
    }
}

// =============================================================================
// OAUTH ERROR HANDLING
// =============================================================================

/// OAuth-specific API error.
enum OAuthApiError {
    OAuth(OAuthError),
    Database(matric_core::Error),
}

impl fmt::Debug for OAuthApiError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::OAuth(err) => f
                .debug_struct("OAuthApiError::OAuth")
                .field("error_code_len", &telemetry_text_len(&err.error))
                .field(
                    "error_description_len",
                    &err.error_description
                        .as_deref()
                        .map(telemetry_text_len)
                        .unwrap_or(0),
                )
                .field(
                    "error_uri_len",
                    &err.error_uri
                        .as_deref()
                        .map(telemetry_text_len)
                        .unwrap_or(0),
                )
                .finish(),
            Self::Database(err) => f
                .debug_struct("OAuthApiError::Database")
                .field("error_len", &telemetry_text_len(&err.to_string()))
                .finish(),
        }
    }
}

impl From<matric_core::Error> for OAuthApiError {
    fn from(err: matric_core::Error) -> Self {
        OAuthApiError::Database(err)
    }
}

fn oauth_problem_mapping(error: &OAuthError) -> (StatusCode, ProblemType, &'static str) {
    match error.error.as_str() {
        "invalid_client" => (
            StatusCode::UNAUTHORIZED,
            ProblemType::Unauthorized,
            "OAuth client authentication failed.",
        ),
        "unauthorized_client" => (
            StatusCode::FORBIDDEN,
            ProblemType::Forbidden,
            "OAuth client is not authorized for this request.",
        ),
        "server_error" => (
            StatusCode::INTERNAL_SERVER_ERROR,
            ProblemType::Internal,
            "An internal error occurred.",
        ),
        "invalid_grant" => (
            StatusCode::BAD_REQUEST,
            ProblemType::Validation,
            "OAuth grant is invalid or expired.",
        ),
        "unsupported_grant_type" => (
            StatusCode::BAD_REQUEST,
            ProblemType::Validation,
            "OAuth grant type is unsupported.",
        ),
        "unsupported_response_type" => (
            StatusCode::BAD_REQUEST,
            ProblemType::Validation,
            "OAuth response type is unsupported.",
        ),
        "invalid_scope" => (
            StatusCode::BAD_REQUEST,
            ProblemType::Validation,
            "OAuth scope is invalid.",
        ),
        "invalid_request" => (
            StatusCode::BAD_REQUEST,
            ProblemType::Validation,
            "OAuth request is invalid.",
        ),
        _ => (
            StatusCode::BAD_REQUEST,
            ProblemType::Validation,
            "OAuth request failed validation.",
        ),
    }
}

impl IntoResponse for OAuthApiError {
    fn into_response(self) -> axum::response::Response {
        match self {
            OAuthApiError::OAuth(err) => {
                let (status, problem_type, detail) = oauth_problem_mapping(&err);
                if problem_type == ProblemType::Internal {
                    error!(
                        oauth_error_code = "server_error",
                        oauth_error_description_len = err
                            .error_description
                            .as_deref()
                            .map(telemetry_text_len)
                            .unwrap_or(0),
                        detail = API_OAUTH_DIAGNOSTIC_FAILURE_DETAIL,
                        operation = "map_oauth_server_error",
                        "oauth server error mapped to problem response"
                    );
                }
                problem_response(status, problem_type, detail.to_string(), None)
            }
            OAuthApiError::Database(err) => {
                error!(
                    error_len = telemetry_text_len(&err.to_string()),
                    detail = API_OAUTH_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_oauth_database_error",
                    "oauth database error mapped to problem response"
                );
                problem_response(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::Internal,
                    "An internal error occurred.".to_string(),
                    None,
                )
            }
        }
    }
}

// =============================================================================
// AUTHENTICATION MIDDLEWARE
// =============================================================================

use axum::extract::FromRequestParts;
use axum::http::request::Parts;

/// Extractor for authenticated requests.
///
/// This extractor validates Bearer tokens (OAuth access tokens or API keys)
/// and provides the authenticated principal to handlers.
///
/// Usage:
/// ```ignore
/// async fn my_handler(auth: Auth) -> impl IntoResponse {
///     if !auth.principal.has_scope("write") {
///         return Err(ApiError::Forbidden("write scope required"));
///     }
///     // ... handler logic
/// }
/// ```
#[derive(Clone)]
pub struct Auth {
    pub principal: AuthPrincipal,
}

impl fmt::Debug for Auth {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("Auth")
            .field("principal", &self.principal)
            .finish()
    }
}

impl FromRequestParts<AppState> for Auth {
    type Rejection = ApiError;

    async fn from_request_parts(
        parts: &mut Parts,
        _state: &AppState,
    ) -> Result<Self, Self::Rejection> {
        // Read Auth from extensions (injected by auth_middleware).
        // The middleware always runs before handlers and sets Auth for all cases:
        // - Valid token → OAuthClient or ApiKey principal
        // - Invalid token → request rejected before reaching handler
        // - No token + REQUIRE_AUTH=true → request rejected before reaching handler
        // - No token + REQUIRE_AUTH=false → Anonymous principal
        if let Some(auth) = parts.extensions.get::<Auth>() {
            return Ok(auth.clone());
        }

        // Fallback: middleware didn't run (e.g., in tests without middleware layer).
        // Default to Anonymous.
        Ok(Auth {
            principal: AuthPrincipal::Anonymous,
        })
    }
}

/// Extractor that requires authentication.
///
/// Use this for endpoints that must have a valid token.
#[derive(Clone)]
pub struct RequireAuth {
    pub principal: AuthPrincipal,
}

impl fmt::Debug for RequireAuth {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("RequireAuth")
            .field("principal", &self.principal)
            .finish()
    }
}

impl FromRequestParts<AppState> for RequireAuth {
    type Rejection = ApiError;

    async fn from_request_parts(
        parts: &mut Parts,
        state: &AppState,
    ) -> Result<Self, Self::Rejection> {
        let auth = Auth::from_request_parts(parts, state).await?;

        if !auth.principal.is_authenticated() {
            return Err(ApiError::Unauthorized(
                "Authentication required".to_string(),
            ));
        }

        Ok(RequireAuth {
            principal: auth.principal,
        })
    }
}

/// Helper trait for requiring specific scopes in handlers.
impl RequireAuth {
    /// Check if the authenticated principal has the required scope.
    #[allow(dead_code)]
    fn require_scope(&self, scope: &str) -> Result<(), ApiError> {
        if !self.principal.has_scope(scope) {
            return Err(ApiError::Forbidden(format!(
                "Missing required scope: {}",
                scope
            )));
        }
        Ok(())
    }
}

