#[derive(Serialize, Deserialize)]
struct ShardManifest {
    /// Knowledge Shard schema version (SemVer, independent of the producer release).
    version: String,
    /// Named conformance profile.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    profile: Option<String>,
    /// Application identity that created this shard.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    producer: Option<ShardProducer>,
    /// Legacy producer application version. New exports use `producer`.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    matric_version: Option<String>,
    format: String,
    created_at: chrono::DateTime<chrono::Utc>,
    components: Vec<String>,
    counts: ShardCounts,
    checksums: std::collections::HashMap<String, String>,

    /// Minimum matric-memory version required to read this shard
    #[serde(default, skip_serializing_if = "Option::is_none")]
    min_reader_version: Option<String>,

    /// Original schema version if this shard was migrated
    #[serde(default, skip_serializing_if = "Option::is_none")]
    migrated_from: Option<String>,

    /// History of migrations applied to this shard
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    migration_history: Vec<MigrationHistoryEntry>,
}

impl std::fmt::Debug for ShardManifest {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("ShardManifest")
            .field("version_len", &self.version.len())
            .field(
                "profile_len",
                &self.profile.as_ref().map(|value| value.len()),
            )
            .field("producer_set", &self.producer.is_some())
            .field(
                "matric_version_len",
                &self.matric_version.as_ref().map(|value| value.len()),
            )
            .field("format_len", &self.format.len())
            .field("created_at", &self.created_at)
            .field("components_count", &self.components.len())
            .field("counts", &self.counts)
            .field("checksums_count", &self.checksums.len())
            .field(
                "min_reader_version_len",
                &self.min_reader_version.as_ref().map(|value| value.len()),
            )
            .field(
                "migrated_from_len",
                &self.migrated_from.as_ref().map(|value| value.len()),
            )
            .field("migration_history_count", &self.migration_history.len())
            .finish()
    }
}

