fn shard_jsonl_records<'a, T>(
    data: &'a [u8],
    invalid_message: &'static str,
) -> Result<impl Iterator<Item = Result<T, ApiError>> + 'a, ApiError>
where
    T: serde::de::DeserializeOwned + 'a,
{
    let text = std::str::from_utf8(data).map_err(|_| shard_validation_failed(invalid_message))?;
    Ok(text
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(move |line| {
            serde_json::from_str(line).map_err(|_| shard_validation_failed(invalid_message))
        }))
}

fn shard_operation_failed(context: &'static str, error: impl std::fmt::Display) -> ApiError {
    let diagnostic = error.to_string();
    ApiError::OperationFailed {
        operation: "Knowledge shard",
        detail: format!("{context}; error_len={}", diagnostic.len()),
    }
}

fn shard_validation_failed(message: &'static str) -> ApiError {
    ApiError::BadRequest(message.to_string())
}

fn invalid_base64_payload(message: &'static str) -> ApiError {
    ApiError::BadRequest(message.to_string())
}

fn validate_shard_export_record_count(record_count: usize) -> Result<(), ApiError> {
    if record_count > SHARD_MAX_RECORDS_PER_COMPONENT {
        Err(shard_validation_failed(
            "Knowledge shard component exceeds the record count limit.",
        ))
    } else {
        Ok(())
    }
}

fn serialize_shard_export_jsonl<T: Serialize>(
    records: &[T],
    context: &'static str,
) -> Result<Vec<u8>, ApiError> {
    records
        .iter()
        .map(serde_json::to_string)
        .collect::<Result<Vec<_>, _>>()
        .map(|lines| lines.join("\n").into_bytes())
        .map_err(|error| shard_operation_failed(context, error))
}

