#[derive(Clone, Copy)]
struct ShardArchiveLimits {
    max_compressed_bytes: usize,
    max_uncompressed_bytes: usize,
    max_entry_bytes: usize,
    max_manifest_bytes: usize,
    max_entries: usize,
}

impl Default for ShardArchiveLimits {
    fn default() -> Self {
        Self {
            max_compressed_bytes: SHARD_MAX_COMPRESSED_BYTES,
            max_uncompressed_bytes: SHARD_MAX_UNCOMPRESSED_BYTES,
            max_entry_bytes: SHARD_MAX_ENTRY_BYTES,
            max_manifest_bytes: SHARD_MAX_MANIFEST_BYTES,
            max_entries: SHARD_MAX_ENTRIES,
        }
    }
}

impl ShardArchiveLimits {
    fn for_compressed_limit(max_compressed_bytes: usize) -> Self {
        let max_compressed_bytes = max_compressed_bytes.min(SHARD_MAX_COMPRESSED_BYTES);
        Self {
            max_compressed_bytes,
            max_uncompressed_bytes: max_compressed_bytes.saturating_mul(4),
            max_entry_bytes: max_compressed_bytes,
            ..Self::default()
        }
    }
}

fn shard_base64_size_limit(max_compressed_bytes: usize) -> usize {
    max_compressed_bytes.saturating_add(2) / 3 * 4
}

#[derive(Debug)]
enum ShardBase64DecodeError {
    InvalidBase64,
    SizeLimit,
    Io(std::io::Error),
}

fn decode_shard_base64_to_tempfile(
    encoded: &str,
    max_compressed_bytes: usize,
) -> Result<(tempfile::NamedTempFile, usize), ShardBase64DecodeError> {
    use std::io::{Read, Write};

    let mut shard_file = tempfile::NamedTempFile::new().map_err(ShardBase64DecodeError::Io)?;
    let mut decoder = base64::read::DecoderReader::new(
        encoded.as_bytes(),
        &base64::engine::general_purpose::STANDARD,
    );
    let mut decoded_bytes = 0usize;
    let mut buffer = [0_u8; 64 * 1024];

    loop {
        let read = decoder.read(&mut buffer).map_err(|error| {
            if error.kind() == std::io::ErrorKind::InvalidData {
                ShardBase64DecodeError::InvalidBase64
            } else {
                ShardBase64DecodeError::Io(error)
            }
        })?;
        if read == 0 {
            break;
        }

        decoded_bytes = decoded_bytes
            .checked_add(read)
            .ok_or(ShardBase64DecodeError::SizeLimit)?;
        if decoded_bytes > max_compressed_bytes {
            return Err(ShardBase64DecodeError::SizeLimit);
        }
        shard_file
            .write_all(&buffer[..read])
            .map_err(ShardBase64DecodeError::Io)?;
    }

    shard_file.flush().map_err(ShardBase64DecodeError::Io)?;
    Ok((shard_file, decoded_bytes))
}

fn validate_shard_entry_name(name: &str) -> Result<(), String> {
    let bytes = name.as_bytes();
    if name.is_empty()
        || bytes.len() > SHARD_MAX_ENTRY_NAME_BYTES
        || name.starts_with('/')
        || name.contains('\\')
        || bytes.get(1) == Some(&b':')
        || bytes.iter().any(|byte| byte.is_ascii_control())
        || name
            .split('/')
            .any(|segment| segment.is_empty() || segment == "." || segment == "..")
    {
        return Err("Knowledge shard contains an unsafe archive entry path.".to_string());
    }
    Ok(())
}

#[cfg(test)]
fn read_shard_archive(
    shard_bytes: &[u8],
    limits: ShardArchiveLimits,
) -> Result<std::collections::HashMap<String, Vec<u8>>, String> {
    use flate2::read::GzDecoder;
    use std::io::Read;
    use tar::Archive;

    if shard_bytes.len() > limits.max_compressed_bytes {
        return Err("Knowledge shard exceeds the compressed size limit.".to_string());
    }

    let decoder = GzDecoder::new(shard_bytes);
    let mut tar_reader = Archive::new(decoder);
    let mut files = std::collections::HashMap::new();
    let mut total_uncompressed_bytes = 0usize;
    let mut entry_count = 0usize;

    for entry in tar_reader
        .entries()
        .map_err(|_| "Invalid knowledge shard archive.".to_string())?
        .raw(true)
    {
        entry_count = entry_count
            .checked_add(1)
            .ok_or_else(|| "Knowledge shard exceeds the archive entry limit.".to_string())?;
        if entry_count > limits.max_entries {
            return Err("Knowledge shard exceeds the archive entry limit.".to_string());
        }

        let mut entry = entry.map_err(|_| "Invalid knowledge shard entry.".to_string())?;
        if !entry.header().entry_type().is_file() {
            return Err("Knowledge shard contains a non-regular archive entry.".to_string());
        }

        let path_bytes = entry.path_bytes();
        let name = std::str::from_utf8(path_bytes.as_ref())
            .map_err(|_| "Knowledge shard contains an unsafe archive entry path.".to_string())?
            .to_string();
        validate_shard_entry_name(&name)?;
        if files.contains_key(&name) {
            return Err("Knowledge shard contains a duplicate archive entry.".to_string());
        }

        let declared_size = usize::try_from(entry.size())
            .map_err(|_| "Knowledge shard entry exceeds the size limit.".to_string())?;
        let entry_limit = match name.as_str() {
            "manifest.json" => limits.max_manifest_bytes,
            shard_signature::SIGNATURE_ENTRY => shard_signature::MAX_SIGNATURE_ENVELOPE_BYTES,
            _ => limits.max_entry_bytes,
        };
        if declared_size > entry_limit {
            return Err("Knowledge shard entry exceeds the size limit.".to_string());
        }
        total_uncompressed_bytes = total_uncompressed_bytes
            .checked_add(declared_size)
            .ok_or_else(|| "Knowledge shard exceeds the uncompressed size limit.".to_string())?;
        if total_uncompressed_bytes > limits.max_uncompressed_bytes {
            return Err("Knowledge shard exceeds the uncompressed size limit.".to_string());
        }

        let mut contents = Vec::with_capacity(declared_size);
        entry
            .read_to_end(&mut contents)
            .map_err(|_| "Invalid knowledge shard entry contents.".to_string())?;
        if contents.len() != declared_size {
            return Err("Invalid knowledge shard entry contents.".to_string());
        }
        files.insert(name, contents);
    }

    Ok(files)
}

#[derive(Debug)]
struct StreamedShardSidecar {
    path: std::path::PathBuf,
    size_bytes: u64,
}

#[derive(Debug)]
struct StreamedShardArchive {
    files: std::collections::HashMap<String, Vec<u8>>,
    sidecars: std::collections::HashMap<String, StreamedShardSidecar>,
}

fn read_shard_archive_streaming_sidecars_from_reader<R: std::io::Read>(
    shard_reader: R,
    compressed_bytes: usize,
    limits: ShardArchiveLimits,
    sidecar_directory: &std::path::Path,
) -> Result<StreamedShardArchive, String> {
    use flate2::read::GzDecoder;
    use std::io::{Read, Write};
    use tar::Archive;

    if compressed_bytes > limits.max_compressed_bytes {
        return Err("Knowledge shard exceeds the compressed size limit.".to_string());
    }

    let decoder = GzDecoder::new(shard_reader);
    let mut tar_reader = Archive::new(decoder);
    let mut files = std::collections::HashMap::new();
    let mut sidecars = std::collections::HashMap::new();
    let mut entry_names = std::collections::HashSet::new();
    let mut total_uncompressed_bytes = 0usize;
    let mut entry_count = 0usize;

    for entry in tar_reader
        .entries()
        .map_err(|_| "Invalid knowledge shard archive.".to_string())?
        .raw(true)
    {
        entry_count = entry_count
            .checked_add(1)
            .ok_or_else(|| "Knowledge shard exceeds the archive entry limit.".to_string())?;
        if entry_count > limits.max_entries {
            return Err("Knowledge shard exceeds the archive entry limit.".to_string());
        }

        let mut entry = entry.map_err(|_| "Invalid knowledge shard entry.".to_string())?;
        if !entry.header().entry_type().is_file() {
            return Err("Knowledge shard contains a non-regular archive entry.".to_string());
        }

        let path_bytes = entry.path_bytes();
        let name = std::str::from_utf8(path_bytes.as_ref())
            .map_err(|_| "Knowledge shard contains an unsafe archive entry path.".to_string())?
            .to_string();
        validate_shard_entry_name(&name)?;
        if !entry_names.insert(name.clone()) {
            return Err("Knowledge shard contains a duplicate archive entry.".to_string());
        }

        let declared_size = usize::try_from(entry.size())
            .map_err(|_| "Knowledge shard entry exceeds the size limit.".to_string())?;
        let entry_limit = match name.as_str() {
            "manifest.json" => limits.max_manifest_bytes,
            shard_signature::SIGNATURE_ENTRY => shard_signature::MAX_SIGNATURE_ENVELOPE_BYTES,
            _ => limits.max_entry_bytes,
        };
        if declared_size > entry_limit {
            return Err("Knowledge shard entry exceeds the size limit.".to_string());
        }
        total_uncompressed_bytes = total_uncompressed_bytes
            .checked_add(declared_size)
            .ok_or_else(|| "Knowledge shard exceeds the uncompressed size limit.".to_string())?;
        if total_uncompressed_bytes > limits.max_uncompressed_bytes {
            return Err("Knowledge shard exceeds the uncompressed size limit.".to_string());
        }

        let Some(checksum) = shard_blob_entry_checksum(&name) else {
            let mut contents = Vec::with_capacity(declared_size);
            entry
                .read_to_end(&mut contents)
                .map_err(|_| "Invalid knowledge shard entry contents.".to_string())?;
            if contents.len() != declared_size {
                return Err("Invalid knowledge shard entry contents.".to_string());
            }
            files.insert(name, contents);
            continue;
        };

        let digest = checksum
            .strip_prefix("blake3:")
            .expect("canonical shard sidecar checksum");
        let path = sidecar_directory.join(digest);
        let mut destination = std::fs::OpenOptions::new()
            .create_new(true)
            .write(true)
            .open(&path)
            .map_err(|_| "Knowledge shard sidecar staging is unavailable.".to_string())?;
        let mut hasher = blake3::Hasher::new();
        let mut copied = 0usize;
        let mut buffer = [0_u8; 64 * 1024];
        loop {
            let read = entry
                .read(&mut buffer)
                .map_err(|_| "Invalid knowledge shard entry contents.".to_string())?;
            if read == 0 {
                break;
            }
            copied = copied
                .checked_add(read)
                .ok_or_else(|| "Knowledge shard entry exceeds the size limit.".to_string())?;
            if copied > declared_size {
                return Err("Invalid knowledge shard entry contents.".to_string());
            }
            hasher.update(&buffer[..read]);
            destination
                .write_all(&buffer[..read])
                .map_err(|_| "Knowledge shard sidecar staging is unavailable.".to_string())?;
        }
        if copied != declared_size || format!("blake3:{}", hasher.finalize().to_hex()) != checksum {
            return Err(
                "Knowledge shard attachment sidecar failed integrity validation.".to_string(),
            );
        }
        destination
            .sync_all()
            .map_err(|_| "Knowledge shard sidecar staging is unavailable.".to_string())?;
        sidecars.insert(
            checksum,
            StreamedShardSidecar {
                path,
                size_bytes: declared_size as u64,
            },
        );
    }

    Ok(StreamedShardArchive { files, sidecars })
}

#[cfg(test)]
fn read_shard_archive_streaming_sidecars(
    shard_bytes: &[u8],
    limits: ShardArchiveLimits,
    sidecar_directory: &std::path::Path,
) -> Result<StreamedShardArchive, String> {
    read_shard_archive_streaming_sidecars_from_reader(
        shard_bytes,
        shard_bytes.len(),
        limits,
        sidecar_directory,
    )
}

