const ATTACHMENT_REQUEST_OVERHEAD_BYTES: usize = 64 * 1024;

fn attachment_base64_size_limit(max_decoded_bytes: usize) -> usize {
    max_decoded_bytes
        .checked_add(2)
        .and_then(|rounded| rounded.checked_div(3))
        .and_then(|groups| groups.checked_mul(4))
        .unwrap_or(usize::MAX)
}

fn attachment_json_request_limit(max_upload_bytes: usize) -> usize {
    attachment_base64_size_limit(max_upload_bytes).saturating_add(ATTACHMENT_REQUEST_OVERHEAD_BYTES)
}

fn attachment_multipart_request_limit(max_upload_bytes: usize) -> usize {
    max_upload_bytes.saturating_add(ATTACHMENT_REQUEST_OVERHEAD_BYTES)
}

fn decoded_base64_size(encoded: &str) -> Option<usize> {
    if !encoded.len().is_multiple_of(4) {
        return None;
    }
    let padding = encoded
        .as_bytes()
        .iter()
        .rev()
        .take_while(|byte| **byte == b'=')
        .count();
    if padding > 2 {
        return None;
    }
    encoded
        .len()
        .checked_div(4)?
        .checked_mul(3)?
        .checked_sub(padding)
}

fn decode_attachment_data_bounded(
    encoded: &str,
    max_decoded_bytes: usize,
) -> Result<Vec<u8>, ApiError> {
    let decoded_size = decoded_base64_size(encoded)
        .ok_or_else(|| invalid_base64_payload("Invalid base64-encoded attachment data."))?;
    if decoded_size > max_decoded_bytes {
        return Err(attachment_exceeds_max_size());
    }

    let data = base64::engine::general_purpose::STANDARD
        .decode(encoded)
        .map_err(|_| invalid_base64_payload("Invalid base64-encoded attachment data."))?;
    if data.len() > max_decoded_bytes {
        return Err(attachment_exceeds_max_size());
    }
    Ok(data)
}

async fn read_multipart_attachment_bounded(
    mut field: axum::extract::multipart::Field<'_>,
    max_bytes: usize,
) -> Result<Vec<u8>, ApiError> {
    let mut uploaded = Vec::new();
    while let Some(chunk) = field
        .chunk()
        .await
        .map_err(|_| ApiError::BadRequest("Invalid uploaded file data.".to_string()))?
    {
        let next_len = uploaded
            .len()
            .checked_add(chunk.len())
            .ok_or_else(attachment_exceeds_max_size)?;
        if next_len > max_bytes {
            return Err(attachment_exceeds_max_size());
        }
        uploaded.extend_from_slice(&chunk);
    }
    Ok(uploaded)
}

impl fmt::Debug for UploadAttachmentBody {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("UploadAttachmentBody")
            .field("filename_len", &telemetry_text_len(&self.filename))
            .field("content_type_len", &telemetry_text_len(&self.content_type))
            .field("data_len", &telemetry_text_len(&self.data))
            .field("document_type_id_set", &self.document_type_id.is_some())
            .field("media_optimize", &self.media_optimize)
            .field(
                "vision_mode_len",
                &self
                    .vision_mode
                    .as_ref()
                    .map(|value| telemetry_text_len(value)),
            )
            .finish()
    }
}

/// List all attachments for a note
#[utoipa::path(get, path = "/api/v1/notes/{id}/attachments", tag = "Attachments",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 200, description = "Success")))]
async fn list_attachments(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let attachments = file_storage.list_by_note_tx(&mut tx, id).await?;
    drop(tx);
    Ok(Json(attachments))
}

/// Query parameters for the global attachments listing.
#[derive(Deserialize)]
struct ListGlobalAttachmentsQuery {
    /// Page size (default: 50)
    limit: Option<i64>,
    /// Pagination offset (default: 0)
    offset: Option<i64>,
    /// Sort field: created_at, filename, size_bytes, content_type (default: created_at)
    sort_by: Option<String>,
    /// Sort order: asc, desc (default: desc)
    sort_order: Option<String>,
    /// Filter by content type prefix (e.g. "image/", "application/pdf")
    content_type: Option<String>,
    /// Filter by filename substring (case-insensitive)
    filename: Option<String>,
}

impl fmt::Debug for ListGlobalAttachmentsQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ListGlobalAttachmentsQuery")
            .field("limit", &self.limit)
            .field("offset", &self.offset)
            .field(
                "sort_by_len",
                &self.sort_by.as_deref().map(telemetry_text_len),
            )
            .field(
                "sort_order_len",
                &self.sort_order.as_deref().map(telemetry_text_len),
            )
            .field(
                "content_type_len",
                &self.content_type.as_deref().map(telemetry_text_len),
            )
            .field(
                "filename_len",
                &self.filename.as_deref().map(telemetry_text_len),
            )
            .finish()
    }
}

/// List all attachments across all notes with pagination, sorting, and filtering
#[utoipa::path(get, path = "/api/v1/attachments", tag = "Attachments",
    params(
        ("limit" = Option<i64>, Query, description = "Page size (default: 50)"),
        ("offset" = Option<i64>, Query, description = "Pagination offset (default: 0)"),
        ("sort_by" = Option<String>, Query, description = "Sort field: created_at, filename, size_bytes, content_type"),
        ("sort_order" = Option<String>, Query, description = "Sort order: asc, desc"),
        ("content_type" = Option<String>, Query, description = "Filter by content type prefix"),
        ("filename" = Option<String>, Query, description = "Filter by filename substring"),
    ),
    responses((status = 200, description = "Paginated list of attachments")))]
async fn list_all_attachments(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Query(query): Query<ListGlobalAttachmentsQuery>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let limit = query.limit.unwrap_or(50).clamp(0, 200);
    let offset = query.offset.unwrap_or(0).max(0);
    let sort_by = query.sort_by.as_deref().unwrap_or("created_at");
    let sort_order = query.sort_order.as_deref().unwrap_or("desc");

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let (attachments, total) = file_storage
        .list_all_tx(
            &mut tx,
            limit,
            offset,
            sort_by,
            sort_order,
            query.content_type.as_deref(),
            query.filename.as_deref(),
        )
        .await?;
    drop(tx);

    Ok(Json(matric_core::ListGlobalAttachmentsResponse {
        attachments,
        total,
    }))
}

/// Upload a file attachment to a note
#[utoipa::path(post, path = "/api/v1/notes/{id}/attachments", tag = "Attachments",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 201, description = "Created")))]
async fn upload_attachment(
    State(state): State<AppState>,
    auth: Auth,
    headers: HeaderMap,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(att_query): Query<UploadAttachmentQuery>,
    Json(body): Json<UploadAttachmentBody>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let data = decode_attachment_data_bounded(&body.data, state.max_upload_size)?;

    // Validate file safety — block executables and dangerous file types (fixes #241)
    let validation =
        matric_core::validate_file(&body.filename, &data, state.max_upload_size as u64);
    if !validation.allowed {
        emit_attachment_upload_audit_event(attachment_upload_audit_event(
            id,
            None,
            &body.filename,
            &body.content_type,
            data.len(),
            AuditOutcome::Denied,
            "json",
            Some(attachment_validation_reason(&validation)),
            validation.detected_type.as_deref(),
            Some(&archive_ctx.schema),
        ))
        .await;
        return Err(ApiError::BadRequest(
            validation
                .block_reason
                .unwrap_or_else(|| "File blocked by safety policy".to_string()),
        ));
    }

    // Validate MIME content type format (issue #308)
    if !matric_core::is_valid_mime_type(&body.content_type) {
        emit_attachment_upload_audit_event(attachment_upload_audit_event(
            id,
            None,
            &body.filename,
            &body.content_type,
            data.len(),
            AuditOutcome::Denied,
            "json",
            Some("invalid_content_type"),
            None,
            Some(&archive_ctx.schema),
        ))
        .await;
        return Err(invalid_attachment_content_type());
    }

    // Detect actual content type from magic bytes (fixes #253)
    let content_type = matric_core::detect_content_type(&body.filename, &data, &body.content_type);

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;

    // Store the file
    let mut attachment = file_storage
        .store_file_tx(&mut tx, id, &body.filename, &content_type, &data)
        .await?;

    // Phase 1: Determine extraction strategy from MIME type (pure function, no DB)
    let ext = std::path::Path::new(&body.filename)
        .extension()
        .and_then(|e| e.to_str());
    let strategy = ExtractionStrategy::from_mime_and_extension(&content_type, ext);
    file_storage
        .set_extraction_strategy_tx(&mut tx, attachment.id, strategy)
        .await?;
    attachment.extraction_strategy = Some(strategy);

    // Validate the document_type_id exists; reject if invalid (issue #309)
    // Query parameter takes priority over body field (issue #334)
    let effective_doc_type_id = att_query.document_type_id.or(body.document_type_id);
    if let Some(doc_type_id) = effective_doc_type_id {
        if state.db.document_types.get(doc_type_id).await?.is_some() {
            file_storage
                .set_document_type_tx(&mut tx, attachment.id, doc_type_id, None)
                .await?;
            attachment.document_type_id = Some(doc_type_id);
        } else {
            return Err(invalid_attachment_document_type_id());
        }
    }
    // Document type classification happens asynchronously after extraction (Phase 2)
    apply_attachment_scan_policy_tx(&state, &mut tx, &mut attachment, &data).await?;

    tx.commit()
        .await
        .map_err(|e| attachment_media_operation_failed("Attachment upload", "commit upload", e))?;
    record_attachment_storage_usage(
        &state,
        &auth,
        &headers,
        &archive_ctx,
        attachment.id,
        data.len(),
    )
    .await;

    // Emit AttachmentCreated event (Issue #454, scoped via #452)
    state.event_bus.emit_with_context(
        ServerEvent::AttachmentCreated {
            attachment_id: attachment.id,
            note_id: id,
            filename: Some(body.filename.clone()),
        },
        event_context_for(&archive_ctx),
    );
    emit_attachment_upload_audit_event(attachment_upload_audit_event(
        id,
        Some(attachment.id),
        &body.filename,
        &content_type,
        data.len(),
        AuditOutcome::Success,
        "json",
        Some("accepted"),
        validation.detected_type.as_deref(),
        Some(&archive_ctx.schema),
    ))
    .await;

    let vision_mode = body
        .vision_mode
        .as_deref()
        .or(att_query.vision_mode.as_deref());
    let media_optimize = att_query
        .media_optimize
        .or(body.media_optimize)
        .unwrap_or(false);
    if state.attachment_scan_mode == AttachmentScanMode::Required {
        queue_attachment_scan_job(
            &state,
            id,
            attachment.id,
            Some(&archive_ctx.schema),
            attachment_scan_downstream_jobs(
                attachment.id,
                strategy,
                &body.filename,
                &content_type,
                Some(&archive_ctx.schema),
                vision_mode,
                media_optimize,
            ),
        )
        .await?;
    } else {
        queue_extraction_job(
            &state.db,
            id,
            attachment.id,
            strategy,
            &body.filename,
            &content_type,
            &state.event_bus,
            Some(&archive_ctx.schema),
            vision_mode,
        )
        .await;
        queue_exif_extraction_job(
            &state.db,
            id,
            attachment.id,
            &content_type,
            &state.event_bus,
            Some(&archive_ctx.schema),
        )
        .await;
        if media_optimize {
            queue_media_optimize_job(
                &state.db,
                id,
                attachment.id,
                &content_type,
                &state.event_bus,
                Some(&archive_ctx.schema),
            )
            .await;
        }
    }

    Ok(Json(attachment))
}

/// Upload a file attachment via multipart/form-data.
///
/// Expects a multipart form with:
/// - `file`: the file data (required)
/// - `document_type_id`: optional UUID for explicit document type override
#[utoipa::path(post, path = "/api/v1/notes/{id}/attachments/upload", tag = "Attachments",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses((status = 201, description = "Created")))]
async fn upload_attachment_multipart(
    State(state): State<AppState>,
    auth: Auth,
    headers: HeaderMap,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(id): Path<Uuid>,
    Query(att_query): Query<UploadAttachmentQuery>,
    mut multipart: axum::extract::Multipart,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let mut filename: Option<String> = None;
    let mut content_type: Option<String> = None;
    let mut data: Option<Vec<u8>> = None;
    let mut document_type_id: Option<Uuid> = None;
    let mut media_optimize: Option<bool> = None;

    while let Some(field) = multipart
        .next_field()
        .await
        .map_err(|_| ApiError::BadRequest("Invalid multipart upload request.".to_string()))?
    {
        let field_name = field.name().map(|n| n.to_string());
        match field_name.as_deref() {
            Some("file") => {
                filename = field.file_name().map(|n| n.to_string());
                content_type = field.content_type().map(|c| c.to_string());
                data = Some(read_multipart_attachment_bounded(field, state.max_upload_size).await?);
            }
            Some("document_type_id") => {
                let val = field.text().await.map_err(|_| {
                    ApiError::BadRequest("Invalid document_type_id field.".to_string())
                })?;
                document_type_id = val.parse::<Uuid>().ok();
            }
            Some("media_optimize") => {
                let val = field.text().await.map_err(|_| {
                    ApiError::BadRequest("Invalid media_optimize field.".to_string())
                })?;
                media_optimize = Some(val == "true" || val == "1");
            }
            _ => {} // ignore unknown fields
        }
    }

    let filename = filename
        .ok_or_else(|| ApiError::BadRequest("Missing file in multipart form".to_string()))?;
    let content_type = content_type.unwrap_or_else(|| "application/octet-stream".to_string());
    let data = data
        .ok_or_else(|| ApiError::BadRequest("Missing file data in multipart form".to_string()))?;

    // Validate MIME content type format (issue #308)
    if !matric_core::is_valid_mime_type(&content_type) {
        emit_attachment_upload_audit_event(attachment_upload_audit_event(
            id,
            None,
            &filename,
            &content_type,
            data.len(),
            AuditOutcome::Denied,
            "multipart",
            Some("invalid_content_type"),
            None,
            Some(&archive_ctx.schema),
        ))
        .await;
        return Err(invalid_attachment_content_type());
    }

    // Validate file safety — block executables and dangerous file types (fixes #241)
    let validation = matric_core::validate_file(&filename, &data, state.max_upload_size as u64);
    if !validation.allowed {
        emit_attachment_upload_audit_event(attachment_upload_audit_event(
            id,
            None,
            &filename,
            &content_type,
            data.len(),
            AuditOutcome::Denied,
            "multipart",
            Some(attachment_validation_reason(&validation)),
            validation.detected_type.as_deref(),
            Some(&archive_ctx.schema),
        ))
        .await;
        return Err(ApiError::BadRequest(
            validation
                .block_reason
                .unwrap_or_else(|| "File blocked by safety policy".to_string()),
        ));
    }

    // Detect actual content type from magic bytes (fixes #253)
    let content_type = matric_core::detect_content_type(&filename, &data, &content_type);

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;

    // Store the file
    let mut attachment = file_storage
        .store_file_tx(&mut tx, id, &filename, &content_type, &data)
        .await?;

    // Set extraction strategy (propagate errors — swallowing SQL errors aborts the PG transaction)
    let ext = std::path::Path::new(&filename)
        .extension()
        .and_then(|e| e.to_str());
    let strategy = ExtractionStrategy::from_mime_and_extension(&content_type, ext);
    file_storage
        .set_extraction_strategy_tx(&mut tx, attachment.id, strategy)
        .await?;
    attachment.extraction_strategy = Some(strategy);

    // Validate the document_type_id exists; reject if invalid (issue #309)
    // Query parameter takes priority over form field (issue #334)
    let effective_doc_type_id = att_query.document_type_id.or(document_type_id);
    if let Some(doc_type_id) = effective_doc_type_id {
        if state.db.document_types.get(doc_type_id).await?.is_some() {
            file_storage
                .set_document_type_tx(&mut tx, attachment.id, doc_type_id, None)
                .await?;
            attachment.document_type_id = Some(doc_type_id);
        } else {
            return Err(invalid_attachment_document_type_id());
        }
    }
    apply_attachment_scan_policy_tx(&state, &mut tx, &mut attachment, &data).await?;

    tx.commit()
        .await
        .map_err(|e| attachment_media_operation_failed("Attachment upload", "commit upload", e))?;
    record_attachment_storage_usage(
        &state,
        &auth,
        &headers,
        &archive_ctx,
        attachment.id,
        data.len(),
    )
    .await;

    // Emit AttachmentCreated event (Issue #454, scoped via #452)
    state.event_bus.emit_with_context(
        ServerEvent::AttachmentCreated {
            attachment_id: attachment.id,
            note_id: id,
            filename: Some(filename.clone()),
        },
        event_context_for(&archive_ctx),
    );
    emit_attachment_upload_audit_event(attachment_upload_audit_event(
        id,
        Some(attachment.id),
        &filename,
        &content_type,
        data.len(),
        AuditOutcome::Success,
        "multipart",
        Some("accepted"),
        validation.detected_type.as_deref(),
        Some(&archive_ctx.schema),
    ))
    .await;

    let do_media_optimize = att_query.media_optimize.or(media_optimize).unwrap_or(false);
    if state.attachment_scan_mode == AttachmentScanMode::Required {
        queue_attachment_scan_job(
            &state,
            id,
            attachment.id,
            Some(&archive_ctx.schema),
            attachment_scan_downstream_jobs(
                attachment.id,
                strategy,
                &filename,
                &content_type,
                Some(&archive_ctx.schema),
                att_query.vision_mode.as_deref(),
                do_media_optimize,
            ),
        )
        .await?;
    } else {
        queue_extraction_job(
            &state.db,
            id,
            attachment.id,
            strategy,
            &filename,
            &content_type,
            &state.event_bus,
            Some(&archive_ctx.schema),
            att_query.vision_mode.as_deref(),
        )
        .await;
        queue_exif_extraction_job(
            &state.db,
            id,
            attachment.id,
            &content_type,
            &state.event_bus,
            Some(&archive_ctx.schema),
        )
        .await;
        if do_media_optimize {
            queue_media_optimize_job(
                &state.db,
                id,
                attachment.id,
                &content_type,
                &state.event_bus,
                Some(&archive_ctx.schema),
            )
            .await;
        }
    }

    Ok(Json(attachment))
}

async fn record_attachment_storage_usage(
    state: &AppState,
    auth: &Auth,
    headers: &HeaderMap,
    archive_ctx: &ArchiveContext,
    attachment_id: Uuid,
    size_bytes: usize,
) {
    let event = usage_subject_from_auth(Some(auth))
        .and_then(|subject| subject.with_archive(archive_ctx.schema.clone()))
        .and_then(|subject| {
            attachment_storage_usage_event(
                attachment_id,
                Utc::now(),
                subject,
                canonical_usage_request_id(headers).as_deref(),
                size_bytes,
            )
        });

    match event {
        Ok(event) => {
            if let Err(error) = state.usage_meter.record(&event).await {
                warn!(
                    error_len = telemetry_text_len(&error.to_string()),
                    "Best-effort attachment storage usage recording failed"
                );
            }
        }
        Err(error) => {
            warn!(
                error_len = telemetry_text_len(&error.to_string()),
                "Attachment storage usage event construction failed"
            );
        }
    }
}

fn attachment_storage_usage_event(
    attachment_id: Uuid,
    event_time: DateTime<Utc>,
    subject: UsageSubject,
    request_id: Option<&str>,
    size_bytes: usize,
) -> Result<UsageEvent, MeteringError> {
    let dimension = UsageDimension::StorageBytes;
    let correlation = match request_id {
        Some(request_id) => UsageCorrelation::default().with_request_id(request_id)?,
        None => UsageCorrelation::default(),
    };
    let size_bytes = u64::try_from(size_bytes).map_err(|_| MeteringError::InvalidQuantity)?;

    UsageEvent::new(
        format!("attachment:{attachment_id}:stored"),
        event_time,
        subject,
        dimension,
        UsageMeasurement::Measured(UsageQuantity::whole(size_bytes, UsageUnit::Byte)?),
        UsageClass::BillableActual,
        UsageProducer::Api,
        UsageSource::LocalMeasured,
        UsageOutcome::Completed,
    )?
    .with_identity(attachment_id, Utc::now())
    .with_correlation(correlation)?
    .with_attrs(UsageAttributes::default())
}

async fn emit_attachment_upload_audit_event(event: AuditEvent) {
    if let Err(err) = TracingSink.emit(event).await {
        warn!(
            error_len = telemetry_text_len(&err.to_string()),
            detail = API_AUDIT_EMIT_DIAGNOSTIC_FAILURE_DETAIL,
            operation = "emit_attachment_upload_audit_event",
            "failed to emit attachment upload audit event"
        );
    }
}

#[allow(clippy::too_many_arguments)]
fn attachment_upload_audit_event(
    note_id: Uuid,
    attachment_id: Option<Uuid>,
    filename: &str,
    content_type: &str,
    size_bytes: usize,
    outcome: AuditOutcome,
    source_surface: &str,
    reason: Option<&str>,
    detected_type: Option<&str>,
    archive_schema: Option<&str>,
) -> AuditEvent {
    let mut event = AuditEvent::new("attachment", "upload", outcome)
        .with_resource(
            if attachment_id.is_some() {
                "attachment"
            } else {
                "note"
            },
            attachment_id.unwrap_or(note_id).to_string(),
        )
        .with_attr("note_id", note_id.to_string())
        .with_attr("upload_source", source_surface.to_string())
        .with_attr("filename_len", filename.chars().count() as i64)
        .with_attr("extension_present", attachment_extension_present(filename))
        .with_attr("extension_len", attachment_extension_len(filename) as i64)
        .with_attr("content_type_class", content_type_class(content_type))
        .with_attr("size_bytes", size_bytes as i64)
        .with_attr("archive_schema_present", archive_schema.is_some());

    if let Some(schema) = archive_schema {
        event = event.with_attr("archive_schema_len", schema.chars().count() as i64);
    }
    if let Some(reason) = reason {
        event.reason = Some(reason.to_string());
        event = event.with_attr("reason_code", reason.to_string());
    }
    if let Some(detected_type) = detected_type {
        event = event.with_attr(
            "detected_type_class",
            attachment_detected_type_class(detected_type),
        );
    }

    event.source = AuditSource::Api;
    event.visibility = AuditVisibilityClass::SecurityRestricted;
    event.failure_policy = AuditFailurePolicy::BestEffort;
    event.severity = match outcome {
        AuditOutcome::Success => AuditSeverity::Info,
        AuditOutcome::Denied => AuditSeverity::Warn,
        AuditOutcome::Failure | AuditOutcome::Error => AuditSeverity::Error,
        AuditOutcome::Unknown => AuditSeverity::Warn,
    };
    event.sanitized()
}

fn attachment_validation_reason(validation: &matric_core::ValidationResult) -> &'static str {
    match validation.detected_type.as_deref() {
        Some("oversized") => "size_exceeded",
        Some(detected) if detected.starts_with("blocked_extension:") => "blocked_extension",
        Some(detected) if detected.starts_with("executable:") => "executable_detected",
        Some("java_or_macho") => "executable_detected",
        Some(_) => "blocked_by_safety_policy",
        None => "blocked_by_safety_policy",
    }
}

fn attachment_detected_type_class(detected_type: &str) -> &'static str {
    if detected_type == "oversized" {
        "oversized"
    } else if detected_type.starts_with("blocked_extension:") {
        "blocked_extension"
    } else if detected_type.starts_with("executable:") || detected_type == "java_or_macho" {
        "executable"
    } else {
        "other"
    }
}

fn attachment_extension_present(filename: &str) -> bool {
    std::path::Path::new(filename).extension().is_some()
}

fn attachment_extension_len(filename: &str) -> usize {
    std::path::Path::new(filename)
        .extension()
        .and_then(|ext| ext.to_str())
        .map(|ext| ext.chars().count())
        .unwrap_or(0)
}

fn content_type_class(content_type: &str) -> String {
    let top_level = content_type.split('/').next().unwrap_or("unknown").trim();
    if !top_level.is_empty()
        && top_level
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || ch == '-' || ch == '+')
    {
        top_level.to_ascii_lowercase()
    } else {
        "unknown".to_string()
    }
}

/// Get attachment metadata
#[utoipa::path(get, path = "/api/v1/attachments/{attachment_id}", tag = "Attachments",
    params(("attachment_id" = Uuid, Path, description = "Attachment ID")),
    responses((status = 200, description = "Success")))]
async fn get_attachment(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(attachment_id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let attachment = file_storage.get_tx(&mut tx, attachment_id).await?;
    drop(tx);
    Ok(Json(attachment))
}

/// Query parameters for attachment download.
#[derive(Deserialize)]
struct DownloadAttachmentQuery {
    /// Request a pre-generated media variant instead of the original file.
    /// Valid values: `faststart`, `web_compatible`, `audio_only`, `preview_720p`,
    /// `web_audio`, `audio_preview`. Requires media optimization to have run (#506).
    variant: Option<String>,
}

impl fmt::Debug for DownloadAttachmentQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("DownloadAttachmentQuery")
            .field(
                "variant_len",
                &self.variant.as_deref().map(telemetry_text_len),
            )
            .finish()
    }
}

fn attachment_media_operation_failed(
    operation: &'static str,
    context: &'static str,
    error: impl std::fmt::Display,
) -> ApiError {
    let diagnostic = error.to_string();
    ApiError::OperationFailed {
        operation,
        detail: format!("{context}; error_len={}", diagnostic.len()),
    }
}

/// Download a file attachment (returns raw binary with proper content headers).
///
/// Clients can use `curl -o filename URL` to download directly.
/// Use `?variant=faststart` (etc.) to download a pre-generated optimized variant.
#[utoipa::path(get, path = "/api/v1/attachments/{attachment_id}/download", tag = "Attachments",
    params(
        ("attachment_id" = Uuid, Path, description = "Attachment ID"),
        ("variant" = Option<String>, Query, description = "Media variant: faststart, web_compatible, audio_only, preview_720p, web_audio, audio_preview"),
    ),
    responses(
        (status = 200, description = "Full content"),
        (status = 206, description = "Partial content (Range request)"),
        (status = 416, description = "Range not satisfiable"),
    ))]
async fn download_attachment(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(attachment_id): Path<Uuid>,
    Query(query): Query<DownloadAttachmentQuery>,
    req_headers: HeaderMap,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    // Split metadata query from file I/O to release DB connection quickly.
    // This prevents pool contention when serving large files (#504).
    let ctx = state.db.for_schema(&archive_ctx.schema)?;

    // If a variant is requested, resolve the derived attachment ID first (#506).
    let target_id = if let Some(ref variant) = query.variant {
        let mut tx = ctx.begin_tx().await?;
        let row: Option<(Uuid,)> = sqlx::query_as(
            r#"SELECT id FROM attachment
               WHERE extracted_metadata->>'source_attachment_id' = $1::TEXT
                 AND extracted_metadata->>'derivation_type' = $2
               LIMIT 1"#,
        )
        .bind(attachment_id)
        .bind(variant.as_str())
        .fetch_optional(&mut *tx)
        .await
        .map_err(|e| {
            attachment_media_operation_failed("Attachment download", "query media variant", e)
        })?;
        drop(tx);

        row.map(|r| r.0).ok_or_else(attachment_variant_not_found)?
    } else {
        attachment_id
    };

    let mut tx = ctx.begin_tx().await?;
    let info = file_storage
        .get_file_metadata_tx(&mut tx, target_id)
        .await?;
    drop(tx); // Release DB connection before file I/O

    let content_type = info.content_type;
    let filename = attachment_media_download_filename(&info.filename, target_id);
    let total_size = info.size_bytes as usize;

    let ct_header: HeaderValue = content_type
        .parse()
        .unwrap_or_else(|_| HeaderValue::from_static("application/octet-stream"));
    let disposition = if content_type.starts_with("video/")
        || content_type.starts_with("audio/")
        || content_type.starts_with("image/")
        || content_type == "application/pdf"
    {
        "inline"
    } else {
        "attachment"
    };
    let cd_header: HeaderValue = format!("{}; filename=\"{}\"", disposition, filename)
        .parse()
        .unwrap_or_else(|_| HeaderValue::from_static(disposition));

    // Graduated serving strategy (#500):
    // - Small files / inline DB blobs: full-buffer then send
    // - Large filesystem files: stream from disk via ReaderStream
    let use_streaming = matches!(&info.source, FileSource::Filesystem(ref path)
        if info.size_bytes >= matric_core::defaults::MEDIA_STREAM_THRESHOLD_BYTES
            && file_storage.resolve_storage_path(path).is_some()
    );

    if use_streaming {
        // Streaming path for large filesystem files
        let storage_path = match &info.source {
            FileSource::Filesystem(p) => p.clone(),
            _ => unreachable!(),
        };
        let fs_path = file_storage
            .resolve_storage_path(&storage_path)
            .expect("resolve_storage_path checked above");

        // Pre-check existence: if the row references a path that no longer
        // exists on disk, return a structured 404 BlobMissing so clients can
        // distinguish "permanently gone, show recovery UI" from a transient
        // I/O fault (which would still surface as 500 from serve_streaming).
        // See issue #631.
        if !tokio::fs::try_exists(&fs_path).await.unwrap_or(false) {
            warn!(
                attachment_id_present = true,
                expected_path_len = telemetry_text_len(&storage_path),
                detail = API_ATTACHMENT_MEDIA_DIAGNOSTIC_FAILURE_DETAIL,
                operation = "stream_attachment_file_missing_blob",
                "attachment_blob row exists but file is missing on disk (issue #631)"
            );
            return Err(ApiError::BlobMissing {
                attachment_id: target_id,
                expected_path: storage_path,
                storage_backend: "filesystem".to_string(),
            });
        }

        serve_streaming(fs_path, total_size, ct_header, cd_header, &req_headers).await
    } else {
        // Buffered path for small files and inline DB blobs
        let data = match info.source {
            FileSource::Inline(bytes) => bytes,
            FileSource::Filesystem(path) => match file_storage.read_file(&path).await {
                Ok(d) => d,
                Err(e) => {
                    // If the underlying error is a "file not found" the row
                    // is referencing a missing blob — return structured 404
                    // BlobMissing instead of a generic 500. Other I/O errors
                    // (permission, EIO) still surface via the normal error
                    // pathway. See issue #631.
                    let err_str = e.to_string();
                    let looks_missing = err_str.contains("No such file or directory")
                        || err_str.contains("os error 2")
                        || err_str.to_lowercase().contains("not found");
                    if looks_missing {
                        warn!(
                            attachment_id_present = true,
                            expected_path_len = telemetry_text_len(&path),
                            error_len = telemetry_text_len(&err_str),
                            detail = API_ATTACHMENT_MEDIA_DIAGNOSTIC_FAILURE_DETAIL,
                            operation = "read_attachment_file_missing_blob",
                            "attachment_blob row exists but file is missing on disk (issue #631)"
                        );
                        return Err(ApiError::BlobMissing {
                            attachment_id: target_id,
                            expected_path: path,
                            storage_backend: "filesystem".to_string(),
                        });
                    }
                    return Err(attachment_media_operation_failed(
                        "Attachment download",
                        "read attachment file",
                        e,
                    ));
                }
            },
        };
        let actual_size = data.len();
        serve_buffered(data, actual_size, ct_header, cd_header, &req_headers)
    }
}

/// Serve a file by streaming from disk (large files).
async fn serve_streaming(
    fs_path: std::path::PathBuf,
    total_size: usize,
    ct_header: HeaderValue,
    cd_header: HeaderValue,
    req_headers: &HeaderMap,
) -> Result<axum::response::Response, ApiError> {
    use tokio::io::{AsyncReadExt, AsyncSeekExt};
    use tokio_util::io::ReaderStream;

    if let Some(range_val) = req_headers.get(header::RANGE) {
        let range_str = range_val
            .to_str()
            .map_err(|_| ApiError::BadRequest("Invalid Range header".to_string()))?;

        match parse_byte_range(range_str, total_size) {
            Ok((start, end)) => {
                let content_length = end - start + 1;
                let mut file = tokio::fs::File::open(&fs_path).await.map_err(|e| {
                    attachment_media_operation_failed(
                        "Attachment download",
                        "open streaming file",
                        e,
                    )
                })?;
                file.seek(std::io::SeekFrom::Start(start as u64))
                    .await
                    .map_err(|e| {
                        attachment_media_operation_failed(
                            "Attachment download",
                            "seek streaming file",
                            e,
                        )
                    })?;
                let limited = file.take(content_length as u64);
                let stream = ReaderStream::with_capacity(
                    limited,
                    matric_core::defaults::MEDIA_STREAM_BUFFER_BYTES,
                );

                let mut headers = HeaderMap::new();
                headers.insert(header::CONTENT_TYPE, ct_header);
                headers.insert(header::CONTENT_DISPOSITION, cd_header);
                headers.insert(header::ACCEPT_RANGES, HeaderValue::from_static("bytes"));
                headers.insert(
                    header::CONTENT_RANGE,
                    format!("bytes {}-{}/{}", start, end, total_size)
                        .parse()
                        .unwrap(),
                );
                headers.insert(header::CONTENT_LENGTH, HeaderValue::from(content_length));

                let body = axum::body::Body::from_stream(stream);
                Ok((StatusCode::PARTIAL_CONTENT, headers, body).into_response())
            }
            Err(_) => {
                let mut headers = HeaderMap::new();
                headers.insert(
                    header::CONTENT_RANGE,
                    format!("bytes */{}", total_size).parse().unwrap(),
                );
                Ok((StatusCode::RANGE_NOT_SATISFIABLE, headers, Vec::<u8>::new()).into_response())
            }
        }
    } else {
        let file = tokio::fs::File::open(&fs_path).await.map_err(|e| {
            attachment_media_operation_failed("Attachment download", "open streaming file", e)
        })?;
        let stream =
            ReaderStream::with_capacity(file, matric_core::defaults::MEDIA_STREAM_BUFFER_BYTES);

        let mut headers = HeaderMap::new();
        headers.insert(header::CONTENT_TYPE, ct_header);
        headers.insert(header::CONTENT_DISPOSITION, cd_header);
        headers.insert(header::ACCEPT_RANGES, HeaderValue::from_static("bytes"));
        headers.insert(header::CONTENT_LENGTH, HeaderValue::from(total_size));

        let body = axum::body::Body::from_stream(stream);
        Ok((StatusCode::OK, headers, body).into_response())
    }
}

/// Serve a file from a fully-buffered Vec<u8> (small files / inline DB blobs).
fn serve_buffered(
    data: Vec<u8>,
    total_size: usize,
    ct_header: HeaderValue,
    cd_header: HeaderValue,
    req_headers: &HeaderMap,
) -> Result<axum::response::Response, ApiError> {
    if let Some(range_val) = req_headers.get(header::RANGE) {
        let range_str = range_val
            .to_str()
            .map_err(|_| ApiError::BadRequest("Invalid Range header".to_string()))?;

        match parse_byte_range(range_str, total_size) {
            Ok((start, end)) => {
                let content_length = end - start + 1;
                let mut headers = HeaderMap::new();
                headers.insert(header::CONTENT_TYPE, ct_header);
                headers.insert(header::CONTENT_DISPOSITION, cd_header);
                headers.insert(header::ACCEPT_RANGES, HeaderValue::from_static("bytes"));
                headers.insert(
                    header::CONTENT_RANGE,
                    format!("bytes {}-{}/{}", start, end, total_size)
                        .parse()
                        .unwrap(),
                );
                headers.insert(header::CONTENT_LENGTH, HeaderValue::from(content_length));

                Ok((
                    StatusCode::PARTIAL_CONTENT,
                    headers,
                    data[start..=end].to_vec(),
                )
                    .into_response())
            }
            Err(_) => {
                let mut headers = HeaderMap::new();
                headers.insert(
                    header::CONTENT_RANGE,
                    format!("bytes */{}", total_size).parse().unwrap(),
                );
                Ok((StatusCode::RANGE_NOT_SATISFIABLE, headers, Vec::<u8>::new()).into_response())
            }
        }
    } else {
        let mut headers = HeaderMap::new();
        headers.insert(header::CONTENT_TYPE, ct_header);
        headers.insert(header::CONTENT_DISPOSITION, cd_header);
        headers.insert(header::ACCEPT_RANGES, HeaderValue::from_static("bytes"));
        headers.insert(header::CONTENT_LENGTH, HeaderValue::from(total_size));

        Ok((StatusCode::OK, headers, data).into_response())
    }
}

/// Serve transcript segments as subtitle/caption tracks (WebVTT, SRT, or RTTM).
///
/// Query parameters:
/// - `format`: `vtt` (default), `srt`, or `rttm`
#[utoipa::path(get, path = "/api/v1/attachments/{attachment_id}/subtitles", tag = "Attachments",
    params(
        ("attachment_id" = Uuid, Path, description = "Attachment ID"),
        ("format" = Option<String>, Query, description = "Caption format: vtt (default), srt, rttm"),
    ),
    responses(
        (status = 200, description = "Subtitle track", content_type = "text/vtt"),
        (status = 404, description = "Attachment not found or no transcript segments"),
    )
)]
async fn get_attachment_subtitles(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(attachment_id): Path<Uuid>,
    Query(params): Query<std::collections::HashMap<String, String>>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let attachment = file_storage.get_tx(&mut tx, attachment_id).await?;
    drop(tx);

    let metadata = attachment.extracted_metadata.ok_or_else(|| {
        ApiError::NotFound("No extraction metadata for this attachment".to_string())
    })?;

    let segments_json = metadata
        .get("transcript_segments")
        .and_then(|v| v.as_array())
        .ok_or_else(|| {
            ApiError::NotFound("No transcript segments found in extraction metadata".to_string())
        })?;

    let segments: Vec<matric_core::captions::CaptionSegment> = segments_json
        .iter()
        .filter_map(|seg| {
            let start = seg.get("start_secs")?.as_f64()?;
            let end = seg.get("end_secs")?.as_f64()?;
            let text = seg.get("text")?.as_str()?.to_string();
            let speaker = seg
                .get("speaker")
                .and_then(|s| s.as_str())
                .map(|s| s.to_string());
            Some(matric_core::captions::CaptionSegment {
                start_secs: start,
                end_secs: end,
                text,
                speaker,
            })
        })
        .collect();

    if segments.is_empty() {
        return Err(ApiError::NotFound(
            "No valid transcript segments found".to_string(),
        ));
    }

    let format = params.get("format").map(|s| s.as_str()).unwrap_or("vtt");

    let (body, content_type, extension) = match format {
        "srt" => (
            matric_core::captions::render_srt(&segments),
            "application/x-subrip",
            "srt",
        ),
        "rttm" => (
            matric_core::captions::render_rttm(&segments, &attachment.filename),
            "text/plain",
            "rttm",
        ),
        _ => (
            matric_core::captions::render_webvtt(&segments),
            "text/vtt",
            "vtt",
        ),
    };

    let subtitle_filename =
        attachment_subtitle_download_filename(&attachment.filename, attachment_id, extension);

    let mut headers = HeaderMap::new();
    headers.insert(
        header::CONTENT_TYPE,
        HeaderValue::from_str(content_type).unwrap(),
    );
    headers.insert(
        header::CONTENT_DISPOSITION,
        format!("inline; filename=\"{}\"", subtitle_filename)
            .parse()
            .unwrap(),
    );

    Ok((StatusCode::OK, headers, body))
}

fn attachment_media_download_filename(filename: &str, attachment_id: Uuid) -> String {
    format!(
        "attachment_filename_len_{}_{}",
        telemetry_text_len(filename),
        attachment_id
    )
}

fn attachment_subtitle_download_filename(
    filename: &str,
    attachment_id: Uuid,
    extension: &str,
) -> String {
    format!(
        "attachment_filename_len_{}_{}_captions.{}",
        telemetry_text_len(filename),
        attachment_id,
        extension
    )
}

/// Serve the thumbnail for a media attachment.
///
/// Returns the derived thumbnail attachment created during extraction.
/// Sets aggressive cache headers since thumbnails are immutable.
/// Returns 404 if no thumbnail exists (non-video attachment or not yet processed).
#[utoipa::path(get, path = "/api/v1/attachments/{attachment_id}/thumbnail", tag = "Attachments",
    params(
        ("attachment_id" = Uuid, Path, description = "Attachment ID"),
    ),
    responses(
        (status = 200, description = "Thumbnail JPEG"),
        (status = 404, description = "No thumbnail available"),
    )
)]
async fn get_attachment_thumbnail(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(attachment_id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;

    // Find the derived thumbnail attachment for this parent
    let mut tx = ctx.begin_tx().await?;
    let thumb_row: Option<(uuid::Uuid,)> = sqlx::query_as(
        r#"SELECT id FROM attachment
           WHERE extracted_metadata->>'source_attachment_id' = $1::TEXT
             AND extracted_metadata->>'derivation_type' = 'thumbnail'
           LIMIT 1"#,
    )
    .bind(attachment_id)
    .fetch_optional(&mut *tx)
    .await
    .map_err(|e| attachment_media_operation_failed("Attachment thumbnail", "query thumbnail", e))?;
    drop(tx);

    let thumb_id = thumb_row.map(|r| r.0).ok_or_else(|| {
        ApiError::NotFound("No thumbnail available for this attachment".to_string())
    })?;

    // Read thumbnail file data via the storage backend
    let mut tx = ctx.begin_tx().await?;
    let info = file_storage
        .get_file_metadata_tx(&mut tx, thumb_id)
        .await
        .map_err(|_| ApiError::NotFound("Thumbnail data not found".to_string()))?;
    drop(tx);

    let thumb_data = match info.source {
        FileSource::Inline(data) => data,
        FileSource::Filesystem(storage_path) => file_storage
            .read_file(&storage_path)
            .await
            .map_err(|_| ApiError::NotFound("Thumbnail data not readable".to_string()))?,
    };

    let mut headers = HeaderMap::new();
    headers.insert(header::CONTENT_TYPE, HeaderValue::from_static("image/jpeg"));
    headers.insert(
        header::CACHE_CONTROL,
        HeaderValue::from_static("public, max-age=86400, immutable"),
    );

    Ok((StatusCode::OK, headers, thumb_data))
}

/// Serve the thumbnail sprite WebVTT file for scrub bar previews (#525).
///
/// Returns the generated VTT with `#xywh=` media fragment coordinates pointing
/// to the sprite sheet images. Clients use this to render seek bar thumbnails.
#[utoipa::path(get, path = "/api/v1/attachments/{attachment_id}/thumbnails.vtt", tag = "Attachments",
    params(
        ("attachment_id" = Uuid, Path, description = "Parent video attachment ID"),
    ),
    responses(
        (status = 200, description = "WebVTT thumbnail map", content_type = "text/vtt"),
        (status = 404, description = "No sprite thumbnails available"),
    )
)]
async fn get_sprite_vtt(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(attachment_id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;

    // Find the derived thumbnail_vtt attachment
    let mut tx = ctx.begin_tx().await?;
    let vtt_row: Option<(uuid::Uuid,)> = sqlx::query_as(
        r#"SELECT id FROM attachment
           WHERE extracted_metadata->>'source_attachment_id' = $1::TEXT
             AND extracted_metadata->>'derivation_type' = 'thumbnail_vtt'
           LIMIT 1"#,
    )
    .bind(attachment_id)
    .fetch_optional(&mut *tx)
    .await
    .map_err(|e| attachment_media_operation_failed("Attachment sprite", "query sprite VTT", e))?;
    drop(tx);

    let vtt_id = vtt_row.map(|r| r.0).ok_or_else(|| {
        ApiError::NotFound("No thumbnail sprites available for this attachment".to_string())
    })?;

    let mut tx = ctx.begin_tx().await?;
    let info = file_storage
        .get_file_metadata_tx(&mut tx, vtt_id)
        .await
        .map_err(|_| ApiError::NotFound("Sprite VTT data not found".to_string()))?;
    drop(tx);

    let vtt_data = match info.source {
        FileSource::Inline(data) => data,
        FileSource::Filesystem(storage_path) => file_storage
            .read_file(&storage_path)
            .await
            .map_err(|_| ApiError::NotFound("Sprite VTT data not readable".to_string()))?,
    };

    let mut headers = HeaderMap::new();
    headers.insert(
        header::CONTENT_TYPE,
        HeaderValue::from_static("text/vtt; charset=utf-8"),
    );
    headers.insert(
        header::CACHE_CONTROL,
        HeaderValue::from_static("public, max-age=86400"),
    );
    headers.insert(
        header::ACCESS_CONTROL_ALLOW_ORIGIN,
        HeaderValue::from_static("*"),
    );

    Ok((StatusCode::OK, headers, vtt_data))
}

/// Serve a numbered sprite sheet image for thumbnail previews (#525).
///
/// Sprite sheets are 5x5 grids of 160x90 JPEG thumbnails, 1-indexed.
/// Returns 404 if the sprite index doesn't exist.
#[utoipa::path(get, path = "/api/v1/attachments/{attachment_id}/sprites/{sprite_index}", tag = "Attachments",
    params(
        ("attachment_id" = Uuid, Path, description = "Parent video attachment ID"),
        ("sprite_index" = String, Path, description = "Sprite sheet number (1-indexed, e.g. '1.jpg')"),
    ),
    responses(
        (status = 200, description = "Sprite sheet JPEG", content_type = "image/jpeg"),
        (status = 404, description = "Sprite sheet not found"),
    )
)]
async fn get_sprite_sheet(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((attachment_id, sprite_index)): Path<(Uuid, String)>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;

    // Parse sprite index: accept "1.jpg", "1", etc.
    let idx_str = sprite_index
        .strip_suffix(".jpg")
        .or_else(|| sprite_index.strip_suffix(".jpeg"))
        .unwrap_or(&sprite_index);
    let _idx: u32 = idx_str
        .parse()
        .map_err(|_| invalid_attachment_sprite_index())?;

    // Find the sprite sheet by matching filename pattern
    let expected_filename = format!("sprite_{}.jpg", idx_str);
    let mut tx = ctx.begin_tx().await?;
    let sprite_row: Option<(uuid::Uuid,)> = sqlx::query_as(
        r#"SELECT id FROM attachment
           WHERE extracted_metadata->>'source_attachment_id' = $1::TEXT
             AND extracted_metadata->>'derivation_type' = 'thumbnail_sprite'
             AND filename = $2
           LIMIT 1"#,
    )
    .bind(attachment_id)
    .bind(&expected_filename)
    .fetch_optional(&mut *tx)
    .await
    .map_err(|e| attachment_media_operation_failed("Attachment sprite", "query sprite sheet", e))?;
    drop(tx);

    let sprite_id = sprite_row
        .map(|r| r.0)
        .ok_or_else(attachment_sprite_not_found)?;

    let mut tx = ctx.begin_tx().await?;
    let info = file_storage
        .get_file_metadata_tx(&mut tx, sprite_id)
        .await
        .map_err(|_| ApiError::NotFound("Sprite sheet data not found".to_string()))?;
    drop(tx);

    let sprite_data = match info.source {
        FileSource::Inline(data) => data,
        FileSource::Filesystem(storage_path) => file_storage
            .read_file(&storage_path)
            .await
            .map_err(|_| ApiError::NotFound("Sprite sheet data not readable".to_string()))?,
    };

    let mut headers = HeaderMap::new();
    headers.insert(header::CONTENT_TYPE, HeaderValue::from_static("image/jpeg"));
    // Sprites are immutable — aggressive caching
    headers.insert(
        header::CACHE_CONTROL,
        HeaderValue::from_static("public, max-age=31536000, immutable"),
    );

    Ok((StatusCode::OK, headers, sprite_data))
}

/// Parse an HTTP Range header value into (start, end) inclusive byte offsets.
/// Supports: `bytes=start-end`, `bytes=start-`, `bytes=-suffix_length`.
fn parse_byte_range(range: &str, total_size: usize) -> Result<(usize, usize), ()> {
    let range = range.trim();
    let spec = range.strip_prefix("bytes=").ok_or(())?;

    // Only support single range (no multi-range with commas)
    if spec.contains(',') {
        return Err(());
    }

    let spec = spec.trim();
    if let Some(suffix) = spec.strip_prefix('-') {
        // bytes=-N  (last N bytes)
        let n: usize = suffix.trim().parse().map_err(|_| ())?;
        if n == 0 || n > total_size {
            return Err(());
        }
        Ok((total_size - n, total_size - 1))
    } else if let Some(start_str) = spec.strip_suffix('-') {
        // bytes=N-  (from N to end)
        let start: usize = start_str.trim().parse().map_err(|_| ())?;
        if start >= total_size {
            return Err(());
        }
        Ok((start, total_size - 1))
    } else {
        // bytes=N-M
        let parts: Vec<&str> = spec.splitn(2, '-').collect();
        if parts.len() != 2 {
            return Err(());
        }
        let start: usize = parts[0].trim().parse().map_err(|_| ())?;
        let end: usize = parts[1].trim().parse().map_err(|_| ())?;
        if start > end || start >= total_size {
            return Err(());
        }
        // Clamp end to total_size - 1
        let end = end.min(total_size - 1);
        Ok((start, end))
    }
}

/// Delete an attachment
#[utoipa::path(delete, path = "/api/v1/attachments/{attachment_id}", tag = "Attachments",
    params(("attachment_id" = Uuid, Path, description = "Attachment ID")),
    responses((status = 204, description = "No Content")))]
async fn delete_attachment(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(attachment_id): Path<Uuid>,
) -> Result<impl IntoResponse, ApiError> {
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    file_storage.delete_tx(&mut tx, attachment_id).await?;
    tx.commit()
        .await
        .map_err(|e| attachment_media_operation_failed("Attachment delete", "commit delete", e))?;

    // Emit AttachmentDeleted event (Issue #454, scoped via #452)
    state.event_bus.emit_with_context(
        ServerEvent::AttachmentDeleted {
            attachment_id,
            note_id: None,
        },
        event_context_for(&archive_ctx),
    );

    Ok(Json(serde_json::json!({
        "success": true,
        "message": "Attachment deleted successfully"
    })))
}

// =============================================================================
// TUS RESUMABLE UPLOAD HANDLERS (Issue #528)
// =============================================================================

/// Returns the mandatory tus protocol response headers shared by all tus endpoints.
fn tus_headers() -> axum::http::HeaderMap {
    let mut headers = axum::http::HeaderMap::new();
    headers.insert("Tus-Resumable", "1.0.0".parse().unwrap());
    headers.insert("Tus-Version", "1.0.0".parse().unwrap());
    headers.insert(
        "Tus-Extension",
        "creation,termination,expiration".parse().unwrap(),
    );
    headers
}

fn tus_operation_failed(context: &'static str, error: impl std::fmt::Display) -> ApiError {
    let diagnostic = error.to_string();
    ApiError::OperationFailed {
        operation: "TUS upload",
        detail: format!("{context}; error_len={}", diagnostic.len()),
    }
}

async fn read_tus_staging_file_bounded(
    path: &str,
    expected_bytes: i64,
    max_bytes: usize,
) -> Result<Vec<u8>, ApiError> {
    use tokio::io::AsyncReadExt;

    let expected_bytes =
        usize::try_from(expected_bytes).map_err(|_| upload_length_exceeds_max_size())?;
    if expected_bytes > max_bytes {
        return Err(upload_length_exceeds_max_size());
    }

    let file = tokio::fs::File::open(path)
        .await
        .map_err(|error| tus_operation_failed("open staging file for finalization", error))?;
    let metadata_bytes = file
        .metadata()
        .await
        .map_err(|error| tus_operation_failed("read staging file metadata", error))?
        .len();
    let max_bytes_u64 = u64::try_from(max_bytes).unwrap_or(u64::MAX);
    if metadata_bytes > max_bytes_u64 {
        return Err(upload_length_exceeds_max_size());
    }
    if metadata_bytes != u64::try_from(expected_bytes).unwrap_or(u64::MAX) {
        return Err(tus_operation_failed(
            "verify staging file length",
            "staging file length does not match Upload-Length",
        ));
    }

    let mut file = file.take(max_bytes_u64.saturating_add(1));
    let mut data = Vec::with_capacity(expected_bytes);
    file.read_to_end(&mut data)
        .await
        .map_err(|error| tus_operation_failed("read staging file", error))?;
    if data.len() > max_bytes {
        return Err(upload_length_exceeds_max_size());
    }
    if data.len() != expected_bytes {
        return Err(tus_operation_failed(
            "verify staging file length",
            "staging file changed during finalization",
        ));
    }
    Ok(data)
}

/// Query parameters for tus upload creation.
#[derive(Deserialize)]
struct TusCreateQuery {
    document_type_id: Option<Uuid>,
    media_optimize: Option<bool>,
    /// Vision analysis depth: "standard" (scene only) or "full" (scene + characters + setting) (#550)
    vision_mode: Option<String>,
}

impl fmt::Debug for TusCreateQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("TusCreateQuery")
            .field("document_type_id_set", &self.document_type_id.is_some())
            .field("media_optimize", &self.media_optimize)
            .field(
                "vision_mode_len",
                &self.vision_mode.as_deref().map(telemetry_text_len),
            )
            .finish()
    }
}

/// OPTIONS handler: tus capability discovery.
///
/// Advertises supported tus protocol versions, extensions, and the maximum
/// upload size. Clients should call this before initiating an upload to verify
/// server capabilities.
#[utoipa::path(options, path = "/api/v1/notes/{id}/attachments/tus", tag = "Attachments",
    params(("id" = Uuid, Path, description = "Note ID")),
    responses(
        (status = 204, description = "Tus server capabilities (Tus-Resumable, Tus-Version, Tus-Extension, Tus-Max-Size headers)")
    ))]
async fn tus_options(State(state): State<AppState>) -> impl IntoResponse {
    let mut headers = tus_headers();
    headers.insert(
        "Tus-Max-Size",
        state.max_upload_size.to_string().parse().unwrap(),
    );
    (axum::http::StatusCode::NO_CONTENT, headers)
}

/// POST handler: create a new tus upload session.
///
/// Reads `Upload-Length` and `Upload-Metadata` headers to set up a staging
/// file on disk and a tracking row in `tus_upload`. Returns `201 Created`
/// with a `Location` header pointing to the upload URL that clients use for
/// subsequent HEAD/PATCH/DELETE requests.
///
/// The `Upload-Metadata` header follows the tus protocol format: a
/// comma-separated list of `key base64value` pairs. Recognised keys:
/// - `filename` — the original file name
/// - `filetype` or `content_type` — MIME type
#[utoipa::path(post, path = "/api/v1/notes/{id}/attachments/tus", tag = "Attachments",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("document_type_id" = Option<Uuid>, Query, description = "Optional document type ID to associate with the finalized attachment"),
        ("media_optimize" = Option<bool>, Query, description = "Whether to run media optimization after upload completes"),
    ),
    responses(
        (status = 201, description = "Upload session created. Location header contains the upload URL. Tus-Resumable and Upload-Expires headers are set."),
        (status = 400, description = "Bad request (missing or invalid Tus-Resumable header, missing or non-positive Upload-Length, or size exceeds maximum)"),
        (status = 404, description = "Note not found"),
    ))]
async fn tus_create_upload(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path(note_id): Path<Uuid>,
    Query(query): Query<TusCreateQuery>,
    headers: axum::http::HeaderMap,
) -> Result<impl IntoResponse, ApiError> {
    // Validate Tus-Resumable header
    let tus_version = headers
        .get("Tus-Resumable")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if tus_version != "1.0.0" {
        return Err(ApiError::BadRequest(
            "Missing or unsupported Tus-Resumable header (requires 1.0.0)".to_string(),
        ));
    }

    // Parse Upload-Length (required)
    let total_size: i64 = headers
        .get("Upload-Length")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.parse().ok())
        .ok_or_else(|| {
            ApiError::BadRequest("Missing or invalid Upload-Length header".to_string())
        })?;

    if total_size <= 0 {
        return Err(ApiError::BadRequest(
            "Upload-Length must be positive".to_string(),
        ));
    }
    if total_size > state.max_upload_size as i64 {
        return Err(upload_length_exceeds_max_size());
    }

    // Parse Upload-Metadata (optional): comma-separated key<space>base64value pairs
    let mut filename = "upload".to_string();
    let mut content_type = "application/octet-stream".to_string();
    let mut extra_metadata = serde_json::Map::new();
    let mut tus_extra_metadata = TusExtraMetadataTelemetry::default();

    if let Some(meta_header) = headers.get("Upload-Metadata").and_then(|v| v.to_str().ok()) {
        for pair in meta_header.split(',') {
            let pair = pair.trim();
            let mut parts = pair.splitn(2, ' ');
            let key = parts.next().unwrap_or("").trim();
            let b64_val = parts.next().unwrap_or("").trim();
            if key.is_empty() {
                continue;
            }
            let decoded = base64_decode_metadata(b64_val).unwrap_or_default();
            match key {
                "filename" => filename = decoded,
                "content_type" | "filetype" => content_type = decoded,
                other => {
                    tus_extra_metadata.record(other, &decoded);
                }
            }
        }
    }
    tus_extra_metadata.insert_into(&mut extra_metadata);

    // Store query params in metadata for finalization
    if let Some(doc_type_id) = query.document_type_id {
        extra_metadata.insert(
            "document_type_id".to_string(),
            serde_json::Value::String(doc_type_id.to_string()),
        );
    }
    if let Some(media_opt) = query.media_optimize {
        extra_metadata.insert(
            "media_optimize".to_string(),
            serde_json::Value::Bool(media_opt),
        );
    }
    if let Some(ref vm) = query.vision_mode {
        insert_tus_vision_mode_metadata(&mut extra_metadata, vm);
    }

    // Validate note exists
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let note_exists: bool = sqlx::query_scalar("SELECT EXISTS(SELECT 1 FROM note WHERE id = $1)")
        .bind(note_id)
        .fetch_one(&mut *tx)
        .await
        .map_err(|e| tus_operation_failed("verify note exists", e))?;

    if !note_exists {
        return Err(note_not_found());
    }

    // Clean up expired uploads lazily (best-effort, don't fail the request)
    let expired = state.db.tus.cleanup_expired().await.unwrap_or_default();
    for (_, path) in &expired {
        let _ = tokio::fs::remove_file(path).await;
    }
    if !expired.is_empty() {
        tracing::info!("Cleaned up {} expired tus uploads", expired.len());
    }

    // Create staging file
    let upload_id = uuid::Uuid::now_v7();
    let storage_path = format!("{}/{}.part", state.tus_staging_path, upload_id);
    tokio::fs::File::create(&storage_path)
        .await
        .map_err(|e| tus_operation_failed("create staging file", e))?;

    // Calculate expiry (default 24 hours)
    let expiry_hours: i64 = std::env::var("TUS_UPLOAD_EXPIRY_HOURS")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(24);
    let expires_at = chrono::Utc::now() + chrono::Duration::hours(expiry_hours);

    // Insert DB record
    let upload = state
        .db
        .tus
        .create(
            &mut tx,
            note_id,
            &filename,
            &content_type,
            total_size,
            &storage_path,
            expires_at,
            serde_json::Value::Object(extra_metadata),
        )
        .await
        .map_err(|e| tus_operation_failed("create upload record", e))?;

    tx.commit()
        .await
        .map_err(|e| tus_operation_failed("commit upload create", e))?;

    // Build Location header
    let location = format!("/api/v1/notes/{}/attachments/tus/{}", note_id, upload.id);

    let mut resp_headers = tus_headers();
    resp_headers.insert("Location", location.parse().unwrap());
    resp_headers.insert(
        "Upload-Expires",
        expires_at
            .format("%a, %d %b %Y %H:%M:%S GMT")
            .to_string()
            .parse()
            .unwrap(),
    );

    Ok((axum::http::StatusCode::CREATED, resp_headers))
}

/// HEAD handler: return current upload offset for resume.
///
/// Returns the current byte offset via `Upload-Offset`, the total expected
/// size via `Upload-Length`, and the expiry time via `Upload-Expires`.
/// `Cache-Control: no-store` prevents stale offset caching.
#[utoipa::path(head, path = "/api/v1/notes/{id}/attachments/tus/{upload_id}", tag = "Attachments",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("upload_id" = Uuid, Path, description = "Upload session ID"),
    ),
    responses(
        (status = 200, description = "Upload state in headers: Upload-Offset (bytes received), Upload-Length (total bytes), Upload-Expires (RFC 7231 datetime), Cache-Control: no-store"),
        (status = 404, description = "Upload not found or has expired"),
    ))]
async fn tus_head_upload(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((_note_id, upload_id)): Path<(Uuid, Uuid)>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let upload = state
        .db
        .tus
        .get(&mut tx, upload_id)
        .await
        .map_err(|e| tus_operation_failed("load upload state", e))?
        .ok_or_else(upload_not_found)?;
    drop(tx);

    if upload.expires_at < chrono::Utc::now() {
        return Err(ApiError::NotFound("Upload has expired".to_string()));
    }

    let mut headers = tus_headers();
    headers.insert(
        "Upload-Offset",
        upload.current_offset.to_string().parse().unwrap(),
    );
    headers.insert(
        "Upload-Length",
        upload.total_size.to_string().parse().unwrap(),
    );
    headers.insert(
        "Upload-Expires",
        upload
            .expires_at
            .format("%a, %d %b %Y %H:%M:%S GMT")
            .to_string()
            .parse()
            .unwrap(),
    );
    headers.insert("Cache-Control", "no-store".parse().unwrap());

    Ok((axum::http::StatusCode::OK, headers))
}

/// PATCH handler: append a chunk of data at the current offset.
///
/// The request body must be `Content-Type: application/offset+octet-stream`.
/// The `Upload-Offset` header must match the server's current offset exactly.
///
/// When the final chunk completes the upload (`new_offset == total_size`),
/// the staging file is finalized through the standard attachment pipeline
/// (validation, storage, extraction queue) and this endpoint returns `200 OK`
/// with the resulting `TusUpload` record in the JSON body. For intermediate
/// chunks, it returns `204 No Content`.
#[utoipa::path(patch, path = "/api/v1/notes/{id}/attachments/tus/{upload_id}", tag = "Attachments",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("upload_id" = Uuid, Path, description = "Upload session ID"),
    ),
    request_body(content = Vec<u8>, description = "Raw binary chunk (Content-Type: application/offset+octet-stream)", content_type = "application/offset+octet-stream"),
    responses(
        (status = 204, description = "Chunk appended. Upload in progress. Upload-Offset and Upload-Expires headers reflect new state."),
        (status = 200, description = "Final chunk accepted, upload complete and attachment finalized", body = matric_core::TusUpload),
        (status = 400, description = "Bad request (missing Tus-Resumable or Upload-Offset headers, wrong Content-Type, or chunk exceeds total size)"),
        (status = 404, description = "Upload not found or has expired"),
        (status = 409, description = "Upload-Offset mismatch between client and server"),
    ))]
async fn tus_patch_upload(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((note_id, upload_id)): Path<(Uuid, Uuid)>,
    headers: axum::http::HeaderMap,
    body: axum::body::Bytes,
) -> Result<impl IntoResponse, ApiError> {
    // Validate Tus-Resumable
    let tus_version = headers
        .get("Tus-Resumable")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if tus_version != "1.0.0" {
        return Err(ApiError::BadRequest(
            "Missing or unsupported Tus-Resumable header".to_string(),
        ));
    }

    // Validate Content-Type
    let ct = headers
        .get("Content-Type")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if ct != "application/offset+octet-stream" {
        return Err(ApiError::BadRequest(
            "Content-Type must be application/offset+octet-stream".to_string(),
        ));
    }

    // Parse Upload-Offset
    let client_offset: i64 = headers
        .get("Upload-Offset")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.parse().ok())
        .ok_or_else(|| {
            ApiError::BadRequest("Missing or invalid Upload-Offset header".to_string())
        })?;

    // Fetch upload record
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let upload = state
        .db
        .tus
        .get(&mut tx, upload_id)
        .await
        .map_err(|e| tus_operation_failed("load upload state", e))?
        .ok_or_else(upload_not_found)?;

    // Validate not expired
    if upload.expires_at < chrono::Utc::now() {
        let _ = state.db.tus.delete(&mut tx, upload_id).await;
        let _ = tx.commit().await;
        let _ = tokio::fs::remove_file(&upload.storage_path).await;
        return Err(ApiError::NotFound("Upload has expired".to_string()));
    }

    // Validate offset matches server state (tus protocol requirement)
    if client_offset != upload.current_offset {
        drop(tx);
        return Err(upload_offset_mismatch());
    }

    // Validate chunk doesn't exceed total size
    let new_offset = upload.current_offset + body.len() as i64;
    if new_offset > upload.total_size {
        drop(tx);
        return Err(upload_chunk_exceeds_total_size());
    }

    // Append chunk to staging file
    use tokio::io::AsyncWriteExt;
    let mut file = tokio::fs::OpenOptions::new()
        .append(true)
        .open(&upload.storage_path)
        .await
        .map_err(|e| tus_operation_failed("open staging file", e))?;
    file.write_all(&body)
        .await
        .map_err(|e| tus_operation_failed("write upload chunk", e))?;
    drop(file);

    // Update offset in DB
    let updated = state
        .db
        .tus
        .update_offset(&mut tx, upload_id, new_offset)
        .await
        .map_err(|e| tus_operation_failed("update upload offset", e))?;

    // Check if upload is complete
    if new_offset == upload.total_size {
        // Finalization retains a full in-memory buffer for validation and storage, but only
        // after both declared and actual staging sizes have passed the upload cap.
        let file_data = read_tus_staging_file_bounded(
            &upload.storage_path,
            upload.total_size,
            state.max_upload_size,
        )
        .await?;

        // Commit offset update before finalization
        tx.commit()
            .await
            .map_err(|e| tus_operation_failed("commit upload offset", e))?;
        // Remove staging file (pipeline takes ownership of the data)
        let _ = tokio::fs::remove_file(&upload.storage_path).await;

        // Store via standard attachment pipeline
        let file_storage = state
            .db
            .file_storage
            .as_ref()
            .ok_or_else(|| ApiError::BadRequest("File storage not configured".to_string()))?;

        if !matric_core::is_valid_mime_type(&upload.content_type) {
            emit_attachment_upload_audit_event(attachment_upload_audit_event(
                note_id,
                None,
                &upload.filename,
                &upload.content_type,
                file_data.len(),
                AuditOutcome::Denied,
                "tus",
                Some("invalid_content_type"),
                None,
                Some(&archive_ctx.schema),
            ))
            .await;
            return Err(invalid_attachment_content_type());
        }
        let validation =
            matric_core::validate_file(&upload.filename, &file_data, state.max_upload_size as u64);
        if !validation.allowed {
            emit_attachment_upload_audit_event(attachment_upload_audit_event(
                note_id,
                None,
                &upload.filename,
                &upload.content_type,
                file_data.len(),
                AuditOutcome::Denied,
                "tus",
                Some(attachment_validation_reason(&validation)),
                validation.detected_type.as_deref(),
                Some(&archive_ctx.schema),
            ))
            .await;
            return Err(ApiError::BadRequest(
                validation
                    .block_reason
                    .unwrap_or_else(|| "File blocked by safety policy".to_string()),
            ));
        }

        let content_type =
            matric_core::detect_content_type(&upload.filename, &file_data, &upload.content_type);
        let ctx2 = state.db.for_schema(&archive_ctx.schema)?;
        let mut tx2 = ctx2.begin_tx().await?;
        let mut attachment = file_storage
            .store_file_tx(
                &mut tx2,
                note_id,
                &upload.filename,
                &content_type,
                &file_data,
            )
            .await?;

        let ext = std::path::Path::new(&upload.filename)
            .extension()
            .and_then(|e| e.to_str());
        let strategy = ExtractionStrategy::from_mime_and_extension(&content_type, ext);
        file_storage
            .set_extraction_strategy_tx(&mut tx2, attachment.id, strategy)
            .await?;

        // Apply document_type_id from metadata if present
        let doc_type_id = upload
            .metadata
            .get("document_type_id")
            .and_then(|v| v.as_str())
            .and_then(|s| s.parse::<Uuid>().ok());
        if let Some(doc_type_id) = doc_type_id {
            if state.db.document_types.get(doc_type_id).await?.is_some() {
                file_storage
                    .set_document_type_tx(&mut tx2, attachment.id, doc_type_id, None)
                    .await?;
            }
        }
        apply_attachment_scan_policy_tx(&state, &mut tx2, &mut attachment, &file_data).await?;

        tx2.commit()
            .await
            .map_err(|e| tus_operation_failed("commit finalized attachment", e))?;

        // Emit event and queue extraction
        state.event_bus.emit_with_context(
            ServerEvent::AttachmentCreated {
                attachment_id: attachment.id,
                note_id,
                filename: Some(upload.filename.clone()),
            },
            event_context_for(&archive_ctx),
        );
        emit_attachment_upload_audit_event(attachment_upload_audit_event(
            note_id,
            Some(attachment.id),
            &upload.filename,
            &content_type,
            file_data.len(),
            AuditOutcome::Success,
            "tus",
            Some("accepted"),
            validation.detected_type.as_deref(),
            Some(&archive_ctx.schema),
        ))
        .await;

        let media_optimize = upload
            .metadata
            .get("media_optimize")
            .and_then(|v| v.as_bool())
            .unwrap_or(false);

        let tus_vision_mode = upload
            .metadata
            .get("vision_mode")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string());

        if state.attachment_scan_mode == AttachmentScanMode::Required {
            queue_attachment_scan_job(
                &state,
                note_id,
                attachment.id,
                Some(&archive_ctx.schema),
                attachment_scan_downstream_jobs(
                    attachment.id,
                    strategy,
                    &upload.filename,
                    &content_type,
                    Some(&archive_ctx.schema),
                    tus_vision_mode.as_deref(),
                    media_optimize,
                ),
            )
            .await?;
        } else {
            queue_extraction_job(
                &state.db,
                note_id,
                attachment.id,
                strategy,
                &upload.filename,
                &content_type,
                &state.event_bus,
                Some(&archive_ctx.schema),
                tus_vision_mode.as_deref(),
            )
            .await;
            queue_exif_extraction_job(
                &state.db,
                note_id,
                attachment.id,
                &content_type,
                &state.event_bus,
                Some(&archive_ctx.schema),
            )
            .await;
            if media_optimize {
                queue_media_optimize_job(
                    &state.db,
                    note_id,
                    attachment.id,
                    &content_type,
                    &state.event_bus,
                    Some(&archive_ctx.schema),
                )
                .await;
            }
        }

        // Mark TUS record as finalized (keeps it for the client GET window)
        let ctx3 = state.db.for_schema(&archive_ctx.schema)?;
        let mut tx3 = ctx3.begin_tx().await?;
        let _ = state
            .db
            .tus
            .mark_finalized(&mut tx3, upload_id, attachment.id)
            .await;
        let _ = tx3.commit().await;

        // Return 200 with attachment info in body
        let mut resp_headers = tus_headers();
        resp_headers.insert("Upload-Offset", new_offset.to_string().parse().unwrap());
        return Ok((
            axum::http::StatusCode::OK,
            resp_headers,
            axum::Json(attachment),
        )
            .into_response());
    }

    tx.commit()
        .await
        .map_err(|e| tus_operation_failed("commit upload offset", e))?;

    let mut resp_headers = tus_headers();
    resp_headers.insert("Upload-Offset", new_offset.to_string().parse().unwrap());
    resp_headers.insert(
        "Upload-Expires",
        updated
            .expires_at
            .format("%a, %d %b %Y %H:%M:%S GMT")
            .to_string()
            .parse()
            .unwrap(),
    );

    Ok((axum::http::StatusCode::NO_CONTENT, resp_headers).into_response())
}

/// DELETE handler: cancel an incomplete upload.
///
/// Deletes the DB record and removes the staging file from disk.
/// Returns `204 No Content` on success.
#[utoipa::path(delete, path = "/api/v1/notes/{id}/attachments/tus/{upload_id}", tag = "Attachments",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("upload_id" = Uuid, Path, description = "Upload session ID"),
    ),
    responses(
        (status = 204, description = "Upload cancelled and staging file cleaned up"),
        (status = 404, description = "Upload not found"),
    ))]
async fn tus_delete_upload(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((_note_id, upload_id)): Path<(Uuid, Uuid)>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let deleted = state
        .db
        .tus
        .delete(&mut tx, upload_id)
        .await
        .map_err(|e| tus_operation_failed("delete upload record", e))?;

    tx.commit()
        .await
        .map_err(|e| tus_operation_failed("commit upload delete", e))?;

    if let Some(upload) = deleted {
        let _ = tokio::fs::remove_file(&upload.storage_path).await;
    }

    let headers = tus_headers();
    Ok((axum::http::StatusCode::NO_CONTENT, headers))
}

/// GET handler: retrieve the finalized attachment after a completed tus upload.
///
/// After the final PATCH completes, the TUS record is marked as finalized with
/// the created `attachment_id` in its metadata. The client's tus library calls
/// GET on the upload URL to retrieve the attachment JSON.
#[utoipa::path(get, path = "/api/v1/notes/{id}/attachments/tus/{upload_id}", tag = "Attachments",
    params(
        ("id" = Uuid, Path, description = "Note ID"),
        ("upload_id" = Uuid, Path, description = "Upload session ID"),
    ),
    responses(
        (status = 200, description = "Finalized attachment", body = matric_core::Attachment),
        (status = 404, description = "Upload not found or not yet finalized"),
    ))]
async fn tus_get_upload(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
    Path((_note_id, upload_id)): Path<(Uuid, Uuid)>,
) -> Result<impl IntoResponse, ApiError> {
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;
    let upload = state
        .db
        .tus
        .get(&mut tx, upload_id)
        .await
        .map_err(|e| tus_operation_failed("load finalized upload", e))?;
    let _ = tx.commit().await;

    let upload = upload.ok_or_else(upload_not_found)?;

    // Extract attachment_id from finalized metadata
    let attachment_id: Uuid = upload
        .metadata
        .get("attachment_id")
        .and_then(|v| v.as_str())
        .and_then(|s| s.parse().ok())
        .ok_or_else(|| {
            ApiError::NotFound("Upload not yet finalized (no attachment_id)".to_string())
        })?;

    // Fetch the full attachment record
    let file_storage = state
        .db
        .file_storage
        .as_ref()
        .ok_or_else(|| ApiError::Internal("File storage not configured".to_string()))?;

    let mut tx2 = ctx.begin_tx().await?;
    let attachment = file_storage.get_tx(&mut tx2, attachment_id).await?;
    drop(tx2);

    Ok(axum::Json(attachment))
}

/// Decode a base64-encoded tus metadata value.
fn base64_decode_metadata(b64: &str) -> Option<String> {
    use base64::Engine;
    base64::engine::general_purpose::STANDARD
        .decode(b64.trim())
        .ok()
        .and_then(|bytes| String::from_utf8(bytes).ok())
}

#[derive(Default)]
struct TusExtraMetadataTelemetry {
    count: usize,
    key_total_len: usize,
    value_total_len: usize,
    secret_candidate_count: usize,
}

impl TusExtraMetadataTelemetry {
    fn record(&mut self, key: &str, value: &str) {
        self.count += 1;
        self.key_total_len += telemetry_text_len(key);
        self.value_total_len += telemetry_text_len(value);
        if webhook_delivery_text_has_secret_candidate(key)
            || webhook_delivery_text_has_secret_candidate(value)
        {
            self.secret_candidate_count += 1;
        }
    }

    fn insert_into(self, metadata: &mut serde_json::Map<String, serde_json::Value>) {
        if self.count == 0 {
            return;
        }

        metadata.insert(
            "extra_metadata_count".to_string(),
            serde_json::json!(self.count),
        );
        metadata.insert(
            "extra_metadata_key_total_len".to_string(),
            serde_json::json!(self.key_total_len),
        );
        metadata.insert(
            "extra_metadata_value_total_len".to_string(),
            serde_json::json!(self.value_total_len),
        );
        metadata.insert(
            "extra_metadata_secret_candidate_count".to_string(),
            serde_json::json!(self.secret_candidate_count),
        );
    }
}

fn insert_tus_vision_mode_metadata(
    metadata: &mut serde_json::Map<String, serde_json::Value>,
    vision_mode: &str,
) {
    let normalized = vision_mode.trim().to_ascii_lowercase();
    match normalized.as_str() {
        "standard" | "full" => {
            metadata.insert(
                "vision_mode".to_string(),
                serde_json::Value::String(normalized),
            );
        }
        "" => {
            metadata.insert(
                "vision_mode_class".to_string(),
                serde_json::Value::String("empty".to_string()),
            );
            metadata.insert("vision_mode_len".to_string(), serde_json::json!(0));
        }
        _ => {
            metadata.insert(
                "vision_mode_class".to_string(),
                serde_json::Value::String("custom".to_string()),
            );
            metadata.insert(
                "vision_mode_len".to_string(),
                serde_json::json!(telemetry_text_len(vision_mode)),
            );
            metadata.insert(
                "vision_mode_secret_candidate".to_string(),
                serde_json::json!(webhook_delivery_text_has_secret_candidate(vision_mode)),
            );
        }
    }
}

