#[allow(dead_code)]
enum ApiError {
    Database(matric_core::Error),
    Unauthorized(String),
    Forbidden(String),
    NotFound(String),
    Gone(String),
    BadRequest(String),
    Conflict(String),
    Internal(String),
    OperationFailed {
        operation: &'static str,
        detail: String,
    },
    ProviderFailure {
        capability: &'static str,
        detail: String,
    },
    ServiceUnavailable(String),
    /// Attachment row exists in `attachment_blob` but the on-disk file is gone.
    /// Distinct from a generic 500 I/O error so clients can surface the
    /// "permanently lost — show recovery UI" case instead of "transient — retry".
    /// Returned as HTTP 404 with a structured JSON body. See issue #631.
    BlobMissing {
        attachment_id: Uuid,
        expected_path: String,
        storage_backend: String,
    },
}

impl fmt::Debug for ApiError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ApiError::Database(error) => f
                .debug_struct("ApiError::Database")
                .field("error_len", &telemetry_text_len(&error.to_string()))
                .finish(),
            ApiError::Unauthorized(detail) => f
                .debug_struct("ApiError::Unauthorized")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::Forbidden(detail) => f
                .debug_struct("ApiError::Forbidden")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::NotFound(detail) => f
                .debug_struct("ApiError::NotFound")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::Gone(detail) => f
                .debug_struct("ApiError::Gone")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::BadRequest(detail) => f
                .debug_struct("ApiError::BadRequest")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::Conflict(detail) => f
                .debug_struct("ApiError::Conflict")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::Internal(detail) => f
                .debug_struct("ApiError::Internal")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::OperationFailed { operation, detail } => f
                .debug_struct("ApiError::OperationFailed")
                .field("operation", operation)
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::ProviderFailure { capability, detail } => f
                .debug_struct("ApiError::ProviderFailure")
                .field("capability", capability)
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::ServiceUnavailable(detail) => f
                .debug_struct("ApiError::ServiceUnavailable")
                .field("detail_len", &telemetry_text_len(detail))
                .finish(),
            ApiError::BlobMissing {
                attachment_id,
                expected_path,
                storage_backend,
            } => f
                .debug_struct("ApiError::BlobMissing")
                .field("attachment_id_set", &(!attachment_id.is_nil()))
                .field("expected_path_len", &telemetry_text_len(expected_path))
                .field("storage_backend_len", &telemetry_text_len(storage_backend))
                .finish(),
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ProblemType {
    Validation,
    Unauthorized,
    Forbidden,
    NotFound,
    Gone,
    Conflict,
    RateLimit,
    Internal,
    OperationFailed,
    ProviderFailure,
    ServiceUnavailable,
    BlobMissing,
}

impl ProblemType {
    const BASE_URI: &'static str = "https://fortemi.com/problems/";
    const ALL: [ProblemType; 12] = [
        ProblemType::Validation,
        ProblemType::Unauthorized,
        ProblemType::Forbidden,
        ProblemType::NotFound,
        ProblemType::Gone,
        ProblemType::Conflict,
        ProblemType::RateLimit,
        ProblemType::Internal,
        ProblemType::OperationFailed,
        ProblemType::ProviderFailure,
        ProblemType::ServiceUnavailable,
        ProblemType::BlobMissing,
    ];

    fn suffix(self) -> &'static str {
        match self {
            ProblemType::Validation => "validation-error",
            ProblemType::Unauthorized => "unauthorized",
            ProblemType::Forbidden => "forbidden",
            ProblemType::NotFound => "not-found",
            ProblemType::Gone => "gone",
            ProblemType::Conflict => "conflict",
            ProblemType::RateLimit => "rate-limit-exceeded",
            ProblemType::Internal => "internal-error",
            ProblemType::OperationFailed => "operation-failed",
            ProblemType::ProviderFailure => "provider-failure",
            ProblemType::ServiceUnavailable => "service-unavailable",
            ProblemType::BlobMissing => "blob-missing",
        }
    }

    fn type_uri(self) -> String {
        format!("{}{}", Self::BASE_URI, self.suffix())
    }

    fn title(self) -> &'static str {
        match self {
            ProblemType::Validation => "Bad Request",
            ProblemType::Unauthorized => "Unauthorized",
            ProblemType::Forbidden => "Forbidden",
            ProblemType::NotFound => "Not Found",
            ProblemType::Gone => "Gone",
            ProblemType::Conflict => "Conflict",
            ProblemType::RateLimit => "Too Many Requests",
            ProblemType::Internal => "Internal Server Error",
            ProblemType::OperationFailed => "Operation Failed",
            ProblemType::ProviderFailure => "Provider Failure",
            ProblemType::ServiceUnavailable => "Service Unavailable",
            ProblemType::BlobMissing => "Blob Missing",
        }
    }

    fn status(self) -> StatusCode {
        match self {
            ProblemType::Validation => StatusCode::BAD_REQUEST,
            ProblemType::Unauthorized => StatusCode::UNAUTHORIZED,
            ProblemType::Forbidden => StatusCode::FORBIDDEN,
            ProblemType::NotFound | ProblemType::BlobMissing => StatusCode::NOT_FOUND,
            ProblemType::Gone => StatusCode::GONE,
            ProblemType::Conflict => StatusCode::CONFLICT,
            ProblemType::RateLimit => StatusCode::TOO_MANY_REQUESTS,
            ProblemType::Internal | ProblemType::OperationFailed => {
                StatusCode::INTERNAL_SERVER_ERROR
            }
            ProblemType::ProviderFailure => StatusCode::BAD_GATEWAY,
            ProblemType::ServiceUnavailable => StatusCode::SERVICE_UNAVAILABLE,
        }
    }

    fn description(self) -> &'static str {
        match self {
            ProblemType::Validation => {
                "Malformed input, invalid parameters, or unsupported request shape."
            }
            ProblemType::Unauthorized => "Missing, malformed, expired, or invalid credentials.",
            ProblemType::Forbidden => {
                "Authenticated request denied by authorization policy or admin gate."
            }
            ProblemType::NotFound => {
                "Requested resource is not present or not visible to the caller."
            }
            ProblemType::Gone => "Previously valid cursor or token state is no longer usable.",
            ProblemType::Conflict => "Duplicate resource or state conflict.",
            ProblemType::RateLimit => {
                "Rate limit or quota boundary reached; retry guidance is in headers."
            }
            ProblemType::Internal => "Unexpected internal failure.",
            ProblemType::OperationFailed => {
                "Backup, restore, command, or storage operation failed."
            }
            ProblemType::ProviderFailure => "AI, media, or inference provider failed.",
            ProblemType::ServiceUnavailable => "Required service or capacity is unavailable.",
            ProblemType::BlobMissing => {
                "Attachment metadata exists but the backing blob is missing."
            }
        }
    }
}

#[derive(Serialize, utoipa::ToSchema)]
struct ProblemDetails {
    #[serde(rename = "type")]
    type_uri: String,
    title: String,
    status: u16,
    detail: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    instance: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    request_id: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    attachment_id: Option<Uuid>,
}

impl fmt::Debug for ProblemDetails {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ProblemDetails")
            .field("type_uri_len", &telemetry_text_len(&self.type_uri))
            .field("title_len", &telemetry_text_len(&self.title))
            .field("status", &self.status)
            .field("detail_len", &telemetry_text_len(&self.detail))
            .field(
                "instance_len",
                &self.instance.as_deref().map(telemetry_text_len),
            )
            .field(
                "request_id_len",
                &self.request_id.as_deref().map(telemetry_text_len),
            )
            .field("attachment_id_set", &self.attachment_id.is_some())
            .finish()
    }
}

impl ProblemDetails {
    fn new(problem_type: ProblemType, status: StatusCode, detail: String) -> Self {
        Self {
            type_uri: problem_type.type_uri(),
            title: problem_type.title().to_string(),
            status: status.as_u16(),
            detail,
            instance: None,
            request_id: None,
            attachment_id: None,
        }
    }
}

#[derive(Serialize, utoipa::ToSchema)]
struct ProblemTypeCatalogEntry {
    type_uri: String,
    status: u16,
    title: String,
    description: String,
}

impl fmt::Debug for ProblemTypeCatalogEntry {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("ProblemTypeCatalogEntry")
            .field("type_uri_len", &telemetry_text_len(&self.type_uri))
            .field("status", &self.status)
            .field("title_len", &telemetry_text_len(&self.title))
            .field("description_len", &telemetry_text_len(&self.description))
            .finish()
    }
}

fn problem_type_catalog_entries() -> Vec<ProblemTypeCatalogEntry> {
    ProblemType::ALL
        .iter()
        .map(|problem_type| ProblemTypeCatalogEntry {
            type_uri: problem_type.type_uri(),
            status: problem_type.status().as_u16(),
            title: problem_type.title().to_string(),
            description: problem_type.description().to_string(),
        })
        .collect()
}

fn problem_response(
    status: StatusCode,
    problem_type: ProblemType,
    detail: String,
    attachment_id: Option<Uuid>,
) -> axum::response::Response {
    let mut problem = ProblemDetails::new(problem_type, status, detail);
    problem.attachment_id = attachment_id;

    (
        status,
        [(header::CONTENT_TYPE, "application/problem+json")],
        Json(problem),
    )
        .into_response()
}

impl From<matric_core::Error> for ApiError {
    fn from(err: matric_core::Error) -> Self {
        match &err {
            matric_core::Error::NotFound(msg) => ApiError::NotFound(msg.clone()),
            matric_core::Error::InvalidInput(msg) => ApiError::BadRequest(msg.clone()),
            matric_core::Error::Database(sqlx_err) => {
                let msg = sqlx_err.to_string();
                if msg.contains("duplicate key") || msg.contains("unique constraint") {
                    // Provide user-friendly error messages for known constraints
                    let friendly_msg =
                        if msg.contains("idx_unique_pref_label") || msg.contains("pref_label") {
                            "A concept with this prefLabel already exists in the scheme".to_string()
                        } else if msg.contains("valid_notation") || msg.contains("notation") {
                            "A concept with this notation already exists in the scheme".to_string()
                        } else if msg.contains("idx_unique_tag_name") || msg.contains("tag_name") {
                            "A tag with this name already exists".to_string()
                        } else if msg.contains("collection_name_key")
                            || msg.contains("collection") && msg.contains("unique")
                        {
                            "A collection with this name already exists".to_string()
                        } else {
                            // Generic friendly message - never expose raw constraint names
                            "A record with this value already exists".to_string()
                        };
                    return ApiError::Conflict(friendly_msg);
                }
                if msg.contains("Polyhierarchy limit") {
                    return ApiError::BadRequest(msg);
                }
                if msg.contains("foreign key") {
                    // Provide user-friendly messages for FK violations
                    let friendly_msg = if msg.contains("job_queue_note_id_fkey")
                        || msg.contains("job_queue") && msg.contains("note")
                    {
                        "Note not found".to_string()
                    } else if msg.contains("note_tag") {
                        "Referenced note or tag not found".to_string()
                    } else {
                        "Referenced resource not found".to_string()
                    };
                    return ApiError::BadRequest(friendly_msg);
                }
                ApiError::Database(err)
            }
            _ => ApiError::Database(err),
        }
    }
}

impl IntoResponse for ApiError {
    fn into_response(self) -> axum::response::Response {
        let (status, problem_type, detail, attachment_id) = match self {
            ApiError::Database(err) => {
                error!(
                    error_len = telemetry_text_len(&err.to_string()),
                    detail = API_DATABASE_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_api_database_error",
                    "database error mapped to problem response"
                );
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::Internal,
                    "An internal error occurred.".to_string(),
                    None,
                )
            }
            ApiError::Unauthorized(msg) => (
                StatusCode::UNAUTHORIZED,
                ProblemType::Unauthorized,
                msg,
                None,
            ),
            ApiError::Forbidden(msg) => (StatusCode::FORBIDDEN, ProblemType::Forbidden, msg, None),
            ApiError::NotFound(msg) => (StatusCode::NOT_FOUND, ProblemType::NotFound, msg, None),
            ApiError::Gone(msg) => (StatusCode::GONE, ProblemType::Gone, msg, None),
            ApiError::BadRequest(msg) => {
                (StatusCode::BAD_REQUEST, ProblemType::Validation, msg, None)
            }
            ApiError::Conflict(msg) => (StatusCode::CONFLICT, ProblemType::Conflict, msg, None),
            ApiError::Internal(msg) => {
                error!(
                    error_len = telemetry_text_len(&msg),
                    detail = API_INTERNAL_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_api_internal_error",
                    "internal error mapped to problem response"
                );
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::Internal,
                    "An internal error occurred.".to_string(),
                    None,
                )
            }
            ApiError::OperationFailed { operation, detail } => {
                error!(
                    operation,
                    error_len = telemetry_text_len(&detail),
                    detail = API_OPERATION_DIAGNOSTIC_FAILURE_DETAIL,
                    "operation failure mapped to problem response"
                );
                (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    ProblemType::OperationFailed,
                    format!("{operation} failed. Check server logs for diagnostics."),
                    None,
                )
            }
            ApiError::ProviderFailure { capability, detail } => {
                error!(
                    capability,
                    error_len = telemetry_text_len(&detail),
                    detail = API_PROVIDER_DIAGNOSTIC_FAILURE_DETAIL,
                    "provider failure mapped to problem response"
                );
                (
                    StatusCode::BAD_GATEWAY,
                    ProblemType::ProviderFailure,
                    format!("{capability} provider failed. Check server logs for diagnostics."),
                    None,
                )
            }
            ApiError::ServiceUnavailable(msg) => (
                StatusCode::SERVICE_UNAVAILABLE,
                ProblemType::ServiceUnavailable,
                msg,
                None,
            ),
            ApiError::BlobMissing {
                attachment_id,
                expected_path,
                storage_backend,
            } => {
                error!(
                    attachment_id_present = true,
                    expected_path_len = telemetry_text_len(&expected_path),
                    storage_backend_len = telemetry_text_len(&storage_backend),
                    detail = API_BLOB_MISSING_DIAGNOSTIC_FAILURE_DETAIL,
                    operation = "map_attachment_blob_missing",
                    "attachment blob missing"
                );
                (
                    StatusCode::NOT_FOUND,
                    ProblemType::BlobMissing,
                    "Attachment content is no longer available.".to_string(),
                    Some(attachment_id),
                )
            }
        };

        problem_response(status, problem_type, detail, attachment_id)
    }
}

