#[derive(Serialize)]
struct MemoryInfoResponse {
    /// Summary statistics
    summary: MemorySummary,
    /// Embedding set details
    embedding_sets: Vec<EmbeddingSetInfo>,
    /// Storage breakdown
    storage: StorageBreakdown,
    /// Hardware recommendations
    recommendations: HardwareRecommendations,
}

impl fmt::Debug for MemoryInfoResponse {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("MemoryInfoResponse")
            .field("summary", &self.summary)
            .field("embedding_sets_count", &self.embedding_sets.len())
            .field("storage", &self.storage)
            .field("recommendations", &self.recommendations)
            .finish()
    }
}

#[derive(Debug, Serialize)]
struct MemorySummary {
    total_notes: i64,
    total_embeddings: i64,
    total_links: i64,
    total_collections: i64,
    total_tags: i64,
    total_templates: i64,
}

#[derive(Serialize)]
struct EmbeddingSetInfo {
    id: Uuid,
    name: String,
    slug: String,
    description: Option<String>,
    document_count: i32,
    embedding_count: i32,
    /// Embedding dimension (e.g., 768 for nomic-embed-text)
    dimension: i32,
    /// Estimated vector storage in bytes
    vector_storage_bytes: i64,
    vector_storage_human: String,
    /// Model name
    model: Option<String>,
    /// Index status
    index_status: String,
    /// Is this the system default set?
    is_system: bool,
}

impl fmt::Debug for EmbeddingSetInfo {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("EmbeddingSetInfo")
            .field("id_set", &true)
            .field("name_len", &telemetry_text_len(&self.name))
            .field("slug_len", &telemetry_text_len(&self.slug))
            .field(
                "description_len",
                &self
                    .description
                    .as_ref()
                    .map(|value| telemetry_text_len(value)),
            )
            .field("document_count", &self.document_count)
            .field("embedding_count", &self.embedding_count)
            .field("dimension", &self.dimension)
            .field("vector_storage_bytes", &self.vector_storage_bytes)
            .field(
                "vector_storage_human_len",
                &telemetry_text_len(&self.vector_storage_human),
            )
            .field(
                "model_len",
                &self.model.as_ref().map(|value| telemetry_text_len(value)),
            )
            .field("index_status_len", &telemetry_text_len(&self.index_status))
            .field("is_system", &self.is_system)
            .finish()
    }
}

#[derive(Serialize)]
struct StorageBreakdown {
    /// Total database size
    database_total_bytes: i64,
    database_total_human: String,
    /// Embedding table size (actual)
    embedding_table_bytes: i64,
    embedding_table_human: String,
    /// Embedding index size (estimated)
    embedding_index_bytes: i64,
    embedding_index_human: String,
    /// Notes table size
    notes_table_bytes: i64,
    notes_table_human: String,
    /// FTS index size
    fts_index_bytes: i64,
    fts_index_human: String,
    /// Blob storage table size (PostgreSQL relation)
    blob_table_bytes: i64,
    blob_table_human: String,
    /// Total blob content size (aggregate of size_bytes column)
    blob_content_bytes: i64,
    blob_content_human: String,
    /// Number of attachment blobs
    blob_count: i64,
    /// Orphaned blobs (reference_count = 0)
    orphaned_blob_count: i64,
    orphaned_blob_bytes: i64,
    orphaned_blob_human: String,
}

impl fmt::Debug for StorageBreakdown {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("StorageBreakdown")
            .field("database_total_bytes", &self.database_total_bytes)
            .field(
                "database_total_human_len",
                &telemetry_text_len(&self.database_total_human),
            )
            .field("embedding_table_bytes", &self.embedding_table_bytes)
            .field(
                "embedding_table_human_len",
                &telemetry_text_len(&self.embedding_table_human),
            )
            .field("embedding_index_bytes", &self.embedding_index_bytes)
            .field(
                "embedding_index_human_len",
                &telemetry_text_len(&self.embedding_index_human),
            )
            .field("notes_table_bytes", &self.notes_table_bytes)
            .field(
                "notes_table_human_len",
                &telemetry_text_len(&self.notes_table_human),
            )
            .field("fts_index_bytes", &self.fts_index_bytes)
            .field(
                "fts_index_human_len",
                &telemetry_text_len(&self.fts_index_human),
            )
            .field("blob_table_bytes", &self.blob_table_bytes)
            .field(
                "blob_table_human_len",
                &telemetry_text_len(&self.blob_table_human),
            )
            .field("blob_content_bytes", &self.blob_content_bytes)
            .field(
                "blob_content_human_len",
                &telemetry_text_len(&self.blob_content_human),
            )
            .field("blob_count", &self.blob_count)
            .field("orphaned_blob_count", &self.orphaned_blob_count)
            .field("orphaned_blob_bytes", &self.orphaned_blob_bytes)
            .field(
                "orphaned_blob_human_len",
                &telemetry_text_len(&self.orphaned_blob_human),
            )
            .finish()
    }
}

#[derive(Serialize)]
struct HardwareRecommendations {
    /// Minimum RAM for embedding inference
    min_inference_ram_gb: f64,
    /// Recommended RAM for good performance
    recommended_ram_gb: f64,
    /// GPU VRAM needed for embedding model (if using GPU inference)
    gpu_vram_needed_gb: f64,
    /// Whether GPU is required
    gpu_required: bool,
    /// Notes about hardware requirements
    notes: Vec<String>,
}

impl fmt::Debug for HardwareRecommendations {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("HardwareRecommendations")
            .field("min_inference_ram_gb", &self.min_inference_ram_gb)
            .field("recommended_ram_gb", &self.recommended_ram_gb)
            .field("gpu_vram_needed_gb", &self.gpu_vram_needed_gb)
            .field("gpu_required", &self.gpu_required)
            .field("notes_count", &self.notes.len())
            .field(
                "note_lens",
                &self
                    .notes
                    .iter()
                    .map(|value| telemetry_text_len(value))
                    .collect::<Vec<_>>(),
            )
            .finish()
    }
}

/// Get detailed memory/storage info for hardware planning.
/// Respects X-Fortemi-Memory header for archive-scoped info (#421).
#[utoipa::path(get, path = "/api/v1/memory/info", tag = "System",
    responses((status = 200, description = "Success")))]
async fn memory_info(
    State(state): State<AppState>,
    Extension(archive_ctx): Extension<ArchiveContext>,
) -> Result<impl IntoResponse, ApiError> {
    // Schema-scoped transaction for all queries
    let ctx = state.db.for_schema(&archive_ctx.schema)?;
    let mut tx = ctx.begin_tx().await?;

    let notes_repo = matric_db::PgNoteRepository::new(state.db.pool.clone());
    let links_repo = matric_db::PgLinkRepository::new(state.db.pool.clone());
    let collections_repo = matric_db::PgCollectionRepository::new(state.db.pool.clone());
    let tags_repo = matric_db::PgTagRepository::new(state.db.pool.clone());
    let templates_repo = matric_db::PgTemplateRepository::new(state.db.pool.clone());
    let sets_repo = matric_db::PgEmbeddingSetRepository::new(state.db.pool.clone());

    // Get summary counts
    let notes_req = ListNotesRequest {
        limit: Some(1),
        ..Default::default()
    };
    let notes_resp = notes_repo.list_tx(&mut tx, notes_req).await?;

    let link_count = links_repo.count_tx(&mut tx).await.unwrap_or(0);
    let collections = collections_repo
        .list_tx(&mut tx, None)
        .await
        .unwrap_or_default();
    let tags = tags_repo.list_tx(&mut tx).await.unwrap_or_default();
    let templates = templates_repo.list_tx(&mut tx).await.unwrap_or_default();

    // Get embedding set info
    let embedding_sets = sets_repo.list_tx(&mut tx).await.unwrap_or_default();

    tx.commit().await.map_err(matric_db::Error::Database)?;
    let mut set_infos = Vec::new();

    for set in &embedding_sets {
        // Calculate vector storage: embedding_count * dimension * 4 bytes per float
        let vector_bytes = (set.embedding_count as i64) * (set.dimension.unwrap_or(768) as i64) * 4;

        set_infos.push(EmbeddingSetInfo {
            id: set.id,
            name: set.name.clone(),
            slug: set.slug.clone(),
            description: set.description.clone(),
            document_count: set.document_count,
            embedding_count: set.embedding_count,
            dimension: set.dimension.unwrap_or(768),
            vector_storage_bytes: vector_bytes,
            vector_storage_human: format_size(vector_bytes as u64),
            model: set.model.clone(),
            index_status: format!("{:?}", set.index_status),
            is_system: set.is_system,
        });
    }

    // Get storage sizes from database
    let storage = get_storage_breakdown(&state.db).await;

    // Calculate total embedding vector bytes
    let total_vector_bytes: i64 = set_infos.iter().map(|s| s.vector_storage_bytes).sum();

    // Hardware recommendations
    let embedding_model_size_gb = 0.5; // nomic-embed-text is ~500MB
    let recommended_ram_gb = 4.0 + (total_vector_bytes as f64 / 1_073_741_824.0); // 4GB base + vectors
    let min_ram_gb = 2.0 + (total_vector_bytes as f64 / 1_073_741_824.0);

    let total_embeddings: i32 = set_infos.iter().map(|s| s.embedding_count).sum();
    let dimension = set_infos.first().map(|s| s.dimension).unwrap_or(768);

    let recommendations = HardwareRecommendations {
        min_inference_ram_gb: min_ram_gb,
        recommended_ram_gb,
        gpu_vram_needed_gb: embedding_model_size_gb + 1.0, // Model + workspace
        gpu_required: false,                               // Ollama can run on CPU (slower)
        notes: vec![
            // Storage explanation
            format!(
                "Vector storage: {} ({} embeddings × {} dimensions × 4 bytes/float)",
                format_size(total_vector_bytes as u64),
                total_embeddings,
                dimension
            ),
            // GPU role - embedding GENERATION
            "GPU usage: EMBEDDING GENERATION via Ollama (runs the embedding model)".to_string(),
            format!(
                "  └─ With GPU: ~{}MB VRAM for nomic-embed-text + workspace",
                (embedding_model_size_gb * 1024.0) as i64
            ),
            "  └─ Without GPU: Falls back to CPU (functional but slower)".to_string(),
            // CPU role - vector SEARCH
            "CPU usage: VECTOR SEARCH via pgvector (runs in PostgreSQL)".to_string(),
            "  └─ HNSW index traversal and cosine similarity are CPU-bound".to_string(),
            "  └─ More RAM = more vectors cached = faster search performance".to_string(),
            // Practical summary
            "Practical: GPU speeds up creating/updating notes; all searches use CPU/RAM"
                .to_string(),
        ],
    };

    Ok(Json(MemoryInfoResponse {
        summary: MemorySummary {
            total_notes: notes_resp.total,
            total_embeddings: set_infos.iter().map(|s| s.embedding_count as i64).sum(),
            total_links: link_count,
            total_collections: collections.len() as i64,
            total_tags: tags.len() as i64,
            total_templates: templates.len() as i64,
        },
        embedding_sets: set_infos,
        storage,
        recommendations,
    }))
}

/// Get storage breakdown using system commands (avoids sqlx dependency).
async fn get_storage_breakdown(_db: &Database) -> StorageBreakdown {
    // Use psql to query sizes - more reliable and doesn't require sqlx in this crate
    let db_size = get_db_size_via_psql("pg_database_size(current_database())").unwrap_or(0);
    let embedding_size = get_db_size_via_psql("pg_total_relation_size('embedding')").unwrap_or(0);
    let notes_size = get_db_size_via_psql("pg_total_relation_size('note')").unwrap_or(0);
    let fts_size =
        get_db_size_via_psql("pg_total_relation_size('note_revised_current')").unwrap_or(0);

    // Estimate index size as 20% of table size (rough heuristic)
    let embedding_index_size = embedding_size / 5;

    // Blob storage metrics (#531)
    let blob_table_size =
        get_db_size_via_psql("pg_total_relation_size('attachment_blob')").unwrap_or(0);
    let blob_content_bytes =
        get_db_size_via_psql("COALESCE(SUM(size_bytes), 0) FROM attachment_blob").unwrap_or(0);
    let blob_count = get_db_size_via_psql("COUNT(*) FROM attachment_blob").unwrap_or(0);
    let orphaned_blob_count =
        get_db_size_via_psql("COUNT(*) FROM attachment_blob WHERE reference_count = 0")
            .unwrap_or(0);
    let orphaned_blob_bytes = get_db_size_via_psql(
        "COALESCE(SUM(size_bytes), 0) FROM attachment_blob WHERE reference_count = 0",
    )
    .unwrap_or(0);

    StorageBreakdown {
        database_total_bytes: db_size,
        database_total_human: format_size(db_size as u64),
        embedding_table_bytes: embedding_size,
        embedding_table_human: format_size(embedding_size as u64),
        embedding_index_bytes: embedding_index_size,
        embedding_index_human: format_size(embedding_index_size as u64),
        notes_table_bytes: notes_size,
        notes_table_human: format_size(notes_size as u64),
        fts_index_bytes: fts_size,
        fts_index_human: format_size(fts_size as u64),
        blob_table_bytes: blob_table_size,
        blob_table_human: format_size(blob_table_size as u64),
        blob_content_bytes,
        blob_content_human: format_size(blob_content_bytes as u64),
        blob_count,
        orphaned_blob_count,
        orphaned_blob_bytes,
        orphaned_blob_human: format_size(orphaned_blob_bytes as u64),
    }
}

/// Get database size using psql command.
fn get_db_size_via_psql(expr: &str) -> Option<i64> {
    let pg = backup_pg_connection("Database size").ok()?;
    let query = format!("SELECT {}", expr);
    let mut command = std::process::Command::new("psql");
    command.args([
        "-U",
        pg.user.as_str(),
        "-h",
        pg.host.as_str(),
        "-d",
        pg.database.as_str(),
        "-t", // Tuples only (no header)
        "-A", // Unaligned output
        "-c",
        query.as_str(),
    ]);
    apply_backup_pg_env(&mut command, &pg);
    let output = command.output().ok()?;

    if output.status.success() {
        String::from_utf8_lossy(&output.stdout)
            .trim()
            .parse::<i64>()
            .ok()
    } else {
        None
    }
}

