    fn test_shard_archive_with_raw_name(name: &[u8]) -> Vec<u8> {
        let encoder = flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::default());
        let mut archive = tar::Builder::new(encoder);
        let mut header = tar::Header::new_gnu();
        header.set_entry_type(tar::EntryType::Regular);
        header.set_size(0);
        header.set_mode(0o644);
        header.as_mut_bytes()[..100].fill(0);
        header.as_mut_bytes()[..name.len()].copy_from_slice(name);
        header.set_cksum();
        archive.append(&header, std::io::empty()).unwrap();
        archive.into_inner().unwrap().finish().unwrap()
    }

    fn replace_shard_entry(shard: &[u8], target: &str, replacement: &[u8]) -> Vec<u8> {
        use std::io::Read;

        let decoder = flate2::read::GzDecoder::new(shard);
        let mut source = tar::Archive::new(decoder);
        let mut entries = Vec::new();
        for entry in source.entries().unwrap() {
            let mut entry = entry.unwrap();
            let name = entry.path().unwrap().to_string_lossy().to_string();
            let mut bytes = Vec::new();
            entry.read_to_end(&mut bytes).unwrap();
            if name == target {
                bytes = replacement.to_vec();
            }
            entries.push((name, bytes));
        }

        let encoder = flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::default());
        let mut archive = tar::Builder::new(encoder);
        for (name, bytes) in entries {
            let mut header = tar::Header::new_gnu();
            header.set_size(bytes.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            archive
                .append_data(&mut header, name, bytes.as_slice())
                .unwrap();
        }
        archive.into_inner().unwrap().finish().unwrap()
    }

    fn append_shard_entry(shard: &[u8], name: &str, contents: &[u8]) -> Vec<u8> {
        use std::io::Read;

        let decoder = flate2::read::GzDecoder::new(shard);
        let mut source = tar::Archive::new(decoder);
        let encoder = flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::default());
        let mut archive = tar::Builder::new(encoder);
        for entry in source.entries().unwrap() {
            let mut entry = entry.unwrap();
            let entry_name = entry.path().unwrap().to_string_lossy().to_string();
            let mut bytes = Vec::new();
            entry.read_to_end(&mut bytes).unwrap();
            let mut header = tar::Header::new_gnu();
            header.set_size(bytes.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            archive
                .append_data(&mut header, entry_name, bytes.as_slice())
                .unwrap();
        }
        let mut header = tar::Header::new_gnu();
        header.set_size(contents.len() as u64);
        header.set_mode(0o644);
        header.set_cksum();
        archive.append_data(&mut header, name, contents).unwrap();
        archive.into_inner().unwrap().finish().unwrap()
    }

    fn regular_file_count(root: &std::path::Path) -> usize {
        let Ok(entries) = std::fs::read_dir(root) else {
            return 0;
        };
        entries
            .filter_map(Result::ok)
            .map(|entry| {
                let path = entry.path();
                if path.is_dir() {
                    regular_file_count(&path)
                } else {
                    usize::from(path.is_file())
                }
            })
            .sum()
    }

    #[test]
    fn shard_base64_decoder_spools_exact_bytes_and_enforces_decoded_limit() {
        use base64::Engine as _;

        let payload = vec![0x5a; 128 * 1024 + 17];
        let encoded = base64::engine::general_purpose::STANDARD.encode(&payload);
        let (shard_file, decoded_bytes) = decode_shard_base64_to_tempfile(&encoded, payload.len())
            .expect("decode shard to temporary file");

        assert_eq!(decoded_bytes, payload.len());
        assert_eq!(
            std::fs::read(shard_file.path()).expect("read decoded shard file"),
            payload
        );

        let rounding_edge = base64::engine::general_purpose::STANDARD.encode([1_u8, 2, 3]);
        assert_eq!(rounding_edge.len(), shard_base64_size_limit(1));
        assert!(matches!(
            decode_shard_base64_to_tempfile(&rounding_edge, 1),
            Err(ShardBase64DecodeError::SizeLimit)
        ));
    }

    #[test]
    fn shard_base64_decoder_rejects_invalid_input() {
        assert!(matches!(
            decode_shard_base64_to_tempfile("H4sIAAAAAAAA!", SHARD_MAX_COMPRESSED_BYTES),
            Err(ShardBase64DecodeError::InvalidBase64)
        ));
    }

