    #[test]
    fn full_v1_candidate_embedding_schemas_validate_pinned_corpus() {
        for (component, data) in [
            (
                "embedding_configs",
                include_bytes!(
                    "../../../tests/fixtures/shards/full-v1-embedding-candidate/embedding_configs.json"
                )
                .as_slice(),
            ),
            (
                "embedding_sets",
                include_bytes!(
                    "../../../tests/fixtures/shards/full-v1-embedding-candidate/embedding_sets.json"
                )
                .as_slice(),
            ),
            (
                "embedding_set_members",
                include_bytes!(
                    "../../../tests/fixtures/shards/full-v1-embedding-candidate/embedding_set_members.jsonl"
                )
                .as_slice(),
            ),
            (
                "embeddings",
                include_bytes!(
                    "../../../tests/fixtures/shards/full-v1-embedding-candidate/embeddings.jsonl"
                )
                .as_slice(),
            ),
        ] {
            assert_eq!(
                validate_shard_component_schema_for_profile(
                    matric_core::shard::CURRENT_SHARD_VERSION,
                    "full-v1",
                    component,
                    data,
                )
                .unwrap(),
                1,
                "candidate component must validate: {component}"
            );
        }

        let current: serde_json::Value = serde_json::from_slice(include_bytes!(
            "../../../tests/fixtures/shards/full-v1-embedding-candidate/embeddings.jsonl"
        ))
        .unwrap();
        assert_eq!(
            current["contract_fingerprint"],
            "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa"
        );

        for malformed in ["A".repeat(64), "a".repeat(63), "g".repeat(64)] {
            let mut invalid = current.clone();
            invalid["contract_fingerprint"] = serde_json::Value::String(malformed);
            assert!(validate_shard_component_schema_for_profile(
                matric_core::shard::CURRENT_SHARD_VERSION,
                "full-v1",
                "embeddings",
                &serde_json::to_vec(&invalid).unwrap(),
            )
            .is_err());
        }

        let mut legacy = current;
        legacy
            .as_object_mut()
            .unwrap()
            .remove("contract_fingerprint");
        assert!(validate_shard_component_schema_for_profile(
            "1.1.0",
            "full-v1",
            "embeddings",
            &serde_json::to_vec(&legacy).unwrap(),
        )
        .is_ok());
    }

