    #[test]
    fn full_v1_candidate_embedding_schemas_cover_persisted_statuses_and_reject_invalid_records() {
        let mut configs: serde_json::Value = serde_json::from_slice(include_bytes!(
            "../../../tests/fixtures/shards/full-v1-embedding-candidate/embedding_configs.json"
        ))
        .unwrap();
        configs[0]
            .as_object_mut()
            .expect("candidate config must be an object")
            .remove("dimension");
        assert_eq!(
            validate_shard_component_schema_for_profile(
                matric_core::shard::CURRENT_SHARD_VERSION,
                "full-v1",
                "embedding_configs",
                &serde_json::to_vec(&configs).unwrap(),
            )
            .unwrap_err(),
            "Knowledge shard component does not match canonical full-v1 candidate schema."
        );

        let mut sets: serde_json::Value = serde_json::from_slice(include_bytes!(
            "../../../tests/fixtures/shards/full-v1-embedding-candidate/embedding_sets.json"
        ))
        .unwrap();
        sets[0]["index_status"] = serde_json::json!("empty");
        assert_eq!(
            validate_shard_component_schema_for_profile(
                matric_core::shard::CURRENT_SHARD_VERSION,
                "full-v1",
                "embedding_sets",
                &serde_json::to_vec(&sets).unwrap(),
            )
            .unwrap(),
            1
        );
        sets[0]["mode"] = serde_json::json!("future");
        assert_eq!(
            validate_shard_component_schema_for_profile(
                matric_core::shard::CURRENT_SHARD_VERSION,
                "full-v1",
                "embedding_sets",
                &serde_json::to_vec(&sets).unwrap(),
            )
            .unwrap_err(),
            "Knowledge shard component does not match canonical full-v1 candidate schema."
        );

        let mut embedding: serde_json::Value = serde_json::from_slice(include_bytes!(
            "../../../tests/fixtures/shards/full-v1-embedding-candidate/embeddings.jsonl"
        ))
        .unwrap();
        embedding["vector"] = serde_json::json!([0.25, -0.5, 1.0]);
        assert_eq!(
            validate_shard_component_schema_for_profile(
                matric_core::shard::CURRENT_SHARD_VERSION,
                "full-v1",
                "embeddings",
                &serde_json::to_vec(&embedding).unwrap(),
            )
            .unwrap_err(),
            "Knowledge shard component does not match canonical full-v1 candidate schema."
        );
    }

    #[test]
    fn full_v1_candidate_manifest_requires_complete_inventory() {
        let fixture = include_bytes!(
            "../../../tests/fixtures/shards/full-v1-manifest-candidate/manifest.json"
        );
        let manifest = parse_and_validate_shard_manifest(fixture)
            .expect("complete full-v1 candidate manifest must match its published schema");
        assert_eq!(manifest.profile.as_deref(), Some("full-v1"));
        assert_eq!(manifest.components.len(), 33);
        assert_eq!(manifest.checksums.len(), 33);
        assert_eq!(manifest.counts.community_sets, 1);
        assert_eq!(manifest.counts.communities, 1);
        validate_shard_manifest_contract(&manifest)
            .expect("complete full-v1 manifest must be supported");
        assert_eq!(
            validate_shard_component_schema_for_profile(
                "1.1.0",
                "full-v1",
                "notes",
                include_bytes!("../../../tests/fixtures/shards/core-v1-v1.2-valid/notes.jsonl"),
            )
            .unwrap(),
            1
        );

        let candidate: serde_json::Value = serde_json::from_slice(fixture).unwrap();
        for invalid in [
            {
                let mut value = candidate.clone();
                value["components"].as_array_mut().unwrap().pop();
                value
            },
            {
                let mut value = candidate.clone();
                value["counts"]
                    .as_object_mut()
                    .unwrap()
                    .remove("communities");
                value
            },
            {
                let mut value = candidate.clone();
                value["checksums"]
                    .as_object_mut()
                    .unwrap()
                    .remove("communities.json");
                value
            },
        ] {
            assert_eq!(
                parse_and_validate_shard_manifest(&serde_json::to_vec(&invalid).unwrap())
                    .unwrap_err(),
                "Knowledge shard manifest does not match published full-v1 candidate schema."
            );
        }
    }

