    #[test]
    fn full_v1_integrated_candidate_archive_round_trips_semantics_and_required_bytes() {
        use sha2::Digest;

        fn assert_typed_jsonl_round_trip<T>(data: &[u8])
        where
            T: serde::de::DeserializeOwned + serde::Serialize,
        {
            for line in std::str::from_utf8(data).unwrap().lines() {
                let expected: serde_json::Value = serde_json::from_str(line).unwrap();
                let typed: T = serde_json::from_value(expected.clone()).unwrap();
                assert_eq!(serde_json::to_value(typed).unwrap(), expected);
            }
        }

        let archive =
            include_bytes!("../../../tests/fixtures/shards/full-v1-integrated-candidate.shard");
        let receipt: serde_json::Value = serde_json::from_slice(include_bytes!(
            "../../../tests/fixtures/shards/full-v1-integrated-candidate.shard.receipt.json"
        ))
        .unwrap();
        assert_eq!(
            hex::encode(sha2::Sha256::digest(archive)),
            receipt["archiveSha256"].as_str().unwrap()
        );

        let files = read_shard_archive(archive, ShardArchiveLimits::default())
            .expect("integrated candidate archive must pass bounded archive preflight");
        assert_eq!(
            hex::encode(sha2::Sha256::digest(&files["manifest.json"])),
            receipt["manifestSha256"].as_str().unwrap()
        );
        let manifest = parse_and_validate_shard_manifest(&files["manifest.json"])
            .expect("integrated candidate manifest must match its published schema");
        assert_eq!(manifest.profile.as_deref(), Some("full-v1"));
        assert_eq!(manifest.components.len(), 33);
        assert_eq!(manifest.checksums.len(), 33);
        validate_shard_manifest_contract(&manifest)
            .expect("integrated full-v1 candidate must be supported");
        validate_shard_component_inventory(&manifest, &files)
            .expect("integrated candidate component inventory must validate");
        for (filename, expected) in &manifest.checksums {
            assert_eq!(
                hex::encode(sha2::Sha256::digest(&files[filename])),
                *expected,
                "integrated candidate checksum drift: {filename}"
            );
        }

        let attachment_digests = validate_shard_relationships(&files)
            .expect("integrated candidate relationships must be coherent");
        let sidecars = validate_shard_sidecars(&files, &attachment_digests, "full-v1")
            .expect("integrated candidate must contain every required attachment byte");
        let trust_store = shard_signature::parse_trust_store(Some(
            &serde_json::json!([{
                "key_id": receipt["signerKeyId"],
                "public_key": receipt["signerPublicKey"],
            }])
            .to_string(),
        ))
        .unwrap()
        .unwrap();
        assert_eq!(
            shard_signature::verify_shard_signature(
                &files,
                attachment_digests.keys(),
                &trust_store,
            ),
            shard_signature::ShardSignatureVerdict::Valid
        );
        assert_eq!(
            hex::encode(sha2::Sha256::digest(
                &files[shard_signature::SIGNATURE_ENTRY]
            )),
            receipt["signatureEnvelopeSha256"].as_str().unwrap()
        );
        assert_eq!(attachment_digests.len(), 1);
        assert_eq!(sidecars.len(), 1);
        let attachment_reference_count =
            parse_shard_component_records("notes", &files["notes.jsonl"])
                .unwrap()
                .iter()
                .map(|note| note["attachments"].as_array().unwrap().len())
                .sum::<usize>();
        assert_eq!(
            attachment_reference_count,
            receipt["attachmentReferenceCount"].as_u64().unwrap() as usize
        );
        let blob_checksum = receipt["blobChecksum"].as_str().unwrap();
        assert_eq!(
            sidecars[blob_checksum],
            b"Fortemi full-v1 attachment fixture\n"
        );

        assert_typed_jsonl_round_trip::<ShardNoteOriginalRecord>(&files["note_originals.jsonl"]);
        assert_typed_jsonl_round_trip::<ShardNoteOriginalHistoryRecord>(
            &files["note_original_history.jsonl"],
        );
        assert_typed_jsonl_round_trip::<ShardNoteRevisedCurrentRecord>(
            &files["note_revised_current.jsonl"],
        );
        assert_typed_jsonl_round_trip::<ShardNoteRevisionRecord>(&files["note_revisions.jsonl"]);

        let entries = files
            .iter()
            .map(|(name, bytes)| (name.as_str(), bytes.as_slice(), tar::EntryType::Regular))
            .collect::<Vec<_>>();
        let rebuilt = test_shard_archive(&entries);
        let round_tripped = read_shard_archive(&rebuilt, ShardArchiveLimits::default())
            .expect("rebuilt integrated candidate archive must remain readable");
        assert_eq!(round_tripped, files);
    }

    #[test]
    fn canonical_core_v1_schemas_reject_negative_fixtures() {
        let manifest_error = parse_and_validate_shard_manifest(include_bytes!(
            "../../../tests/fixtures/shards/schema-invalid/manifest-unknown-profile.json"
        ))
        .unwrap_err();
        assert_eq!(
            manifest_error,
            "Knowledge shard manifest does not match canonical core-v1 schema."
        );

        let note_error = validate_shard_component_schema_for_profile(
            matric_core::shard::CURRENT_SHARD_VERSION,
            DEFAULT_SHARD_PROFILE,
            "notes",
            include_bytes!("../../../tests/fixtures/shards/schema-invalid/note-missing-id.json"),
        )
        .unwrap_err();
        assert_eq!(
            note_error,
            "Knowledge shard component does not match canonical core-v1 schema."
        );

        let link_error = validate_shard_component_schema_for_profile(
            matric_core::shard::CURRENT_SHARD_VERSION,
            DEFAULT_SHARD_PROFILE,
            "links",
            include_bytes!(
                "../../../tests/fixtures/shards/schema-invalid/link-ambiguous-target.json"
            ),
        )
        .unwrap_err();
        assert_eq!(
            link_error,
            "Knowledge shard component does not match canonical core-v1 schema."
        );

        let valid_note: serde_json::Value = serde_json::from_str(include_str!(
            "../../../tests/fixtures/shards/core-v1-v1.2-valid/notes.jsonl"
        ))
        .expect("golden note must parse");
        let mut tombstone_note = valid_note.clone();
        tombstone_note["deleted_at"] = serde_json::json!("2026-07-18T00:00:00Z");
        validate_shard_json_schema(
            &tombstone_note,
            CORE_V1_NOTE_SCHEMA,
            "Knowledge shard component does not match canonical core-v1 schema.",
        )
        .expect("canonical tombstone timestamp must validate");
        for (field, value) in [
            ("id", serde_json::json!("not-a-uuid")),
            ("created_at", serde_json::json!("not-a-timestamp")),
            ("deleted_at", serde_json::json!("not-a-timestamp")),
        ] {
            let mut invalid = valid_note.clone();
            invalid[field] = value;
            assert_eq!(
                validate_shard_json_schema(
                    &invalid,
                    CORE_V1_NOTE_SCHEMA,
                    "Knowledge shard component does not match canonical core-v1 schema.",
                )
                .unwrap_err(),
                "Knowledge shard component does not match canonical core-v1 schema."
            );
        }
        let mut invalid_hash = valid_note.clone();
        invalid_hash["attachments"][0]["attachment"]["checksum"] = serde_json::json!("not-a-hash");
        assert_eq!(
            validate_shard_json_schema(
                &invalid_hash,
                CORE_V1_NOTE_SCHEMA,
                "Knowledge shard component does not match canonical core-v1 schema.",
            )
            .unwrap_err(),
            "Knowledge shard component does not match canonical core-v1 schema."
        );
        let mut invalid_digest_algorithm = valid_note;
        invalid_digest_algorithm["attachments"][0]["attachment"]["checksum"] = serde_json::json!(
            "sha256:0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef"
        );
        assert_eq!(
            validate_shard_json_schema(
                &invalid_digest_algorithm,
                CORE_V1_NOTE_SCHEMA,
                "Knowledge shard component does not match canonical core-v1 schema.",
            )
            .unwrap_err(),
            "Knowledge shard component does not match canonical core-v1 schema."
        );

        let valid_manifest: serde_json::Value = serde_json::from_str(include_str!(
            "../../../tests/fixtures/shards/core-v1-v1.2-valid/manifest.json"
        ))
        .expect("golden manifest must parse");
        for (pointer, value) in [
            ("/version", serde_json::json!("1.0")),
            ("/checksums/notes.jsonl", serde_json::json!("not-a-sha256")),
        ] {
            let mut invalid = valid_manifest.clone();
            *invalid
                .pointer_mut(pointer)
                .expect("golden manifest pointer must exist") = value;
            assert_eq!(
                validate_shard_json_schema(
                    &invalid,
                    CORE_V1_MANIFEST_SCHEMA,
                    "Knowledge shard manifest does not match canonical core-v1 schema.",
                )
                .unwrap_err(),
                "Knowledge shard manifest does not match canonical core-v1 schema."
            );
        }
    }

    #[test]
    fn shard_contract_rejects_missing_unknown_and_incomplete_profiles() {
        let mut manifest = valid_core_shard_manifest();
        manifest.profile = None;
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Knowledge shard profile is required."
        );

        manifest.profile = Some("future-profile".to_string());
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Unknown knowledge shard profile."
        );

        manifest.profile = Some("full-v1".to_string());
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Knowledge shard full-v1 profile requires the complete component inventory."
        );

        let record_manifest = parse_and_validate_shard_manifest(include_bytes!(
            "../../../tests/fixtures/shards/record-v1-v1.1-valid/manifest.json"
        ))
        .expect("record-v1 golden manifest must match canonical schema");
        validate_shard_manifest_contract(&record_manifest)
            .expect("record-v1 must be supported by this server release");

        manifest.profile = Some("record-v1".to_string());
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Shard profile declares a component unsupported by this server release."
        );
    }

    #[test]
    fn shard_contract_rejects_invalid_and_incompatible_schema_versions() {
        let mut manifest = valid_core_shard_manifest();
        for version in ["1.0", "01.0.0", "1.0.0-beta"] {
            manifest.version = version.to_string();
            assert_eq!(
                validate_shard_manifest_contract(&manifest).unwrap_err(),
                "Knowledge shard schema version must be strict SemVer."
            );
        }

        manifest.version = "2.0.0".to_string();
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Knowledge shard schema version is incompatible."
        );

        manifest.version = "1.0.1".to_string();
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "No migration path exists for this shard schema version."
        );

        manifest.version = "1.0.0".to_string();
        validate_shard_manifest_contract(&manifest)
            .expect("registered legacy schema version must have a migration path");
    }

    #[test]
    fn shard_contract_rejects_invalid_or_newer_minimum_reader() {
        let mut manifest = valid_core_shard_manifest();
        manifest.min_reader_version = Some("1.0".to_string());
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Knowledge shard minimum reader version must be strict SemVer."
        );

        manifest.min_reader_version = Some("2.0.0".to_string());
        assert_eq!(
            validate_shard_manifest_contract(&manifest).unwrap_err(),
            "Knowledge shard requires a newer reader contract."
        );
    }

    #[test]
    fn shard_inventory_rejects_missing_undeclared_and_count_mismatches() {
        let manifest = valid_core_shard_manifest();

        let mut files = valid_core_shard_files();
        files.insert(shard_signature::SIGNATURE_ENTRY.to_string(), b"{}".to_vec());
        validate_shard_component_inventory(&manifest, &files)
            .expect("the reserved signature envelope is not a manifest component");

        let mut files = valid_core_shard_files();
        files.remove("tags.json");
        assert_eq!(
            validate_shard_component_inventory(&manifest, &files).unwrap_err(),
            "Knowledge shard declared component file is missing."
        );

        let mut files = valid_core_shard_files();
        files.insert("embeddings.jsonl".to_string(), Vec::new());
        assert_eq!(
            validate_shard_component_inventory(&manifest, &files).unwrap_err(),
            "Knowledge shard contains an undeclared component file."
        );

        let mut files = valid_core_shard_files();
        files.insert(
            "notes.jsonl".to_string(),
            include_bytes!("../../../tests/fixtures/shards/core-v1-valid/notes.jsonl").to_vec(),
        );
        assert_eq!(
            validate_shard_component_inventory(&manifest, &files).unwrap_err(),
            "Knowledge shard component count validation failed."
        );
    }

