    struct DenyAllPolicy;

    #[async_trait::async_trait]
    impl AuthorizationPolicy for DenyAllPolicy {
        async fn authorize(
            &self,
            _principal: &AuthPrincipal,
            _action: &matric_core::Action,
            _resource: &matric_core::Resource,
            _ctx: &matric_core::AuthzContext,
        ) -> Result<Decision, matric_core::AuthzError> {
            Ok(Decision::Deny {
                reason: matric_core::DenyReason::MissingScope,
                policy_id: self.policy_id().to_string(),
                policy_version: self.policy_version().to_string(),
            })
        }

        fn policy_id(&self) -> &'static str {
            "deny-all-test"
        }

        fn policy_version(&self) -> &'static str {
            "test"
        }
    }

    #[tokio::test]
    async fn authorize_policy_input_denies_with_forbidden_response() {
        let auth = Auth {
            principal: AuthPrincipal::ApiKey {
                key_id: Uuid::new_v4(),
                scope: "read".to_string(),
            },
        };
        let input =
            route_policy::authorization_input_for_request(&Method::POST, "/api/v1/notes", None)
                .expect("notes route has policy input");

        let response = authorize_policy_input(&DenyAllPolicy, &auth, &input)
            .await
            .expect_err("deny policy should produce a forbidden response");

        assert_eq!(response.status(), StatusCode::FORBIDDEN);
        let problem = read_response_json(response).await;
        assert_eq!(problem["type"], "https://fortemi.com/problems/forbidden");
        assert_eq!(problem["detail"], "Authorization denied.");
        assert!(problem.get("error").is_none());
        assert!(problem.get("error_description").is_none());
        assert!(!problem.to_string().contains("MissingScope"));
    }

    #[tokio::test]
    async fn get_call_returns_session_segments_pagination_and_404() {
        let database_url = std::env::var("DATABASE_URL")
            .unwrap_or_else(|_| "postgres://matric:matric@localhost/matric".to_string());
        let db = Database::connect(&database_url)
            .await
            .expect("Failed to connect to test DB");
        let provider_call_id = format!("api-test-secret-{}", Uuid::new_v4());
        let remote_party = "+15551234567";
        let asr_backend = "mock-asr-secret-backend";
        let metadata_secret = "https://api.twilio.com/recording.wav?token=sk-live-call-detail";
        let session = db
            .call_sessions
            .create_session(matric_core::CreateCallSessionRequest {
                provider: "mock".to_string(),
                provider_call_id: provider_call_id.clone(),
                started_at: None,
                asr_backend: Some(asr_backend.to_string()),
                remote_party: Some(remote_party.to_string()),
                archive_id: None,
                metadata: serde_json::json!({
                    "test": true,
                    "recording_url": metadata_secret,
                    "customer": "customer@example.com"
                }),
            })
            .await
            .expect("create call session");

        for sequence in 0..2 {
            db.call_sessions
                .create_transcript_segment(matric_core::CreateTranscriptSegmentRequest {
                    call_id: session.call_id,
                    speaker_label: Some("speaker_0".to_string()),
                    text: format!("segment {sequence}"),
                    start_ts: Some(sequence as f64),
                    end_ts: Some(sequence as f64 + 0.5),
                    confidence: Some(0.9),
                    sequence,
                })
                .await
                .expect("create transcript segment");
        }

        let state = build_call_api_test_state(db.clone(), &database_url).await;
        let router = Router::new()
            .route("/api/v1/calls/{id}", get(get_call))
            .with_state(state);
        let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
        let base_url = format!("http://{}", listener.local_addr().unwrap());
        tokio::spawn(async move {
            axum::serve(listener, router).await.unwrap();
        });

        let client = reqwest::Client::new();
        let response = client
            .get(format!(
                "{}/api/v1/calls/{}?limit=1&offset=1",
                base_url, session.call_id
            ))
            .send()
            .await
            .unwrap();
        assert_eq!(response.status(), reqwest::StatusCode::OK);
        let body: serde_json::Value = response.json().await.unwrap();
        assert_eq!(body["call_id"], session.call_id.to_string());
        assert_eq!(body["provider"], "mock");
        assert_eq!(body["provider_call"]["provider_call_id_present"], true);
        assert_eq!(
            body["provider_call"]["provider_call_id_len"],
            provider_call_id.chars().count()
        );
        assert_eq!(body["asr_backend_len"], asr_backend.chars().count());
        assert_eq!(body["remote_party_present"], true);
        assert_eq!(body["remote_party_len"], remote_party.chars().count());
        assert_eq!(body["metadata_class"], "object");
        assert!(body["metadata_len"].as_u64().unwrap() > 0);
        assert_eq!(body["segment_count"], 2);
        assert_eq!(body["segments"].as_array().unwrap().len(), 1);
        assert_eq!(body["segments"][0]["text"], "segment 1");
        assert_eq!(body["pagination"]["total"], 2);
        assert_eq!(body["pagination"]["limit"], 1);
        assert_eq!(body["pagination"]["offset"], 1);
        assert_eq!(body["pagination"]["has_more"], false);
        let serialized_body = serde_json::to_string(&body).expect("serialize call detail body");
        for raw in [
            provider_call_id.as_str(),
            "api-test-secret",
            remote_party,
            asr_backend,
            "recording_url",
            "api.twilio.com",
            "sk-live-call-detail",
            "customer@example.com",
        ] {
            assert!(
                !serialized_body.contains(raw),
                "raw call metadata leaked: {raw}"
            );
        }

        let missing = client
            .get(format!("{}/api/v1/calls/{}", base_url, Uuid::new_v4()))
            .send()
            .await
            .unwrap();
        assert_eq!(missing.status(), reqwest::StatusCode::NOT_FOUND);

        sqlx::query("DELETE FROM transcript_segments WHERE call_id = $1")
            .bind(session.call_id)
            .execute(db.pool())
            .await
            .expect("cleanup segments");
        sqlx::query("DELETE FROM call_sessions WHERE call_id = $1")
            .bind(session.call_id)
            .execute(db.pool())
            .await
            .expect("cleanup session");
    }

