    /// Receive the next Text message from a WS stream, skipping Ping/Pong frames.
    async fn next_text_message(
        ws: &mut (impl futures::Stream<
            Item = Result<
                tokio_tungstenite::tungstenite::Message,
                tokio_tungstenite::tungstenite::Error,
            >,
        > + Unpin),
    ) -> String {
        use futures::StreamExt;
        let deadline = std::time::Duration::from_secs(5);
        let start = tokio::time::Instant::now();
        loop {
            let remaining = deadline.saturating_sub(start.elapsed());
            if remaining.is_zero() {
                panic!("timeout waiting for WS text message");
            }
            let msg = tokio::time::timeout(remaining, ws.next())
                .await
                .expect("timeout waiting for WS message")
                .expect("stream ended")
                .expect("WS error");
            if msg.is_text() {
                return msg.into_text().unwrap().to_string();
            }
            // Skip Ping, Pong, Binary, etc.
        }
    }

    /// Build a minimal test server with only eventing routes.
    /// Returns the base URL (e.g., "http://127.0.0.1:PORT").
    async fn spawn_eventing_test_server() -> (String, Arc<EventBus>, Arc<AtomicUsize>) {
        let database_url = std::env::var("DATABASE_URL")
            .unwrap_or_else(|_| "postgres://matric:matric@localhost/matric".to_string());
        let db = Database::connect(&database_url)
            .await
            .expect("Failed to connect to test DB");
        let event_bus = Arc::new(EventBus::new(matric_core::defaults::EVENT_BUS_CAPACITY));
        let ws_connections = Arc::new(AtomicUsize::new(0));

        let state = AppState {
            db,
            search: Arc::new(matric_search::HybridSearchEngine::new(
                Database::connect(&database_url).await.unwrap(),
            )),
            issuer: "http://localhost:3000".to_string(),
            rate_limiter: None,
            tag_resolver: matric_api::services::TagResolver::new(
                Database::connect(&database_url).await.unwrap(),
            ),
            search_cache: matric_api::services::SearchCache::disabled(),
            event_bus: event_bus.clone(),
            ws_connections: ws_connections.clone(),
            default_archive_cache: Arc::new(RwLock::new(DefaultArchiveCache::new(60))),
            require_auth: false,
            call_recording_require_confirmation: false,
            authorization_policy: Arc::new(AllowAllPolicy),
            usage_meter: Arc::new(NoOpMeter),
            oauth_token_lifetime: chrono::Duration::seconds(
                matric_core::defaults::OAUTH_TOKEN_LIFETIME_SECS as i64,
            ),
            oauth_mcp_token_lifetime: chrono::Duration::seconds(
                matric_core::defaults::OAUTH_MCP_TOKEN_LIFETIME_SECS as i64,
            ),
            max_memories: matric_core::defaults::MAX_MEMORIES,
            max_upload_size: matric_core::defaults::MAX_UPLOAD_SIZE_BYTES,
            attachment_scan_mode: AttachmentScanMode::Disabled,
            attachment_scan_metrics: Arc::new(AttachmentScanMetrics::default()),
            vision_backend: None,
            transcription_backend: None,
            realtime_deepgram_metrics: None,
            realtime_asr_backend: None,
            ner_backend: None,
            diarization_backend: None,
            git_sha: "test".to_string(),
            build_date: "test".to_string(),
            extraction_strategies: Vec::new(),
            inference_runtime: Arc::new(std::sync::RwLock::new(InferenceRuntime {
                generation_backend: None,
                provider_registry: std::sync::Arc::new(
                    matric_inference::ProviderRegistry::from_env(),
                ),
            })),
            schema_engines: Arc::new(tokio::sync::RwLock::new(std::collections::HashMap::new())),
            database_url: String::new(),
            tus_staging_path: "/tmp/matric-tus-staging-test".to_string(),
            pause_state: None,
            chat_semaphore: None,
            inference_available: Arc::new(AtomicBool::new(false)),
            chat_stream_metrics: Arc::new(ChatStreamMetrics::default()),
            ingest_stream_metrics: Arc::new(
                crate::handlers::ingest_stream::IngestStreamMetrics::default(),
            ),
            inbound_metrics: Arc::new(matric_jobs::inbound::InboundMetrics::new()),
            lifecycle: LifecycleState::default(),
            trusted_proxy_config: TrustedProxyConfig::default(),
            chat_stream_store: matric_api::services::ChatStreamStore::disabled(),
            ingest_cursor_store: matric_api::services::IngestCursorStore::disabled(),
            ingest_token_store: matric_api::services::IngestTokenStore::disabled(),
            idempotency_store: matric_api::services::IdempotencyStore::disabled(),
        };

        let router = Router::new()
            .route("/health", get(health_check))
            .route("/api/v1/ws", get(ws_handler))
            .route("/api/v1/events", get(sse_events))
            .route("/api/v1/webhooks", post(create_webhook).get(list_webhooks))
            .route(
                "/api/v1/webhooks/{id}",
                get(get_webhook)
                    .patch(update_webhook)
                    .delete(delete_webhook_handler),
            )
            .route(
                "/api/v1/webhooks/{id}/deliveries",
                get(list_webhook_deliveries),
            )
            .route("/api/v1/webhooks/{id}/test", post(test_webhook))
            .route("/api/v1/api-keys", get(list_api_keys).post(create_api_key))
            .route("/api/v1/api-keys/{id}", delete(revoke_api_key))
            .route(
                "/api/v1/inbound-sources",
                get(list_inbound_sources).post(create_inbound_source),
            )
            .route(
                "/api/v1/inbound-sources/{name}",
                delete(delete_inbound_source),
            )
            .route(
                "/api/v1/webhooks/incoming",
                post(create_incoming_webhook_receiver).get(list_incoming_webhook_receivers),
            )
            .route(
                "/api/v1/webhooks/incoming/validate",
                post(validate_incoming_webhook_payload_handler),
            )
            .route(
                "/api/v1/webhooks/incoming/{slug}",
                get(get_incoming_webhook_receiver)
                    .post(receive_incoming_webhook)
                    .patch(update_incoming_webhook_receiver)
                    .delete(delete_incoming_webhook_receiver),
            )
            .layer(Extension(ArchiveContext::default()))
            .with_state(state);

        let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
        let addr = listener.local_addr().unwrap();
        let base_url = format!("http://{}", addr);

        tokio::spawn(async move {
            axum::serve(listener, router).await.unwrap();
        });

        // Give server a moment to start
        tokio::time::sleep(std::time::Duration::from_millis(50)).await;

        (base_url, event_bus, ws_connections)
    }

