    fn note_timeline_and_activity_debug_redacts_note_ids_and_titles() {
        let note_id = Uuid::new_v4();
        let timeline = TimelineBucket {
            period_start: chrono::Utc::now(),
            period_end: chrono::Utc::now(),
            count: 1,
            note_ids: vec![note_id],
        };
        let activity = ActivityEntry {
            note_id,
            title: Some(
                "operator@example.com postgres://user:secret@db.internal/note /srv/private sk-live-title"
                    .to_string(),
            ),
            created_at: chrono::Utc::now(),
            updated_at: chrono::Utc::now(),
            is_recently_created: true,
            is_recently_updated: false,
        };

        let rendered_timeline = format!("{timeline:?}");
        let rendered_activity = format!("{activity:?}");
        let combined = format!("{rendered_timeline}\n{rendered_activity}");

        for forbidden in [
            &note_id.to_string(),
            "operator@example.com",
            "postgres://user:secret@db.internal/note",
            "/srv/private",
            "sk-live-title",
        ] {
            assert!(
                !combined.contains(forbidden),
                "timeline/activity Debug leaked {forbidden}: {combined}"
            );
        }

        assert!(rendered_timeline.contains("note_id_count"));
        assert!(rendered_timeline.contains("count"));
        assert!(rendered_activity.contains("note_id_present"));
        assert!(rendered_activity.contains("title_len"));
    }

    #[test]
    fn test_parse_byte_range_full_range() {
        // bytes=0-99 of a 1000-byte file
        let (start, end) = parse_byte_range("bytes=0-99", 1000).unwrap();
        assert_eq!(start, 0);
        assert_eq!(end, 99);
    }

    #[test]
    fn test_parse_byte_range_middle() {
        let (start, end) = parse_byte_range("bytes=500-999", 2000).unwrap();
        assert_eq!(start, 500);
        assert_eq!(end, 999);
    }

    #[test]
    fn test_parse_byte_range_open_end() {
        // bytes=500- means from 500 to end
        let (start, end) = parse_byte_range("bytes=500-", 1000).unwrap();
        assert_eq!(start, 500);
        assert_eq!(end, 999);
    }

    #[test]
    fn test_parse_byte_range_suffix() {
        // bytes=-200 means last 200 bytes
        let (start, end) = parse_byte_range("bytes=-200", 1000).unwrap();
        assert_eq!(start, 800);
        assert_eq!(end, 999);
    }

    #[test]
    fn test_parse_byte_range_clamps_end() {
        // End beyond file size should clamp
        let (start, end) = parse_byte_range("bytes=0-9999", 1000).unwrap();
        assert_eq!(start, 0);
        assert_eq!(end, 999);
    }

