    /// Standard base64-encoded ASCII value must round-trip correctly.
    #[test]
    fn test_base64_decode_metadata_ascii() {
        use base64::Engine;
        let encoded = base64::engine::general_purpose::STANDARD.encode("hello.txt");
        let result = base64_decode_metadata(&encoded);
        assert_eq!(result, Some("hello.txt".to_string()));
    }

    /// Non-ASCII UTF-8 content must decode without error.
    #[test]
    fn test_base64_decode_metadata_utf8() {
        use base64::Engine;
        let input = "Ünïcödé_fïlë.txt";
        let encoded = base64::engine::general_purpose::STANDARD.encode(input);
        let result = base64_decode_metadata(&encoded);
        assert_eq!(result, Some(input.to_string()));
    }

    /// Empty string must decode to Some(""), not None.
    #[test]
    fn test_base64_decode_metadata_empty_value() {
        use base64::Engine;
        let encoded = base64::engine::general_purpose::STANDARD.encode("");
        let result = base64_decode_metadata(&encoded);
        assert_eq!(result, Some(String::new()));
    }

    /// Whitespace surrounding the value (from header parsing) must be trimmed
    /// before decoding so the base64 engine does not reject the input.
    #[test]
    fn test_base64_decode_metadata_trims_whitespace() {
        use base64::Engine;
        let raw = base64::engine::general_purpose::STANDARD.encode("trimmed");
        let padded = format!("  {}  ", raw);
        let result = base64_decode_metadata(&padded);
        assert_eq!(result, Some("trimmed".to_string()));
    }

    #[test]
    fn tus_extra_metadata_telemetry_redacts_keys_and_values() {
        let mut telemetry = TusExtraMetadataTelemetry::default();
        telemetry.record("api_key", "sk-live-secret");
        telemetry.record(
            "callback_url",
            "https://provider.example.test/callback?token=secret",
        );

        let mut metadata = serde_json::Map::new();
        telemetry.insert_into(&mut metadata);
        let value = serde_json::Value::Object(metadata);
        let serialized = value.to_string();

        assert_eq!(value["extra_metadata_count"], 2);
        assert_eq!(value["extra_metadata_secret_candidate_count"], 2);
        assert!(serialized.contains("extra_metadata_key_total_len"));
        assert!(serialized.contains("extra_metadata_value_total_len"));
        assert!(!serialized.contains("api_key"));
        assert!(!serialized.contains("callback_url"));
        assert!(!serialized.contains("sk-live-secret"));
        assert!(!serialized.contains("provider.example.test"));
        assert!(!serialized.contains("token=secret"));
    }

