    #[test]
    fn incoming_signature_accepts_outbound_hmac_format() {
        use hmac::{Hmac, Mac};
        use sha2::Sha256;
        type HmacSha256 = Hmac<Sha256>;

        let body = br#"{"CallSid":"CA123","CallStatus":"ringing"}"#;
        let secret = "super-secret-value";
        let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(body);
        let signature = format!("sha256={}", hex::encode(mac.finalize().into_bytes()));

        let mut headers = HeaderMap::new();
        headers.insert("X-Fortemi-Signature", signature.parse().unwrap());

        verify_incoming_signature(&headers, "X-Fortemi-Signature", secret, body, None, None)
            .unwrap();
    }

    #[test]
    fn incoming_signature_accepts_twilio_hmac_sha1_format() {
        use hmac::{Hmac, Mac};
        use sha1::Sha1;
        type HmacSha1 = Hmac<Sha1>;

        let secret = "twilio-auth-token-value";
        let uri: Uri = "/api/v1/webhooks/incoming/twilio-voice-events?retry=1"
            .parse()
            .unwrap();
        let body = b"To=%2B18005551212&CallSid=CA1234567890ABCDE&Digits=1234&From=%2B12349013030&Caller=%2B12349013030";
        let payload = "https://voice.example.com/api/v1/webhooks/incoming/twilio-voice-events?retry=1CallSidCA1234567890ABCDECaller+12349013030Digits1234From+12349013030To+18005551212";
        let mut mac = HmacSha1::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(payload.as_bytes());
        let signature =
            base64::engine::general_purpose::STANDARD.encode(mac.finalize().into_bytes());

        let mut headers = HeaderMap::new();
        headers.insert("Host", "internal.local".parse().unwrap());
        headers.insert("X-Forwarded-Proto", "https".parse().unwrap());
        headers.insert("X-Forwarded-Host", "voice.example.com".parse().unwrap());
        headers.insert("X-Twilio-Signature", signature.parse().unwrap());
        let context = ExternalRequestContext::from_request(
            &TrustedProxyConfig::from_value(Some("127.0.0.1/32")).unwrap(),
            Some("127.0.0.1:45000".parse().unwrap()),
            &headers,
            &uri,
        )
        .unwrap();

        verify_incoming_signature(
            &headers,
            "X-Twilio-Signature",
            secret,
            body,
            Some(&uri),
            Some(&context),
        )
        .unwrap();
    }

    #[test]
    fn incoming_signature_ignores_untrusted_forwarded_url_spoofing() {
        use hmac::{Hmac, Mac};
        use sha1::Sha1;
        type HmacSha1 = Hmac<Sha1>;

        let secret = "twilio-auth-token-value";
        let uri: Uri = "/api/v1/webhooks/incoming/twilio-voice-events"
            .parse()
            .unwrap();
        let body = b"CallSid=CA1234567890ABCDE";
        let attacker_payload = "http://attacker.example/api/v1/webhooks/incoming/twilio-voice-eventsCallSidCA1234567890ABCDE";
        let mut mac = HmacSha1::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(attacker_payload.as_bytes());
        let signature =
            base64::engine::general_purpose::STANDARD.encode(mac.finalize().into_bytes());

        let mut headers = HeaderMap::new();
        headers.insert("Host", "voice.example.com".parse().unwrap());
        headers.insert("X-Forwarded-Proto", "http".parse().unwrap());
        headers.insert("X-Forwarded-Host", "attacker.example".parse().unwrap());
        headers.insert("X-Twilio-Signature", signature.parse().unwrap());
        let context = ExternalRequestContext::from_request(
            &TrustedProxyConfig::from_value(Some("10.0.0.0/8")).unwrap(),
            Some("192.0.2.4:45000".parse().unwrap()),
            &headers,
            &uri,
        )
        .unwrap();

        assert_eq!(
            context.forwarded_disposition().as_str(),
            "suppressed",
            "configured proxy mismatch must suppress spoofed metadata"
        );
        assert!(matches!(
            verify_incoming_signature(
                &headers,
                "X-Twilio-Signature",
                secret,
                body,
                Some(&uri),
                Some(&context),
            ),
            Err(ApiError::Unauthorized(_))
        ));
    }

    #[test]
    fn incoming_signature_rejects_twilio_mismatched_url() {
        let uri: Uri = "/api/v1/webhooks/incoming/twilio-voice-events"
            .parse()
            .unwrap();
        let mut headers = HeaderMap::new();
        headers.insert("Host", "voice.example.com".parse().unwrap());
        headers.insert("X-Twilio-Signature", "invalid".parse().unwrap());
        let context = ExternalRequestContext::from_request(
            &TrustedProxyConfig::default(),
            Some("192.0.2.4:45000".parse().unwrap()),
            &headers,
            &uri,
        )
        .unwrap();

        assert!(matches!(
            verify_incoming_signature(
                &headers,
                "X-Twilio-Signature",
                "twilio-auth-token-value",
                b"CallSid=CA1234567890ABCDE&CallStatus=ringing",
                Some(&uri),
                Some(&context),
            ),
            Err(ApiError::Unauthorized(_))
        ));
    }

    #[test]
    fn incoming_signature_rejects_missing_or_mismatched_signature() {
        let body = b"payload";
        let headers = HeaderMap::new();
        assert!(matches!(
            verify_incoming_signature(
                &headers,
                "X-Fortemi-Signature",
                "super-secret-value",
                body,
                None,
                None,
            ),
            Err(ApiError::Unauthorized(_))
        ));

        let mut headers = HeaderMap::new();
        headers.insert("X-Fortemi-Signature", "sha256=00".parse().unwrap());
        assert!(matches!(
            verify_incoming_signature(
                &headers,
                "X-Fortemi-Signature",
                "super-secret-value",
                body,
                None,
                None,
            ),
            Err(ApiError::Unauthorized(_))
        ));
    }

