    #[tokio::test]
    async fn twilio_voice_webhook_emits_call_event_outbox_contract() {
        use sqlx::Row;

        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database");
        let provider_call_id = format!("CA{}", Uuid::new_v4().simple());
        let state = build_call_api_test_state(db.clone(), &database_url).await;

        let start_body = format!(
            "CallSid={provider_call_id}&CallStatus=ringing&From=%2B15551230000&To=%2B15559870000&Direction=inbound&ConsentConfirmed=true&DisclosurePlayed=true&DisclosureVersion=v2026-05"
        );
        let started = apply_twilio_voice_webhook(&state, start_body.as_bytes())
            .await
            .expect("apply started webhook");
        let call_id = Uuid::parse_str(started["call_id"].as_str().unwrap()).unwrap();
        assert_eq!(started["provider_call"]["provider_call_id_present"], true);
        assert_eq!(
            started["provider_call"]["provider_call_id_len"],
            provider_call_id.chars().count()
        );

        let active_body = format!("CallSid={provider_call_id}&CallStatus=in-progress");
        let active = apply_twilio_voice_webhook(&state, active_body.as_bytes())
            .await
            .expect("apply active webhook");

        let recording_body = format!(
            "CallSid={provider_call_id}&RecordingStatus=completed&RecordingSid=RE123&RecordingUrl=https%3A%2F%2Fapi.twilio.com%2Frecording.wav"
        );
        let recording = apply_twilio_voice_webhook(&state, recording_body.as_bytes())
            .await
            .expect("apply recording webhook");
        assert_eq!(recording["recording"]["recording_url_class"], "twilio_api");
        assert_eq!(
            recording["recording"]["recording_url_len"],
            "https://api.twilio.com/recording.wav".chars().count()
        );

        let ended_body = format!("CallSid={provider_call_id}&CallStatus=completed");
        let ended = apply_twilio_voice_webhook(&state, ended_body.as_bytes())
            .await
            .expect("apply completed webhook");
        let serialized_responses = serde_json::to_string(&vec![started, active, recording, ended])
            .expect("serialize Twilio webhook responses");
        assert!(!serialized_responses.contains(&provider_call_id));
        assert!(!serialized_responses.contains("+15551230000"));
        assert!(!serialized_responses.contains("api.twilio.com"));
        assert!(!serialized_responses.contains("recording.wav"));

        let rows = sqlx::query(
            r#"
            SELECT event_type, entity_type, entity_id, payload
            FROM event_outbox
            WHERE entity_id = $1
            ORDER BY created_at ASC, id ASC
            "#,
        )
        .bind(call_id)
        .fetch_all(db.pool())
        .await
        .expect("load call event outbox rows");
        assert_eq!(rows.len(), 4);

        let payloads: Vec<serde_json::Value> = rows
            .iter()
            .map(|row| {
                assert_eq!(row.get::<String, _>("event_type"), "call_event");
                assert_eq!(row.get::<String, _>("entity_type"), "call_session");
                assert_eq!(row.get::<Uuid, _>("entity_id"), call_id);
                row.get::<serde_json::Value, _>("payload")
            })
            .collect();

        let event_types: Vec<_> = payloads
            .iter()
            .map(|payload| payload["event_type"].as_str().unwrap())
            .collect();
        assert_eq!(
            event_types,
            vec![
                "call_started",
                "state_change",
                "recording_available",
                "ended"
            ]
        );
        assert!(payloads.iter().all(|payload| {
            payload["call_id"] == serde_json::json!(call_id)
                && payload["provider"] == "twilio"
                && payload["provider_call_id_present"] == true
                && payload["provider_call_id_len"] == provider_call_id.chars().count()
        }));
        assert_eq!(payloads[0]["payload"]["remote_party_present"], true);
        assert_eq!(payloads[0]["payload"]["remote_party_len"], 12);
        assert_eq!(payloads[0]["payload"]["metadata_class"], "object");
        assert_eq!(payloads[1]["payload"]["to"], "active");
        assert_eq!(payloads[2]["payload"]["url_class"], "twilio_api");
        assert_eq!(payloads[3]["payload"]["reason"], "normal_hangup");
        let serialized_payloads =
            serde_json::to_string(&payloads).expect("serialize Twilio call event payloads");
        assert!(!serialized_payloads.contains(&provider_call_id));
        assert!(!serialized_payloads.contains("+15551230000"));
        assert!(!serialized_payloads.contains("api.twilio.com"));
        assert!(!serialized_payloads.contains("recording.wav"));

        sqlx::query("DELETE FROM event_outbox WHERE entity_id = $1")
            .bind(call_id)
            .execute(db.pool())
            .await
            .expect("cleanup outbox events");
        sqlx::query("DELETE FROM call_sessions WHERE call_id = $1")
            .bind(call_id)
            .execute(db.pool())
            .await
            .expect("cleanup session");
    }

    /// #818: every accepted incoming webhook is durably captured into the
    /// shared event outbox as a generic `incoming_webhook.received` event, in
    /// addition to any schema-specific side effect. Uses a `twilio.media-stream`
    /// receiver (whose side effect is a no-op) to isolate the generic capture.
    #[tokio::test]
    async fn receive_incoming_webhook_captures_generic_outbox() {
        use hmac::{Hmac, Mac};
        use sha2::Sha256;
        use sqlx::Row;
        type HmacSha256 = Hmac<Sha256>;

        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database");
        let state = build_call_api_test_state(db.clone(), &database_url).await;

        let slug = format!("ms-capture-{}", Uuid::new_v4().simple());
        let secret = "incoming-capture-secret-1234567890";
        let receiver_id = db
            .incoming_webhooks
            .create(matric_core::CreateIncomingWebhookReceiverRequest {
                slug: slug.clone(),
                provider: "twilio".to_string(),
                schema_ref: "twilio.media-stream.v1".to_string(),
                hmac_secret: secret.to_string(),
                signature_header: "X-Fortemi-Signature".to_string(),
                is_active: true,
                schema_doc: None,
            })
            .await
            .expect("create receiver");

        let body =
            br#"{"event":"media","sequenceNumber":"7","media":{"payload":"AQIDBA=="}}"#.to_vec();
        let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(&body);
        let signature = format!("sha256={}", hex::encode(mac.finalize().into_bytes()));

        let mut headers = HeaderMap::new();
        headers.insert("X-Fortemi-Signature", signature.parse().unwrap());
        headers.insert(header::CONTENT_TYPE, "application/json".parse().unwrap());
        headers.insert(header::HOST, "localhost".parse().unwrap());

        let uri: Uri = format!("/api/v1/webhooks/incoming/{slug}").parse().unwrap();

        let response = receive_incoming_webhook(
            State(state.clone()),
            SocketPeer(None),
            OriginalUri(uri),
            Path(slug.clone()),
            headers,
            Bytes::from(body),
        )
        .await;
        assert!(response.is_ok(), "signed valid webhook should be accepted");

        let rows = sqlx::query(
            "SELECT event_type, payload FROM event_outbox \
             WHERE entity_type = 'incoming_webhook' AND entity_id = $1",
        )
        .bind(receiver_id)
        .fetch_all(db.pool())
        .await
        .expect("load generic capture rows");

        assert_eq!(rows.len(), 1, "exactly one generic capture row");
        assert_eq!(
            rows[0].get::<String, _>("event_type"),
            "incoming_webhook.received"
        );
        let payload = rows[0].get::<serde_json::Value, _>("payload");
        assert_eq!(payload["slug"], slug);
        assert_eq!(payload["schema_ref"], "twilio.media-stream.v1");
        assert_eq!(payload["provider"], "twilio");

        sqlx::query("DELETE FROM event_outbox WHERE entity_id = $1")
            .bind(receiver_id)
            .execute(db.pool())
            .await
            .ok();
        sqlx::query("DELETE FROM incoming_webhook_receiver WHERE id = $1")
            .bind(receiver_id)
            .execute(db.pool())
            .await
            .ok();
    }

    /// #820/#823: a wrong or missing HMAC signature is rejected with 401 before
    /// any processing (no outbox row, no side effect).
    #[tokio::test]
    async fn incoming_webhook_rejects_bad_and_missing_signature() {
        use hmac::{Hmac, Mac};
        use sha2::Sha256;
        type HmacSha256 = Hmac<Sha256>;

        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database");
        let state = build_call_api_test_state(db.clone(), &database_url).await;

        let slug = format!("sig-{}", Uuid::new_v4().simple());
        let secret = "sig-test-secret-1234567890abcd";
        let receiver_id = db
            .incoming_webhooks
            .create(matric_core::CreateIncomingWebhookReceiverRequest {
                slug: slug.clone(),
                provider: "contract".to_string(),
                schema_ref: "contract.any.v1".to_string(),
                hmac_secret: secret.to_string(),
                signature_header: "X-Fortemi-Signature".to_string(),
                is_active: true,
                schema_doc: Some(serde_json::json!({"type": "object"})),
            })
            .await
            .expect("create receiver");

        let body = br#"{"hello":"world"}"#.to_vec();
        let uri: Uri = format!("/api/v1/webhooks/incoming/{slug}").parse().unwrap();

        // Wrong signature → 401.
        let mut mac = HmacSha256::new_from_slice(b"the-wrong-secret").unwrap();
        mac.update(&body);
        let wrong = format!("sha256={}", hex::encode(mac.finalize().into_bytes()));
        let mut headers = HeaderMap::new();
        headers.insert("X-Fortemi-Signature", wrong.parse().unwrap());
        headers.insert(header::CONTENT_TYPE, "application/json".parse().unwrap());
        headers.insert(header::HOST, "localhost".parse().unwrap());
        let res = receive_incoming_webhook(
            State(state.clone()),
            SocketPeer(None),
            OriginalUri(uri.clone()),
            Path(slug.clone()),
            headers,
            Bytes::from(body.clone()),
        )
        .await;
        assert!(
            matches!(res, Err(ApiError::Unauthorized(_))),
            "wrong signature must be 401"
        );

        // Missing signature header → 401.
        let mut headers = HeaderMap::new();
        headers.insert(header::CONTENT_TYPE, "application/json".parse().unwrap());
        headers.insert(header::HOST, "localhost".parse().unwrap());
        let res = receive_incoming_webhook(
            State(state.clone()),
            SocketPeer(None),
            OriginalUri(uri),
            Path(slug.clone()),
            headers,
            Bytes::from(body),
        )
        .await;
        assert!(
            matches!(res, Err(ApiError::Unauthorized(_))),
            "missing signature must be 401"
        );

        // No outbox row should have been written for the rejected requests.
        let count: i64 = sqlx::query_scalar(
            "SELECT COUNT(*) FROM event_outbox WHERE entity_type = 'incoming_webhook' AND entity_id = $1",
        )
        .bind(receiver_id)
        .fetch_one(db.pool())
        .await
        .expect("count outbox");
        assert_eq!(count, 0, "rejected signatures must not capture outbox rows");

        sqlx::query("DELETE FROM incoming_webhook_receiver WHERE id = $1")
            .bind(receiver_id)
            .execute(db.pool())
            .await
            .ok();
    }

    /// #821/#823: a custom JSON Schema (`schema_doc`) rejects a body missing a
    /// required field with 400 and names the field.
    #[tokio::test]
    async fn incoming_webhook_custom_schema_rejects_missing_field() {
        use hmac::{Hmac, Mac};
        use sha2::Sha256;
        type HmacSha256 = Hmac<Sha256>;

        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database");
        let state = build_call_api_test_state(db.clone(), &database_url).await;

        let slug = format!("schema-{}", Uuid::new_v4().simple());
        let secret = "schema-test-secret-1234567890ab";
        let receiver_id = db
            .incoming_webhooks
            .create(matric_core::CreateIncomingWebhookReceiverRequest {
                slug: slug.clone(),
                provider: "contract".to_string(),
                schema_ref: "contract.payment.v1".to_string(),
                hmac_secret: secret.to_string(),
                signature_header: "X-Fortemi-Signature".to_string(),
                is_active: true,
                schema_doc: Some(serde_json::json!({
                    "type": "object",
                    "required": ["amount", "currency"],
                    "properties": {
                        "amount": {"type": "number"},
                        "currency": {"type": "string"}
                    }
                })),
            })
            .await
            .expect("create receiver");

        let body = br#"{"currency":"USD"}"#.to_vec(); // missing "amount"
        let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(&body);
        let signature = format!("sha256={}", hex::encode(mac.finalize().into_bytes()));
        let mut headers = HeaderMap::new();
        headers.insert("X-Fortemi-Signature", signature.parse().unwrap());
        headers.insert(header::CONTENT_TYPE, "application/json".parse().unwrap());
        headers.insert(header::HOST, "localhost".parse().unwrap());
        let uri: Uri = format!("/api/v1/webhooks/incoming/{slug}").parse().unwrap();

        let res = receive_incoming_webhook(
            State(state.clone()),
            SocketPeer(None),
            OriginalUri(uri),
            Path(slug.clone()),
            headers,
            Bytes::from(body),
        )
        .await;
        match res {
            Err(ApiError::BadRequest(msg)) => {
                // #968: schema-validation rejections return a stable, redacted
                // message and must not echo payload field names or validator detail.
                assert!(
                    msg.contains("schema validation"),
                    "expected generic schema-validation rejection, got: {msg}"
                );
                assert!(
                    !msg.contains("amount") && !msg.contains("currency"),
                    "rejection must not echo payload field names: {msg}"
                );
            }
            Err(other) => panic!("expected 400 BadRequest, got {other:?}"),
            Ok(_) => panic!("expected 400 BadRequest, got Ok"),
        }

        sqlx::query("DELETE FROM incoming_webhook_receiver WHERE id = $1")
            .bind(receiver_id)
            .execute(db.pool())
            .await
            .ok();
    }

