    /// #833: the inbound supervisor writes healthy events to the outbox, commits
    /// their offsets, and dead-letters a malformed event.
    #[tokio::test]
    async fn inbound_supervisor_processes_and_dead_letters() {
        use matric_jobs::inbound::{
            InMemorySource, InboundEvent, InboundMetrics, InboundSupervisor,
        };
        use std::sync::Arc;

        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database");

        let source_name = format!("inbtest-{}", Uuid::new_v4().simple());
        let metrics = Arc::new(InboundMetrics::new());
        // max_attempts=1 so the malformed event dead-letters immediately (no backoff).
        let supervisor =
            Arc::new(InboundSupervisor::new(db.clone(), metrics.clone()).with_max_attempts(1));

        let source = Box::new(InMemorySource::new(
            source_name.clone(),
            vec![
                InboundEvent::new("external.metric.v1", serde_json::json!({"v": 1}), "1-0"),
                // Malformed: empty event_type -> dead-lettered.
                InboundEvent::new("", serde_json::json!({"v": 2}), "1-1"),
                InboundEvent::new("external.metric.v1", serde_json::json!({"v": 3}), "1-2"),
            ],
        ));
        // Runs to completion: InMemorySource reports Closed when drained.
        supervisor.run_source(source).await;

        let outbox_count: i64 = sqlx::query_scalar(
            "SELECT COUNT(*) FROM event_outbox \
             WHERE entity_type = 'inbound_event' \
             AND event_type = 'external.metric.v1' \
             AND payload->>'source_present' = 'true' \
             AND payload->'payload'->>'v' IN ('1', '3')",
        )
        .fetch_one(db.pool())
        .await
        .expect("count outbox");
        assert_eq!(
            outbox_count, 2,
            "two healthy events should reach the outbox"
        );

        let dlq = db
            .inbound_sources
            .dlq_count(&source_name)
            .await
            .expect("dlq count");
        assert_eq!(dlq, 1, "the malformed event should be dead-lettered");

        let snap = metrics.snapshot();
        assert_eq!(snap[&source_name]["events_total"], 2);
        assert_eq!(snap[&source_name]["errors_total"], 1);

        sqlx::query(
            "DELETE FROM event_outbox \
             WHERE entity_type = 'inbound_event' \
             AND event_type = 'external.metric.v1' \
             AND payload->>'source_present' = 'true' \
             AND payload->'payload'->>'v' IN ('1', '3')",
        )
        .execute(db.pool())
        .await
        .ok();
        sqlx::query("DELETE FROM inbound_dlq WHERE source_name = $1")
            .bind(matric_db::inbound_sources::inbound_dlq_source_ref(
                &source_name,
            ))
            .execute(db.pool())
            .await
            .ok();
    }

    /// #819: the DELETE endpoint removes a receiver (204) and reports 404 for an
    /// unknown slug; the underlying repo delete is idempotent.
    #[tokio::test]
    async fn delete_incoming_webhook_receiver_round_trip() {
        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database");
        let state = build_call_api_test_state(db.clone(), &database_url).await;

        let slug = format!("del-{}", Uuid::new_v4().simple());
        db.incoming_webhooks
            .create(matric_core::CreateIncomingWebhookReceiverRequest {
                slug: slug.clone(),
                provider: "twilio".to_string(),
                schema_ref: "twilio.voice.v1".to_string(),
                hmac_secret: "delete-secret-1234567890abcd".to_string(),
                signature_header: "X-Fortemi-Signature".to_string(),
                is_active: true,
                schema_doc: None,
            })
            .await
            .expect("create receiver");
        assert!(db
            .incoming_webhooks
            .get_by_slug(&slug)
            .await
            .unwrap()
            .is_some());

        // DELETE the existing receiver via the handler → 204.
        let deleted =
            delete_incoming_webhook_receiver(State(state.clone()), Path(slug.clone())).await;
        assert!(
            deleted.is_ok(),
            "deleting an existing receiver should succeed"
        );
        assert!(db
            .incoming_webhooks
            .get_by_slug(&slug)
            .await
            .unwrap()
            .is_none());

        // Repo delete is idempotent — a second delete reports no row removed.
        assert!(!db.incoming_webhooks.delete_by_slug(&slug).await.unwrap());

        // DELETE on an unknown slug → 404 (ApiError::NotFound).
        let missing = delete_incoming_webhook_receiver(
            State(state),
            Path(format!("missing-{}", Uuid::new_v4().simple())),
        )
        .await;
        assert!(missing.is_err(), "deleting an unknown receiver should 404");
    }

    #[tokio::test]
    async fn twilio_recording_completed_queues_audio_transcription_job_when_db_is_available() {
        use matric_inference::transcription::{
            TranscriptionBackend, TranscriptionResult, TranscriptionSegment,
        };
        use matric_jobs::JobHandler;
        use sqlx::Row;

        #[derive(Debug)]
        struct MockTranscriptionBackend;

        #[async_trait::async_trait]
        impl TranscriptionBackend for MockTranscriptionBackend {
            async fn transcribe(
                &self,
                _audio_data: &[u8],
                _mime_type: &str,
                _language: Option<&str>,
            ) -> matric_core::Result<TranscriptionResult> {
                Ok(TranscriptionResult {
                    full_text: "batch transcript".to_string(),
                    segments: vec![TranscriptionSegment {
                        start_secs: 0.0,
                        end_secs: 1.5,
                        text: "batch transcript".to_string(),
                        speaker_id: Some("speaker_0".to_string()),
                        words: None,
                    }],
                    language: Some("en".to_string()),
                    duration_secs: Some(1.5),
                })
            }

            async fn health_check(&self) -> matric_core::Result<bool> {
                Ok(true)
            }

            fn model_name(&self) -> &str {
                "mock-whisper"
            }
        }

        if std::env::var("INTEGRATION_TEST_DB").ok().as_deref() != Some("1") {
            return;
        }
        let database_url = match std::env::var("DATABASE_URL") {
            Ok(value) => value,
            Err(_) => return,
        };
        let storage_dir = tempfile::tempdir().expect("file storage dir");
        let db = Database::connect(&database_url)
            .await
            .expect("connect integration database")
            .with_filesystem_storage(storage_dir.path().to_str().unwrap(), 0);
        let state = build_call_api_test_state(db.clone(), &database_url).await;
        let provider_call_id = format!("CA{}", Uuid::new_v4().simple());

        let router = Router::new().route(
            "/recording.wav",
            get(|| async { ([(header::CONTENT_TYPE, "audio/wav")], vec![0_u8; 16]) }),
        );
        let listener = tokio::net::TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind recording fixture server");
        let recording_url = format!("http://{}/recording.wav", listener.local_addr().unwrap());
        tokio::spawn(async move {
            axum::serve(listener, router).await.unwrap();
        });

        let start_body = format!(
            "CallSid={provider_call_id}&CallStatus=ringing&From=%2B15551230000&Direction=inbound&ConsentConfirmed=true"
        );
        let started = apply_twilio_voice_webhook(&state, start_body.as_bytes())
            .await
            .expect("apply started webhook");
        let call_id = Uuid::parse_str(started["call_id"].as_str().unwrap()).unwrap();

        let recording_body = format!(
            "CallSid={provider_call_id}&RecordingStatus=completed&RecordingSid=RE123&RecordingUrl={}",
            urlencoding::encode(&recording_url)
        );
        let recording = apply_twilio_voice_webhook(&state, recording_body.as_bytes())
            .await
            .expect("apply recording webhook");
        let job_id = Uuid::parse_str(
            recording["audio_transcription_job_id"]
                .as_str()
                .expect("recording should queue transcription job"),
        )
        .expect("job uuid");

        let job = db
            .jobs
            .claim_next_for_types(&[JobType::AudioTranscription])
            .await
            .expect("claim audio transcription job")
            .expect("queued audio transcription job");
        assert_eq!(job.id, job_id);
        let note_id = job.note_id;
        let payload = job.payload.as_ref().expect("audio transcription payload");
        let audio_attachment_id = Uuid::parse_str(
            payload["audio_attachment_id"]
                .as_str()
                .expect("audio attachment id"),
        )
        .expect("audio attachment uuid");
        assert_eq!(
            payload["batch_transcript_policy"],
            "append_attachment_transcript"
        );

        let handler = AudioTranscriptionHandler::new(
            db.clone(),
            Arc::new(MockTranscriptionBackend) as Arc<dyn TranscriptionBackend>,
            Arc::new(NoOpMeter),
        );
        match handler.execute(matric_jobs::JobContext::new(job)).await {
            matric_jobs::JobResult::Success(_) => {}
            other => panic!("audio transcription handler failed: {other:?}"),
        }

        let metadata: serde_json::Value =
            sqlx::query_scalar("SELECT extracted_metadata FROM attachment WHERE id = $1")
                .bind(audio_attachment_id)
                .fetch_one(db.pool())
                .await
                .expect("load attachment transcript metadata");
        assert_eq!(metadata["transcript_complete"], true);
        assert_eq!(
            metadata["transcript_segments"][0]["text"],
            "batch transcript"
        );

        let session_metadata: serde_json::Value =
            sqlx::query("SELECT metadata FROM call_sessions WHERE call_id = $1")
                .bind(call_id)
                .fetch_one(db.pool())
                .await
                .expect("load call session metadata")
                .get("metadata");
        assert_eq!(
            session_metadata["batch_transcription"]["policy"],
            "append_attachment_transcript"
        );
        assert_eq!(
            session_metadata["batch_transcription"]["audio_attachment_id"],
            serde_json::json!(audio_attachment_id)
        );

        sqlx::query("DELETE FROM event_outbox WHERE entity_id = $1")
            .bind(call_id)
            .execute(db.pool())
            .await
            .expect("cleanup outbox events");
        sqlx::query("DELETE FROM call_sessions WHERE call_id = $1")
            .bind(call_id)
            .execute(db.pool())
            .await
            .expect("cleanup call session");
        if let Some(note_id) = note_id {
            sqlx::query("DELETE FROM note WHERE id = $1")
                .bind(note_id)
                .execute(db.pool())
                .await
                .expect("cleanup recording note");
        }
    }

